import {IonRippleEffect,IonIcon} from '@ionic/react';
import Link, {ThLink} from '../../components/Link';
import ScrollContainer from '../../components/ScrollContainer';
import InnerLink from '../../components/InnerLink';
const _penetrating_possession = {title: "Penetrating Possession", jsx: <><h2 id="feat-penetrating_possession-penetrating-possession">Penetrating Possession</h2>
<p><strong>Sources</strong> <Link to="/source/demons_revisited">Demons Revisited pg. 32</Link></p>
<p>Your ability to possess foes can bypass magical protections.<br/><strong>Prerequisites:</strong> <Link to="/spell/magic_jar">Magic jar</Link> as a known spell or spell-like ability, Cha 21<br/><strong>Benefit:</strong> The first time you attempt to possess a host under the effect of <Link to="/spell/protection_from_evil">protection from evil</Link> spell or any similar spell, you have a chance to dispel that spell as if you had cast <Link to="/spell/dispel_magic">dispel magic</Link> on the spell.</p>
</>};
const _penetrating_stare = {title: "Penetrating Stare", jsx: <><h2 id="feat-penetrating_stare-penetrating-stare-combat-stare">Penetrating Stare (Combat, Stare)</h2>
<p><strong>Sources</strong> <Link to="/source/psychic_anthology">Psychic Anthology pg. 17</Link></p>
<p>Your stare penetrates right through your foe's strongest mental defenses.<br/><strong>Prerequisites:</strong> <Link to="/class/mesmerist">Mesmerist</Link> level 7th, painful stare class feature.<br/><strong>Benefit:</strong> When you trigger your painful stare, the damage dealt ignores 5 points of the target's damage reduction, unless that damage reduction is untyped (for example, DR 10/-).</p>
</>};
const _penetrating_strike = {title: "Penetrating Strike", jsx: <><h2 id="feat-penetrating_strike-penetrating-strike-combat">Penetrating Strike (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 131</Link></p>
<p>Your attacks are capable of penetrating the defenses of some creatures.<br/><strong>Prerequisites:</strong> <Link to="/feat/weapon_focus">Weapon Focus</Link>, base attack bonus +1, 12th-level fighter, proficiency with weapon.<br/><strong>Benefit:</strong> Your attacks with weapons selected with Weapon Focus ignore up to 5 points of damage reduction. This feat does not apply to damage reduction without a type (such as DR 10/-).</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-penetrating_strike--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-penetrating_strike-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 128</Link><br/>Whenever you deal damage to a creature with damage reduction using the selected weapons, you can spend 5 stamina points to allow all your allies (other than yourself) within 30 feet of the creature to ignore 5 points of the creature's damage reduction for 1 round. This has no effect on creatures with damage reduction without a type (such as DR 10/-). This effect does not stack with Penetrating Strike's normal effect, but it does allow you to apply the effect to all your other weapons for the duration.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional mythic"><ScrollContainer id="feat-penetrating_strike--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Penetrating Strike</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 70</Link><br/>You know just how to strike to bypass even the most heavily armored foe's defenses.<br/><strong>Prerequisites:</strong> Penetrating Strike.<br/><strong>Benefit:</strong> When using Penetrating Strike or Greater Penetrating Strike, you can ignore an additional point of damage reduction for every 3 tiers you posses. Additionally, the effects apply to damage reduction without a type (such as DR 10/-).</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional elephant"><ScrollContainer id="feat-penetrating_strike--table-2"><table><tbody><tr><ThLink scope="row" to="/rule/the_elephant_in_the_room"><IonIcon aria-label="The Elephant in the Room" icon="/icons/elephant.svg" /></ThLink><td><p><strong>Sources</strong> <Link to="/source/the_elephant_in_the_room_feat_taxes_in_pathfinder">The Elephant in the Room: Feat Taxes in Pathfinder</Link><br/>Your attacks are capable of penetrating the defenses of some creatures.<br/><strong>Prerequisites:</strong> <Link to="/feat/weapon_focus">Weapon Focus</Link>, base attack bonus +1, 12th-level fighter<br/><strong>Benefit:</strong> Your attacks with weapons from the group in which you have Weapon Focus ignore up to 5 points of damage reduction. This feat does not apply to damage reduction without a type (such as DR 10/-).</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _perfect_awareness = {title: "Perfect Awareness", jsx: <><h2 id="feat-perfect_awareness-perfect-awareness-combat-meditation">Perfect Awareness (Combat, Meditation)</h2>
<p><strong>Sources</strong> <Link to="/source/faiths_and_philosophies">Faiths and Philosophies pg. 19</Link></p>
<p>You can set aside all irrelevant sensory information to understand your surroundings perfectly for a moment.<br/><strong>Prerequisites:</strong> Wis 17, <Link to="/feat/combat_meditation">Combat Meditation</Link>, <Link to="/feat/meditation_master">Meditation Master</Link>, character level 9th.<br/><strong>Benefit:</strong> Once per day, you can take 20 on a Perception check as a move action.</p>
</>};
const _perfect_casting = {title: "Perfect Casting", jsx: <><h2 id="feat-perfect_casting-perfect-casting">Perfect Casting</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 215</Link></p>
<p>You unlock greater secrets of divine spellcasting from the First Vault.<br/><strong>Prerequisites:</strong> <Link to="/feat/combat_casting">Combat Casting</Link>, <Link to="/feat/divine_dignity">Divine Dignity</Link>, ability to cast divine spells, worshiper of <Link to="/faith/abadar">Abadar</Link>.<br/><strong>Benefit:</strong> When you use Divine Dignity, it can affect the casting of any of your divine spells, not just harmless and domain spells.</p>
</>};
const _perfect_center = {title: "Perfect Center", jsx: <><h2 id="feat-perfect_center-perfect-center-combat-meditation">Perfect Center (Combat, Meditation)</h2>
<p><strong>Sources</strong> <Link to="/source/faiths_and_philosophies">Faiths and Philosophies pg. 19</Link></p>
<p>You can ignore almost any distraction.<br/><strong>Prerequisites:</strong> Wis 21, <Link to="/feat/combat_meditation">Combat Meditation</Link>, <Link to="/feat/meditation_master">Meditation Master</Link>, character level 17th.<br/><strong>Benefit:</strong> You can take 10 on any skill check or <Link to="/rule/concentration">concentration</Link> check, even if it is not normally allowed due to strenuous circumstances.</p>
</>};
const _perfect_strike = {title: "Perfect Strike", jsx: <><h2 id="feat-perfect_strike-perfect-strike-combat">Perfect Strike (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 166</Link></p>
<p>When wielding a monk weapon, your attacks can be extremely precise.<br/><strong>Prerequisites:</strong> Dex 13, Wis 13, <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>, base attack bonus +8.<br/><strong>Benefit:</strong> You must declare that you are using this feat before you make your attack roll (thus a failed attack roll ruins the attempt). You must use one of the following weapons to make the attack: <Link to="/eq-weapon/kama">kama</Link>, <Link to="/eq-weapon/nunchaku">nunchaku</Link>, <Link to="/eq-weapon/quarterstaff">quarterstaff</Link>, <Link to="/eq-weapon/sai">sai</Link>, and <Link to="/eq-weapon/siangham">siangham</Link>. You can roll your attack roll twice and take the higher result. If one of these rolls is a critical threat, the other roll is used as your confirmation roll (your choice if they are both critical threats). You may attempt a perfect attack once per day for every four levels you have attained (but see Special), and no more than once per round.<br/><strong>Special:</strong> A <Link to="/arc-monk/weapon_adept">weapon adept</Link> monk or <Link to="/arc-monk/zen_archer">zen archer</Link> monk receives Perfect Strike as a bonus feat at 1st level, even if he does not meet the prerequisites. A monk may attempt an perfect strike attack a number of times per day equal to his monk level, plus one more time per day for every four levels he has in classes other than monk.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-perfect_strike--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-perfect_strike-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 128</Link><br/>You can spend 5 stamina points to use Perfect Strike a second time during the same round.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _perfect_style = {title: "Perfect Style", jsx: <><h2 id="feat-perfect_style-perfect-style-combat-style">Perfect Style (Combat, Style)</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 106</Link>, <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 13</Link></p>
<p>You have trained at one of the <Link to="/rule/houses_of_perfection">Houses of Perfection</Link>.<br/><strong>Prerequisites:</strong> Wis 13; base attack bonus +5 or monk level 5th.<br/><strong>Benefit:</strong> When you take this feat, choose one of the Houses of Perfection; once this decision has been made, it cannot be changed. While using this style, you gain a type of energy resistance based on the House of Perfection you have chosen. Students of the <em>Monastery of Untwisting Iron</em> gain acid resistance 5. Students of the <em>Monastery of Unblinking Flame</em> gain fire resistance 5. Students of the <em>Monastery of Unfolding Wind</em> gain electricity resistance 5. If you have energy resistance from a racial trait or class feature, the energy resistance gained from this style stacks.</p>
<p>Additionally, you gain a ki pool that you can use to activate abilities of your chosen House of Perfection style. Your pool contains 2 ki points, and this increases by 1 point at 9th level and every 4 levels thereafter. If you have a ki pool from another source, you do not gain additional ki points from this feat.</p>
<p><strong>Special:</strong> You can select Perfect Style multiple times. Each time you do so, you must select a different House of Perfection to belong to.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-perfect_style--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-perfect_style-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/weapon_masters_handbook">Weapon Master's Handbook pg. 25</Link><br/>You can spend up to 5 stamina points to increase the resistance granted to you by Perfect Style by 2 per stamina point spent.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _performance_weapon_mastery = {title: "Performance Weapon Mastery", jsx: <><h2 id="feat-performance_weapon_mastery-performance-weapon-mastery-combat">Performance Weapon Mastery (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 112</Link></p>
<p>You wield all your weapons with the flair of a performer.<br/><strong>Benefit:</strong> You treat all weapons you are proficient in as if they had the <Link to="/misc/performance">performance</Link> weapon quality.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-performance_weapon_mastery--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-performance_weapon_mastery-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 128</Link><br/>As long as you have at least 1 stamina point in your stamina pool, you treat all weapons - not just the ones you are proficient with - as if they had the performance weapon quality.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _performing_combatant = {title: "Performing Combatant", jsx: <><h2 id="feat-performing_combatant-performing-combatant-combat">Performing Combatant (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 112</Link></p>
<p>You treat every combat as a performance, bringing flare and showmanship.<br/><strong>Prerequisites:</strong> <Link to="/feat/dazzling_display">Dazzling Display</Link>, any one performance feat.<br/><strong>Benefit:</strong> You can make <Link to="/rule/performance_combat">performance combat</Link> checks in any combat. When making a performance check outside of performance combat, you can pick a single <Link to="/main/feats_performance">performance feat</Link> to use. You automatically gain any bonus on the performance combat check the feat grants, and then you make a DC 20 performance combat check. On a success, you gain the full effect of the performance feat you chose.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-performing_combatant--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-performing_combatant-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 128</Link><br/>When using this feat, you can spend up to 5 stamina points to gain a bonus on your performance combat check equal to the number of stamina points you spent.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _pernicious_stab = {title: "Pernicious Stab", jsx: <><h2 id="feat-pernicious_stab-pernicious-stab-combat">Pernicious Stab (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook pg. 23</Link></p>
<p>Your deep strikes allow you to deliver poison efficiently when your opponent is off guard.<br/><strong>Prerequisites:</strong> <Link to="/ability/sneak_attack">Sneak attack</Link> +2d6.<br/><strong>Benefit:</strong> When you hit an opponent with a poisoned weapon and would deal sneak attack damage, you can choose to forgo some or all of the sneak attack damage to increase the poison's chance of success. For every 2d6 points of sneak attack damage you forgo, add 1 to the saving throw DC of the poison delivered with your attack. This increase to the poison save DC does not apply to creatures that are immune to <Link to="/misc/precision_damage">precision damage</Link>.</p>
</>};
const _persistent_spell = {title: "Persistent Spell", jsx: <><h2 id="feat-persistent_spell-persistent-spell-metamagic">Persistent Spell (Metamagic)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 167</Link></p>
<p>You can modify a spell to become more tenacious when its targets resist its effect.<br/><strong>Benefit:</strong> Whenever a creature targeted by a persistent spell or within its area succeeds on its saving throw against the spell, it must make another saving throw against the effect. If a creature fails this second saving throw, it suffers the full effects of the spell, as if it had failed its first saving throw. A persistent spell uses up a spell slot two levels higher than the spell's actual level. Spells that do not require a saving throw to resist or lessen the spell's effect do not benefit from this feat.</p>
</>};
const _personal_chronicler = {title: "Personal Chronicler", jsx: <><h2 id="feat-personal_chronicler-personal-chronicler">Personal Chronicler</h2>
<p><strong>Sources</strong> <Link to="/source/plane_hoppers_handbook">Plane-Hopper's Handbook pg. 16</Link></p>
<p>Psychopomps have sent a nosoi scribe to record your actions.<br/><strong>Prerequisites:</strong> <Link to="/race/duskwalker">Duskwalker</Link>.</p>
<p>You gain a fledgling nosoi <Link to="/ability/familiar">familiar</Link> as per the arcane bond class feature, using your character level as your wizard level. Treat this as either a <Link to="/monster/raven">raven</Link> or a whippoorwill familiar (a whippoorwill uses the statistics for a <Link to="/monster/thrush">thrush</Link>, but grants a +3 bonus to Intimidate instead of Diplomacy). If you have the ability to gain a familiar through other means and you are at least 5th level, the bird is instead treated as a <Link to="/monster/nosoi">nosoi</Link> as though you had taken the <Link to="/feat/improved_familiar">Improved Familiar</Link> feat. You can have only one familiar.</p>
<p>This feat can be taken a second time by a character of 7th level or higher if that character doesn't otherwise have access to a familiar. Such characters treat their familiars as nosoi, as described above.</p>
<p>If you ever willingly consort with sahkils or undead, your familiar abandons you and reports your actions to the nearest psychopomps. To regain your familiar, you must atone for your deeds via the <Link to="/spell/atonement">atonement</Link> spell.</p>
</>};
const _persuasive = {title: "Persuasive", jsx: <><h2 id="feat-persuasive-persuasive">Persuasive</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 131</Link></p>
<p>You are skilled at swaying attitudes and intimidating others into your way of thinking.<br/><strong>Benefit:</strong> You get a +2 bonus on Diplomacy and Intimidate skill checks. If you have 10 or more ranks in one of these skills, the bonus increases to +4 for that skill.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="feat-persuasive--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Persuasive</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 70</Link><br/>You're a master of persuasion, be it with soothing words or harsh barking commands.<br/><strong>Prerequisites:</strong> Persuasive.<br/><strong>Benefit:</strong> The bonus on Diplomacy and Intimidate skill checks granted by Persuasive increases by 2. In addition, you can expend one use of mythic power to treat a Diplomacy or Intimidate check as if you had rolled a natural 20. You must decide to use this ability before making the roll.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _persuasive_bribery = {title: "Persuasive Bribery", jsx: <><h2 id="feat-persuasive_bribery-persuasive-bribery">Persuasive Bribery</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 88</Link></p>
<p>You know how to get the most out of bribes.<br/><strong>Prerequisites:</strong> <Link to="/feat/persuasive">Persuasive</Link>.<br/><strong>Benefit:</strong> You gain a +2 bonus on Diplomacy checks when attempting to bribe someone and on Diplomacy or Charisma checks to bargain with a conjured creature (such as with <Link to="/spell/planar_ally">planar ally</Link> or <Link to="/spell/planar_binding">planar binding</Link>), in addition to any bonus granted by the bribe itself. The first time someone refuses a bribe you offer, that person's attitude toward you doesn't worsen, even if the offer would normally offend the person.</p>
</>};
const _persuasive_performer = {title: "Persuasive Performer", jsx: <><h2 id="feat-persuasive_performer-persuasive-performer">Persuasive Performer</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 215</Link></p>
<p>For you, performance is the heart of negotiation.<br/><strong>Prerequisites:</strong> Versatile performance class feature, worshiper of <Link to="/faith/shelyn">Shelyn</Link>.<br/><strong>Benefit:</strong> You can use any of your Perform skills in place of Diplomacy, not just Perform (keyboard, oratory, string, or wind). If you do use Perform (keyboard, oratory, string, or wind), you gain a +2 bonus on your check.</p>
</>};
const _perturbing_stare = {title: "Perturbing Stare", jsx: <><h2 id="feat-perturbing_stare-perturbing-stare-combat-stare">Perturbing Stare (Combat, Stare)</h2>
<p><strong>Sources</strong> <Link to="/source/psychic_anthology">Psychic Anthology pg. 17</Link></p>
<p>Your stare dulls your foe's reactions.<br/><strong>Prerequisites:</strong> <Link to="/class/mesmerist">Mesmerist</Link> level 5th, painful stare class feature.<br/><strong>Benefit:</strong> When you trigger your painful stare, the target must succeed at a Will save (DC = 10 + half your mesmerist level + your Charisma modifier) or lose its Dexterity modifier to AC for 1 round.</p>
</>};
const _pesh_euphoria = {title: "Pesh Euphoria", jsx: <><h2 id="feat-pesh_euphoria-pesh-euphoria">Pesh Euphoria</h2>
<p><strong>Sources</strong> <Link to="/source/black_markets">Black Markets pg. 18</Link>, <Link to="/source/dark_markets___a_guide_to_katapesh">Dark Markets - A Guide to Katapesh pg. 56</Link></p>
<p>The calming effects of pesh make you difficult to disturb.<br/><strong>Prerequisites:</strong> <Link to="/feat/sahir_afiyun">Sahir-Afiyun</Link> or <Link to="/drug/pesh">pesh</Link> addict.<br/><strong>Benefit:</strong> When you take a dose of pesh, in addition to its normal initial effect, you gain a +2 bonus on saves against emotion and fear effects. Once per day, if you fail a saving throw against an emotion or fear effect while you are under the initial effect of pesh, you can attempt another saving throw 1 round later at the same DC.</p>
</>};
const _pesh_healing = {title: "Pesh Healing", jsx: <><h2 id="feat-pesh_healing-pesh-healing">Pesh Healing</h2>
<p><strong>Sources</strong> <Link to="/source/black_markets">Black Markets pg. 18</Link>, <Link to="/source/dark_markets___a_guide_to_katapesh">Dark Markets - A Guide to Katapesh pg. 56</Link></p>
<p>Consuming pesh makes you feel healthier.<br/><strong>Prerequisites:</strong> <Link to="/feat/sahir_afiyun">Sahir-Afiyun</Link> or <Link to="/drug/pesh">pesh</Link> addict.<br/><strong>Benefit:</strong> When you take a dose of pesh, in addition to its normal initial effect, you gain a number of <Link to="/rule/temporary_hit_points">temporary hit points</Link> equal to your total Hit Dice for 1 hour. Temporary hit points gained from additional doses of pesh do not stack.</p>
</>};
const _pesh_rejuvenation = {title: "Pesh Rejuvenation", jsx: <><h2 id="feat-pesh_rejuvenation-pesh-rejuvenation">Pesh Rejuvenation</h2>
<p><strong>Sources</strong> <Link to="/source/black_markets">Black Markets pg. 18</Link>, <Link to="/source/dark_markets___a_guide_to_katapesh">Dark Markets - A Guide to Katapesh pg. 56</Link></p>
<p>When you are close to death, your body can convert pesh into lifesaving medicine.<br/><strong>Prerequisites:</strong> <Link to="/feat/sahir_afiyun">Sahir-Afiyun</Link> or <Link to="/drug/pesh">pesh</Link> addict.<br/><strong>Benefit:</strong> If you are brought to 0 or fewer hit points while under the initial effect of pesh, you can end the drug's initial effect as an immediate action. If you do, you gain a number of <Link to="/rule/temporary_hit_points">temporary hit points</Link> equal to your Constitution score. These temporary hit points last 1 hour. Upon using this feat, you are <Link to="/misc/sickened">sickened</Link> for 1d6 hours.</p>
</>};
const _pestilent = {title: "Pestilent", jsx: <><h2 id="feat-pestilent-pestilent">Pestilent</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_81_shifting_sands">Pathfinder #81: Shifting Sands pg. 73</Link></p>
<p>Your unarmed strikes and natural weapons cause extra harm to those infected with your disease.<br/><strong>Prerequisites:</strong> Ability to cause disease via a spell, spell-like ability, or supernatural means.<br/><strong>Benefit:</strong> When you successfully use a spell, spell-like ability, or supernatural ability to cause a creature to contract a disease, you gain a +2 bonus on attack rolls with natural weapons and unarmed strikes against that creature. In addition, such attacks deal an additional 1d6 points of negative energy damage. If you have the supernatural ability to cause a single disease (such as <Link to="/curse/mummy_rot">mummy rot</Link>), you gain these bonuses against any creature that has contracted the same disease, even if it did not contract it from you.</p>
</>};
const _phalanx_formation = {title: "Phalanx Formation", jsx: <><h2 id="feat-phalanx_formation-phalanx-formation-combat">Phalanx Formation (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 10</Link></p>
<p>You are trained to use long weapons in tight formations.<br/><strong>Prerequisites:</strong> Base attack bonus +1.<br/><strong>Benefit:</strong> When you wield a <Link to="/misc/reach">reach</Link> weapon with which you are proficient, allies don't provide soft cover to opponents you attack with reach.<br/><strong>Normal:</strong> Attacking a target that is beyond another creature, even an ally, can result in the target having soft cover from you.</p>
</>};
const _phantom_ally = {title: "Phantom Ally", jsx: <><h2 id="feat-phantom_ally-phantom-ally">Phantom Ally</h2>
<p><strong>Sources</strong> <Link to="/source/haunted_heroes_handbook">Haunted Heroes Handbook pg. 4</Link></p>
<p>Your phantom's strength is fueled by your own diverse experiences and abilities.<br/><strong>Prerequisites:</strong> Phantom class feature.<br/><strong>Benefit:</strong> The abilities of your <Link to="/sidekick/phantom">phantom</Link> are calculated as though you were 4 class levels higher, to a maximum effective spiritualist level equal to your character level.</p>
</>};
const _phantom_fighter = {title: "Phantom Fighter", jsx: <><h2 id="feat-phantom_fighter-phantom-fighter">Phantom Fighter</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 137</Link></p>
<p>Your phantom is a deadly foe of incorporeal adversaries.<br/><strong>Prerequisites:</strong> Phantom class feature, phantom with the magic attacks ability.<br/><strong>Benefit:</strong> Your <Link to="/sidekick/phantom">phantom's</Link> natural weapons are treated as having the <Link to="/magic-enh/ghost_touch">ghost touch</Link> property. In addition, when you cast a touch spell to be delivered by your phantom, you can modify the spell as if you possessed the <Link to="/feat/ectoplasmic_spell">Ectoplasmic Spell</Link> metamagic feat.</p>
</>};
const _phantom_fortification = {title: "Phantom Fortification", jsx: <><h2 id="feat-phantom_fortification-phantom-fortification">Phantom Fortification</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 137</Link></p>
<p>Your phantom remains partly immaterial even when fully manifested in ectoplasmic form.<br/><strong>Prerequisites:</strong> Phantom class feature, <Link to="/sidekick/phantom">phantom</Link> with the incorporeal flight ability.<br/><strong>Benefit:</strong> Your phantom has a 50% chance of ignoring critical hits and <Link to="/misc/precision_damage">precision-based damage</Link> when fully manifested in its ectoplasmic form, as if wearing armor with the <Link to="/magic-enh/moderate_fortification">moderate fortification</Link> special ability. This doesn't stack with other similar effects, and doesn't apply against attacks made with <Link to="/magic-enh/ghost_touch">ghost touch</Link> weapons or weapon-like constructs made of force (such as a <Link to="/spell/clenched_fist">clenched fist</Link>, <Link to="/spell/mages_sword">mage's sword</Link>, or <Link to="/spell/spiritual_weapon">spiritual weapon</Link>).</p>
</>};
const _phase_strike = {title: "Phase Strike", jsx: <><h2 id="feat-phase_strike-phase-strike-combat-conduit">Phase Strike (Combat, Conduit)</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 31</Link></p>
<p>You strike through the Ethereal Plane so your weapon phases through obstacles, armor, and even thick hide to strike true.<br/><strong>Prerequisites:</strong> Knowledge (planes) 10 ranks.<br/><strong>Benefit:</strong> As a move action, you can phase out one manufactured weapon or piece of ammunition you are holding. The next melee attack or thrown ranged attack you make with that weapon before the end of your turn is resolved as a touch attack and ignores <Link to="/rule/cover">cover</Link>, but does not ignore armor bonuses from force effects. You can attack through total cover this way, although you must still select the correct square for your target.</p>
<p>You can use this feat's benefit once per day, plus an additional time per day for every 10 ranks you have in Knowledge (planes). This feat does not function on planes that are not coterminous with the Ethereal Plane.</p>
</>};
const _photosynthetic_healing = {title: "Photosynthetic Healing", jsx: <><h2 id="feat-photosynthetic_healing-photosynthetic-healing">Photosynthetic Healing</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 24</Link></p>
<p>You can heal yourself using sunlight.<br/><strong>Prerequisites:</strong> Con 15, change shape ability, leshy subtype.<br/><strong>Benefit:</strong> You can temporarily draw energy from the sun to heal your wounds. Once per day while you are using change shape to assume a plant form, you can activate this ability as a free action to gain fast healing 1 for a number of rounds equal to your Hit Dice, as long as you are in an area of bright, natural sunlight.</p>
<p>When you rest in plant form in bright, natural sunlight, you are healed of twice the normal amount of hit point damage and ability score damage.</p>
</>};
const _piercing_chant = {title: "Piercing Chant", jsx: <><h2 id="feat-piercing_chant-piercing-chant">Piercing Chant</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_golarion">Heroes of Golarion pg. 9</Link></p>
<p>Music plays a key role in goblin culture - at the very least, goblins are fond of cacophonous chants describing the last enemy they slew or what they're roasting for dinner. You have gathered, however, that non-goblins don't appreciate your songs very much.<br/><strong>Prerequisites:</strong> <Link to="/race/goblin">Goblin</Link>.<br/><strong>Benefit:</strong> As a full-round action, you can sing a song so terrible and ear-splitting that each enemy within 15 feet of you that hears it must succeed at a Will save or be <Link to="/misc/dazed">dazed</Link> for 1 round. The DC of this saving throw is equal to 10 + half your level + your Charisma modifier. Whether or not the initial save is successful, a creature cannot be affected by this ability again for 24 hours. This is a mind-affecting effect.</p>
</>};
const _piercing_gambit = {title: "Piercing Gambit", jsx: <><h2 id="feat-piercing_gambit-piercing-gambit-teamwork">Piercing Gambit (Teamwork)</h2>
<p><strong>Sources</strong> <Link to="/source/antiheros_handbook">Antihero's Handbook pg. 10</Link></p>
<p>You cast a spell destined to fail in order to help your ally overcome an enemy's spell resistance.<br/><strong>Prerequisites:</strong> <Link to="/feat/spell_penetration">Spell Penetration</Link> or Bluff 3 ranks; caster level 1st.<br/><strong>Benefit:</strong> You can expend one prepared spell or spell slot, as if you had cast the spell, to weaken an enemy's defenses. Your spell has no effect, but a designated ally who also has this feat gains a bonus on her caster level check to overcome spell resistance equal to half the level of the spell or spell slot you expended, lasting until the start of your next turn.</p>
</>};
const _piercing_grapple = {title: "Piercing Grapple", jsx: <><h2 id="feat-piercing_grapple-piercing-grapple-combat">Piercing Grapple (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 88</Link></p>
<p>You can use small but deadly weapons to restrain a foe, forcing it to choose between pain and capitulation.<br/><strong>Prerequisites:</strong> Dex 13, <Link to="/feat/improved_grapple">Improved Grapple</Link>, <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>, <Link to="/feat/quick_draw">Quick Draw</Link>, Intimidate 7 ranks.<br/><strong>Benefit:</strong> You can draw a light or one-handed piercing weapon and stab your opponent with it when you initiate a <Link to="/rule/grapple">grapple</Link>. You take a -2 penalty on your combat maneuver check to initiate the grapple, but since you pull the weapon out as part of the grapple, you don't take the usual -4 penalty. If you succeed, you grapple your opponent as normal, and the weapon doesn't count as being in your hand either for the purposes of the -4 penalty or for dealing damage while maintaining a grapple. If your opponent successfully breaks the grapple, it takes an amount of damage equal to the base weapon damage of the weapon you used to initiate the grapple plus an additional 1d4 points of <Link to="/rule/bleed">bleed</Link> damage. A successful DC 15 Heal check or any magical healing ends the bleed effect. If you choose to end the grapple, you can opt to not deal the bleed damage, but either way, your opponent still takes the base weapon damage. While maintaining this grapple, you gain a +2 circumstance bonus on all Intimidate checks made against your opponent.</p>
</>};
const _piercing_spell = {title: "Piercing Spell", jsx: <><h2 id="feat-piercing_spell-piercing-spell-metamagic">Piercing Spell (Metamagic)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 154</Link></p>
<p>Your studies have helped you develop methods to overcome spell resistance.<br/><strong>Benefit:</strong> When you cast a piercing spell against a target with spell resistance, it treats the spell resistance of the target as 5 lower than its actual SR. A piercing spell uses up a spell slot one level higher than the spell's actual level.</p>
</>};
const _pile_on = {title: "Pile On", jsx: <><h2 id="feat-pile_on-pile-on-combat">Pile On (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 20</Link></p>
<p>You can keep a foe shuddering in fear.<br/><strong>Prerequisites:</strong> Str 13, <Link to="/feat/hurtful">Hurtful</Link>, <Link to="/feat/power_attack">Power Attack</Link>.<br/><strong>Benefit:</strong> Once per round when you damage a creature that is shaken, frightened, or panicked, you can choose to deal half your normal damage in order to extend the duration of its fear condition by 1 round.</p>
</>};
const _pin_down = {title: "Pin Down", jsx: <><h2 id="feat-pin_down-pin-down-combat">Pin Down (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 113</Link></p>
<p>You easily block enemy escapes.<br/><strong>Prerequisites:</strong> <Link to="/feat/combat_reflexes">Combat Reflexes</Link>, <Link to="/class/fighter">fighter</Link> level 11th.<br/><strong>Benefit:</strong> Whenever an opponent you threaten takes a 5-foot step or uses the <Link to="/rule/withdraw">withdraw</Link> action, that opponent provokes an attack of opportunity from you. If the attack hits, you deal no damage, but the targeted creature is prevented from making the move action that granted a 5-foot step or the withdraw action and does not move.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-pin_down--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-pin_down-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 129</Link><br/>When using this feat, you can spend 5 stamina points to gain its benefits and still deal damage with the attack of opportunity.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _pinch_time = {title: "Pinch Time", jsx: <><h2 id="feat-pinch_time-pinch-time">Pinch Time</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe pg. 21</Link></p>
<p>Often having one parent with a human lifespan and one with an elven lifespan, many half-elves have a skewed perception of time, and none more so than the Spireborn, who also study the subject of time academically.<br/><strong>Prerequisites:</strong> Character level 5th, Spireborn <Link to="/race/half_elf">half-elf</Link>.<br/><strong>Benefit:</strong> Once per day, as a standard action, you can gain the benefits of <Link to="/spell/haste">haste</Link> until the end of your next turn.</p>
</>};
const _pinning_knockout = {title: "Pinning Knockout", jsx: <><h2 id="feat-pinning_knockout-pinning-knockout-combat">Pinning Knockout (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 113</Link></p>
<p>An opponent you have pinned is easy for you to knock out.<br/><strong>Prerequisites:</strong> Dex 13, <Link to="/feat/greater_grapple">Greater Grapple</Link>, <Link to="/feat/improved_grapple">Improved Grapple</Link>, <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>, base attack bonus +9 or monk level 9th.<br/><strong>Benefit:</strong> While you have an opponent pinned, when you succeed at a <Link to="/rule/grapple">grapple</Link> combat maneuver check to deal an opponent nonlethal damage using an unarmed strike or a light or one-handed weapon, double your damage result. Any creature that is immune to critical hits is immune to the effects of this feat.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-pinning_knockout--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-pinning_knockout-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 129</Link><br/>When using an unarmed strike or a light or one-handed weapon to deal nonlethal damage to a pinned opponent with this feat, you can spend 5 stamina points to triple the damage instead of doubling it.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _pinning_rend = {title: "Pinning Rend", jsx: <><h2 id="feat-pinning_rend-pinning-rend-combat">Pinning Rend (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 113</Link></p>
<p>You tear flesh when you damage an opponent that you have pinned.<br/><strong>Prerequisites:</strong> Dex 13, <Link to="/feat/greater_grapple">Greater Grapple</Link>, <Link to="/feat/improved_grapple">Improved Grapple</Link>, <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>, base attack bonus +9 or monk level 9th.<br/><strong>Benefit:</strong> While you have an opponent pinned, when you succeed at a <Link to="/rule/grapple">grapple</Link> combat maneuver check to deal an opponent damage using an unarmed strike or a light or one-handed weapon, that opponent also takes <Link to="/rule/bleed">bleed</Link> damage equal to your unarmed strike or weapon damage dice. Any creature that is immune to critical hits is immune to the effects of this feat.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-pinning_rend--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-pinning_rend-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 129</Link><br/>When you deal bleed damage with this feat, you can spend up to 5 stamina points to increase the bleed damage by an amount equal to the number of stamina points you spent.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _pinpoint_jab = {title: "Pinpoint Jab", jsx: <><h2 id="feat-pinpoint_jab-pinpoint-jab-combat">Pinpoint Jab (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/martial_arts_handbook">Martial Arts Handbook pg. 26</Link></p>
<p>You strikes land exactly where you mean them to.<br/><strong>Prerequisites:</strong> <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>, and either a ki pool or martial flexibility class feature.</p>
<p>As a full-round action, you can expend 1 ki point or one daily use of martial flexibility to use a limited version of the <Link to="/swashdeed/targeted_strike">targeted strike</Link> deed, targeting either hands or legs with an unarmed attack. A target who succeeds at a Fortitude save (DC = 10 + your base attack bonus) can negate the effect. When your base attack bonus reaches +11, you can instead target head or torso, which the target can negate with a Fortitude save. When your BAB reaches +16, you can target two locations; the target must save against each effect separately.<br/><strong>Special:</strong> A monk can substitute his class level for his base attack bonus for this feat's effects.</p>
</>};
const _pinpoint_poisoner = {title: "Pinpoint Poisoner", jsx: <><h2 id="feat-pinpoint_poisoner-pinpoint-poisoner-combat">Pinpoint Poisoner (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 113</Link></p>
<p>You deftly use specially prepared needles to apply poison for maximum effect.<br/><strong>Prerequisites:</strong> <Link to="/ability/poison_use">Poison use</Link> class feature, Craft (alchemy) 6 ranks, <Link to="/feat/adder_strike">Adder Strike</Link>, <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>, <Link to="/feat/two_weapon_fighting">Two-Weapon Fighting</Link> or flurry of blows class feature.<br/><strong>Benefit:</strong> When you use Adder Strike, you can instead poison up to two <Link to="/eq-weapon/blowgun_darts">blowgun darts</Link> that you can then use to strike your opponent in melee. (Drawing such darts is a free action.) While holding these darts, you can spend a standard action to attack with one or a full-attack action to attack with both. Such attacks are considered melee touch attacks that deal 1d2 damage plus any bonuses you gain on your normal unarmed strike damage, and they deliver the poison. You can instead throw such darts as if they were <Link to="/eq-weapon/shuriken">shuriken</Link>, making your ranged attack rolls against the target's AC.<br/><strong>Normal:</strong> Applying poison to a weapon or single piece of ammunition is a standard action.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-pinpoint_poisoner--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-pinpoint_poisoner-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 129</Link><br/>When throwing blowgun darts as shuriken with this feat while you're within 10 feet of your target, you can spend 5 stamina points to make your attack roll against the target's touch AC instead.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _pinpoint_targeting = {title: "Pinpoint Targeting", jsx: <><h2 id="feat-pinpoint_targeting-pinpoint-targeting-combat">Pinpoint Targeting (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 131</Link></p>
<p>You can target the weak points in your opponent's armor.<br/><strong>Prerequisites:</strong> Dex 19, <Link to="/feat/improved_precise_shot">Improved Precise Shot</Link>, <Link to="/feat/precise_shot">Precise Shot</Link>, base attack bonus +16.<br/><strong>Benefit:</strong> As a standard action, make a single ranged attack. The target does not gain any armor, natural armor, or shield bonuses to its Armor Class. You do not gain the benefit of this feat if you move this round.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-pinpoint_targeting--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-pinpoint_targeting-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 129</Link><br/>When you use this feat, you can spend stamina points to retain the ability to move. If you spend 2 stamina points, you can take a 5-foot step after you make the attack. If you instead spend 5 stamina points, you can move up to half your speed as a move action.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional mythic"><ScrollContainer id="feat-pinpoint_targeting--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Pinpoint Targeting</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 70</Link><br/>Your attacks can home in on your opponent's weak spot and ignore many defenses.<br/><strong>Prerequisites:</strong> Pinpoint Targeting.<br/><strong>Benefit:</strong> You can use this feat even if you move this round, but only if the distance you move is equal to or less than 5 feet per tier.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _piranha_strike = {title: "Piranha Strike", jsx: <><h2 id="feat-piranha_strike-piranha-strike-combat">Piranha Strike (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/sargava_the_lost_colony">Sargava, the Lost Colony pg. 24</Link></p>
<p>You make a combination of quick strikes, sacrificing accuracy for multiple, minor wounds that prove exceptionally deadly.<br/><strong>Prerequisites:</strong> <Link to="/feat/weapon_finesse">Weapon Finesse</Link>, base attack bonus +1.<br/><strong>Benefit:</strong> When wielding a light weapon, you can choose to take a -1 penalty on all melee attack rolls and combat maneuver checks to gain a +2 bonus on all melee damage rolls. This bonus to damage is halved (-50%) if you are making an attack with an off-hand weapon or secondary natural weapon. When your base attack bonus reaches +4, and for every 4 points thereafter, the penalty increases by -1 and the bonus on damage rolls increases by +2. You must choose to use this feat before the attack roll, and its effects last until your next turn. The bonus damage does not apply to touch attacks or effects that do not deal hit point damage. This feat cannot be used in conjunction with the <Link to="/feat/power_attack">Power Attack</Link> feat.</p>
</>};
const _plague_resistance = {title: "Plague Resistance", jsx: <><h2 id="feat-plague_resistance-plague-resistance">Plague Resistance</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 68</Link></p>
<p>Diseases tend to have milder effects on you.<br/><strong>Prerequisites:</strong> Constitution 13.<br/><strong>Benefit:</strong> When you take <Link to="/rule/drain">damage or drain</Link> to your ability scores as the result of a disease, roll damage and drain to each ability score twice and take the lower result. You suffer any other effects of the disease as normal.</p>
</>};
const _plains_nomad = {title: "Plains Nomad", jsx: <><h2 id="feat-plains_nomad-plains-nomad">Plains Nomad</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 117</Link></p>
<p>You are a native of the wide and endless prairie, savanna, or steppe.<br/><strong>Prerequisites:</strong> <Link to="/ability/favored_terrain">Favored terrain</Link> (plains) class feature.<br/><strong>Benefit:</strong> You and a mount you are riding gain a +2 bonus on Constitution checks to avoid damage and fatigue from <Link to="/rule/forced_march">hustling or a forced march</Link>. In plains terrain, this bonus is doubled and also applies on Survival checks to avoid getting lost, to find food and water, to protect yourself from severe weather, and to predict the weather.</p>
</>};
const _planar_focus = {title: "Planar Focus", jsx: <><h2 id="feat-planar_focus-planar-focus">Planar Focus</h2>
<p><strong>Sources</strong> <Link to="/source/monster_summoners_handbook">Monster Summoner's Handbook pg. 14</Link></p>
<p>By studying other planes, you've learned to take on aspects of outsiders as well as animals.<br/><strong>Prerequisites:</strong> Knowledge (planes) 5 ranks, <Link to="/ability/animal_focus">animal focus</Link> class feature.<br/><strong>Benefit:</strong> When you use your animal focus class feature, you can choose any of the following new aspects unless they conflict with your alignment.</p>
<blockquote>
<p><strong className="hl">Air:</strong> You gain a constant <Link to="/spell/feather_fall">feather fall</Link> effect. At 10th level, you instead gain a constant <Link to="/spell/levitate">levitate</Link> effect.</p>
<p><strong className="hl">Chaotic:</strong> Your form shifts subtly, making it difficult for others to aim precise attacks against you. You gain a 25% chance to negate extra damage from critical hits and <Link to="/misc/precision_damage">precision damage</Link> from attacks made against you (such as from <Link to="/ability/sneak_attack">sneak attacks</Link>). Only chaotic characters can use this planar focus.</p>
<p><strong className="hl">Cold:</strong> Creatures that attack you with natural attacks or melee weapons take 1d4 points of cold damage for every 2 class levels you possess.</p>
<p><strong className="hl">Earth:</strong> You gain a burrow speed equal to your base land speed, and a +2 enhancement bonus to your natural armor.</p>
<p><strong className="hl">Evil:</strong> You gain a +1 profane bonus to AC and on saves against attacks made and effects created by good outsiders. This bonus increases to +2 at 10th level. Only evil characters can use this planar focus.</p>
<p><strong className="hl">Fire:</strong> Your natural attacks and melee weapons deal 1d6 points of fire damage for every 4 class levels you possess.</p>
<p><strong className="hl">Good:</strong> You gain a +1 sacred bonus to AC and on saves against attacks made or effects created by evil outsiders. This bonus increases to +2 at 10th level. Only good characters can use this planar focus.</p>
<p><strong className="hl">Lawful:</strong> You can automatically succeed at any saving throw against a polymorph spell or effect. Only lawful characters can use this planar focus.</p>
<p><strong className="hl">Shadow:</strong> You gain a +5 bonus on Stealth and Sleight of Hand checks.</p>
<p><strong className="hl">Water:</strong> You gain a 30-foot swim speed and can breathe water as well as air.</p>
</blockquote>
</>};
const _planar_heritage = {title: "Planar Heritage", jsx: <><h2 id="feat-planar_heritage-planar-heritage">Planar Heritage</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 31</Link></p>
<p>You can trace your ancestry to a type of native outsider, even though you yourself are otherwise fully human.<br/><strong>Prerequisites:</strong> <Link to="/race/human">Human</Link>.<br/><strong>Benefit:</strong> Choose one type of native outsider (such as <Link to="/race/ganzi">ganzi</Link>). You count as both human and that race for any effects related to race. For example, if you choose ganzi, you are considered both a human and a ganzi for the purposes of taking traits, meeting feat prerequisites, determining how spells and magic items affect you, and so on. You must have the requisite physical features to gain certain benefits, as determined by the GM (for example, you cannot gain feats that augment your tail's abilities if you do not actually have a tail).<br/><strong>Special:</strong> You cannot select Planar Heritage if you already have an ability or feat (like <Link to="/feat/racial_heritage">Racial Heritage</Link>) that adjusts your heritage in this way.</p>
</>};
const _planar_hunter = {title: "Planar Hunter", jsx: <><h2 id="feat-planar_hunter-planar-hunter">Planar Hunter</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_balance">Champions of Balance pg. 13</Link></p>
<p>After careful study of otherworldly environments, you can quickly evaluate how an outsider reacts in its home surroundings. You can use your knowledge of the outsider's native environment to guide your attacks and overcome the outsider's natural resistances.<br/><strong>Prerequisites:</strong> Knowledge (planes) 5 ranks, <Link to="/ability/favored_terrain">favored terrain</Link> (any plane) class feature.<br/><strong>Benefit:</strong> When you are on one of the planes you've selected as a favored terrain, you gain a +2 bonus on weapon attack rolls against outsiders native to that plane. You also ignore up to 5 points of damage reduction when making weapon attacks against outsiders native to that plane, except for damage reduction without a type (such as DR 10/-). In addition, you gain this bonus against extraplanar creatures you encounter and identify as being from one of your planar favored terrains, such as with a successful Knowledge (planes) check, regardless of what plane you or they are on.<br/><strong>Special:</strong> You may select this feat multiple times. Each time you take it, you apply it to a different qualifying favored terrain.</p>
</>};
const _planar_infusion = {hasJL:true,title: "Planar Infusion", jsx: <><div className="jumpList" id="feat-planar_infusion-jumplist"><h2>Jump to:</h2><ul><li><InnerLink toTop to="feat-planar_infusion-abyss">Abyss</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-abaddon">Abaddon</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-akashic-record">Akashic Record</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-astral-plane">Astral Plane</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-axis">Axis</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-boneyard">Boneyard</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-cynosure">Cynosure</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-dead-vault">Dead Vault</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-dimension-of-dreamsdreamlands">Dimension of Dreams/Dreamlands</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-dimension-of-time">Dimension of Time</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-elysium">Elysium</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-ethereal-plane">Ethereal Plane</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-first-world">First World</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-hao-jin-tapestry">Hao Jin Tapestry</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-harrowed-realm">Harrowed Realm</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-heaven">Heaven</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-hell">Hell</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-jandelay">Jandelay</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-leng">Leng</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-maelstrom">Maelstrom</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-material-plane">Material Plane</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-negative-energy-plane">Negative Energy Plane</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-nirvana">Nirvana</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-plane-of-air">Plane of Air</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-plane-of-earth">Plane of Earth</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-plane-of-fire">Plane of Fire</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-plane-of-water">Plane of Water</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-positive-energy-plane">Positive Energy Plane</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-shadow-plane">Shadow Plane</InnerLink></li><li><InnerLink toTop to="feat-planar_infusion-xibalba">Xibalba</InnerLink></li></ul></div><h2 id="feat-planar_infusion-planar-infusion-conduit">Planar Infusion (Conduit)</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 31</Link></p>
<p>After enduring hardship on another plane, your body, mind, and soul have become infused with that plane's power.<br/><strong>Prerequisites:</strong> You must spend a significant amount of time on a plane other than your home plane or the Material Plane. Typically, this amount of time should coincide with an adventure set on that plane, but at the GM's discretion, you can qualify for this feat in other ways, such as by being subjected to a powerful planar effect via the influence of an artifact associated with that plane, being exposed to raw energies from the plane, or even by dying on another plane and being brought back to life in that reality.<br/><strong>Benefit:</strong> Your body, mind, or soul gains a benefit of some sort as a result of your infusion with the plane of your choice for which you meet the prerequisite. Details on planar infusions can be found below.</p>
<p>Planar infusions that take actions to activate are supernatural abilities unless they specifically allow for the use of a spell, in which case they are spell-like abilities. Your caster level for spell-like abilities granted by a planar infusion is equal to your Hit Dice (maximum CL 20th). All other planar infusions are extraordinary abilities.</p>
<p><strong>Special:</strong> You can take this feat multiple times. Each time you do, you must select another plane for which you qualify. In cases where the specific effects of Planar Infusion are identical, the effects do not stack.</p>
<h3 id="feat-planar_infusion-planar-infusions">Planar Infusions</h3>
<h4 id="feat-planar_infusion-abyss" data-hash-target>Abyss</h4>
<p><strong>Basic:</strong> The horrific fecundity of <Link to="/rule/the_abyss">the Abyss</Link> and its entropic drive to expand and consume have bolstered your body and enhanced your capacities for cruelty. You gain a +1 bonus on Fortitude saves, a +2 bonus on Intimidate checks to demoralize a foe, and a +2 bonus on attack rolls to confirm critical hits.</p>
<p><strong>Improved:</strong> You can call upon the Abyss to infect and transform the surrounding terrain, afflicting it with horrors and nightmares. You can use <Link to="/spell/curse_terrain">curse terrain</Link> as a spell-like ability once per day.</p>
<p><strong>Greater:</strong> You can flood a creature's mind with horrific truths and the overwhelming chaos and evil from the Abyss. You can use <Link to="/spell/insanity">insanity</Link> as a spell-like ability once per day.</p>
<h4 id="feat-planar_infusion-abaddon" data-hash-target>Abaddon</h4>
<p><strong>Basic:</strong> Your link to <Link to="/rule/abaddon">Abaddon</Link> enhances your skill in hunting prey while avoiding being hunted yourself. You gain a +1 bonus on Reflex saves, you can move at full speed while hiding your tracks, and you a gain a +2 bonus on Survival checks to follow tracks.</p>
<p><strong>Improved:</strong> Mirroring Abaddon's hunger for and mastery over souls, you gain a +4 bonus on all saving throws against possession effects and effects that tamper with your soul, such as <Link to="/spell/soul_trap">soul trap</Link> or an <Link to="/monster/astradaemon">astradaemon's</Link> devour soul ability. Furthermore, you can consume a soul gem created by a <Link to="/monster/cacodaemon">cacodaemon</Link> as a standard action. Immediately thereafter, for a number of rounds equal to your Hit Dice, you are treated as an evil outsider and gain <Link to="/umr/fast_healing">fast healing</Link> 2.</p>
<p><strong>Greater:</strong> The waters of the River Styx infuse you. You are immune to effects that cause amnesia or otherwise alter your memory, including the effect of the Styx itself. Your touch can affect the memories of others as well. Three times per day, you can use <Link to="/spell/mindwipe">mindwipe</Link> as a spell-like ability.</p>
<h4 id="feat-planar_infusion-akashic-record" data-hash-target>Akashic Record</h4>
<p><strong>Basic:</strong> Your memories have been infused with energies from the <Link to="/rule/akashic_record">Akashic Record</Link>, but it's difficult to keep them all at the forefront of your thoughts. Once per day (typically when you wake from sleep), select one Knowledge skill. You gain a +2 bonus on checks using that skill for the remainder of the day. If you have at least 10 ranks in that skill, you instead gain a +4 bonus on checks using that skill.</p>
<p><strong>Improved:</strong> You can use <Link to="/spell/divination">divination</Link> once per day as a spell-like ability.</p>
<p><strong>Greater:</strong> You can use <Link to="/spell/retrocognition">retrocognition</Link> once per day as a spell-like ability.</p>
<h4 id="feat-planar_infusion-astral-plane" data-hash-target>Astral Plane</h4>
<p><strong>Basic:</strong> You gain a +2 bonus on saves against curses, diseases, and poisons. You also gain a +4 bonus on Wisdom checks to maneuver in <Link to="/rule/gravity_traits">subjective directional gravity</Link>.</p>
<p><strong>Improved:</strong> You always succeed at Wisdom checks to maneuver in subjective directional gravity. Increase your maximum lifespan and the number of years you must age to reach each age category by 10%. You can act under the effects of <Link to="/spell/haste">haste</Link> as a free action for 1 round; you can activate this ability a number of times per day equal to your Hit Dice divided by 4 (minimum of 1 round per day). These rounds need not be consecutive.</p>
<p><strong>Greater:</strong> Select one of the following <Link to="/rule/afflictions">afflictions</Link>: curses, diseases, or poisons. You become immune to the effects of that affliction. Increase your maximum lifespan and the number of years you must <Link to="/rule/age">age</Link> to reach each age category by an additional 10% (20% total when combined with the improved infusion above), and you do not retroactively age or hunger when departing a plane with the timeless <Link to="/rule/planar_traits">planar trait</Link>. You gain a fly speed of 60 feet (perfect) on the <Link to="/rule/astral_plane">Astral Plane</Link>.</p>
<h4 id="feat-planar_infusion-axis" data-hash-target>Axis</h4>
<p><strong>Basic:</strong> The rigidity and order of <Link to="/rule/axis">Axis</Link> bolsters you physically, enhances your ability to notice tiny imperfections, and inspires your ability to create. You gain a +1 bonus on Fortitude saves, a +2 bonus on one Craft skill of your choice, and a +2 bonus on Perception checks to find secret doors or hidden traps.</p>
<p><strong>Improved:</strong> You are never far from the comforts and safety of urban life. You can use <Link to="/spell/secure_shelter">secure shelter</Link> once per day as a spell-like ability.</p>
<p><strong>Greater:</strong> You can transform yourself into a whirling cloud of glowing glyphs and symbols as a standard action. While in this form, you gain a fly speed of 60 feet with perfect maneuverability and can move through small cracks as per <Link to="/spell/gaseous_form">gaseous form</Link> (but you are not prohibited from entering water). You gain DR 10/chaos and <Link to="/umr/regeneration">regeneration</Link> 5/chaos and are immune to <Link to="/misc/precision_damage">precision damage</Link> and critical hits while in glyph form. You can remain in this form for up to 1 minute per level each day, but these minutes need not be used consecutively.</p>
<h4 id="feat-planar_infusion-boneyard" data-hash-target>Boneyard</h4>
<p><strong>Basic:</strong> The knowledge that <Link to="/rule/the_boneyard_pa">the Boneyard</Link> awaits us all bolsters your ability to resist the pull of death and to aid others in doing the same. You gain a +1 bonus on Will saves, a +2 bonus on Heal checks to stabilize a dying creature, and a +4 bonus on Constitution checks to stabilize yourself when your hit points are reduced below 0.</p>
<p><strong>Improved:</strong> You can use <Link to="/spell/death_ward">death ward</Link> once per day as a spell-like ability.</p>
<p><strong>Greater:</strong> Once per day, you can attempt to revoke the unnatural energies that empower an undead creature's animation. This spell-like ability functions as <Link to="/spell/destruction">destruction</Link>, save that it is not a death effect and can target only undead creatures. As a spell-like ability, it does not require an expensive focus to function.</p>
<h4 id="feat-planar_infusion-cynosure" data-hash-target>Cynosure</h4>
<p><strong>Basic:</strong> Your connection to <Link to="/rule/cynosure">Cynosure</Link> allows you to remain alert as you sleep and have more control over effects that force you to slumber. Perception check DCs are not modified for you when you are asleep, and you gain a +4 bonus on all saving throws against sleep effects.</p>
<p><strong>Improved:</strong> You can use <Link to="/spell/air_walk">air walk</Link> once per day as a spell-like ability.</p>
<p><strong>Greater:</strong> You can use <Link to="/spell/dream_travel">dream travel</Link> once per day as a spell-like ability. When you do so, you roll twice to determine how accurate your arrival is at the end of the journey and take the better of the two results as your actual result.</p>
<h4 id="feat-planar_infusion-dead-vault" data-hash-target>Dead Vault</h4>
<p><strong>Basic:</strong> The inexorable strengths of <Link to="/faith/rovagug">Rovagug's</Link> prison suffuse you, making you difficult to move against your will and enhancing your ability to detain others. You gain a +4 bonus to CMD against combat maneuvers that attempt to force you to change position (such as <Link to="/rule/bull_rush">bull rush</Link> or <Link to="/rule/reposition">reposition</Link>), and a +4 bonus on <Link to="/rule/grapple">grapple</Link> checks to maintain an existing grapple.</p>
<p><strong>Improved:</strong> You can use <Link to="/spell/dimensional_anchor">dimensional anchor</Link> as a spell-like ability once per day.</p>
<p><strong>Greater:</strong> You can use <Link to="/spell/forcecage">forcecage</Link> as a spell-like ability once per day, but only to create a windowless cell.</p>
<h4 id="feat-planar_infusion-dimension-of-dreamsdreamlands" data-hash-target>Dimension of Dreams/Dreamlands</h4>
<p><strong>Basic:</strong> You gain a +4 bonus on Charisma checks to arrive in the <Link to="/rule/dimension_of_dreams">Dimension of Dreams</Link> at an advantage, and you can attempt one additional impossible action beyond the normal limit during a visit to a Dreamscape.</p>
<p><strong>Improved:</strong> You can use <Link to="/spell/dream">dream</Link> as a spell-like ability once per day.</p>
<p><strong>Greater:</strong> You can use <Link to="/spell/dream_council">dream council</Link> as a spell-like ability once per day.</p>
<h4 id="feat-planar_infusion-dimension-of-time" data-hash-target>Dimension of Time</h4>
<p><strong>Basic:</strong> Once per day, you can roll twice for initiative and take the higher roll as your actual result. When you gain the improved infusion, you can use this basic infusion twice per day. When you gain the greater infusion, you can use this ability three times per day.</p>
<p><strong>Improved:</strong> Once per day, you can touch an object that was once alive, such as wood, paper, or a dead body. That object is protected from time, as if you had used a dose of <Link to="/magic-wondrous/unguent_of_timelessness">unguent of timelessness</Link> on the object. You can maintain this effect on a number of objects equal to your Intelligence modifier (minimum of 1) at any one time. If you exceed this limit, the oldest existing effect immediately ceases.</p>
<p><strong>Greater:</strong> You are immune to <Link to="/spell/temporal_stasis">temporal stasis</Link>. In addition, once per day, when a creature within 30 feet of you casts <Link to="/spell/time_stop">time stop</Link>, you are treated as if you were under the effects of <em>time stop</em> as well and are free to act for as long as the spell effect allows. This ability activates automatically, whether you notice the casting of the spell or not.</p>
<h4 id="feat-planar_infusion-elysium" data-hash-target>Elysium</h4>
<p><strong>Basic:</strong> <Link to="/rule/elysium">Elysium</Link> has inspired your artistic sense and quickened your agility. You gain a +1 bonus on Reflex saves, a +2 bonus on Acrobatics checks to avoid provoking attacks of opportunity, and a +2 bonus on a single type of Perform check of your choice.</p>
<p><strong>Improved:</strong> You can use <Link to="/spell/confusion">confusion</Link> once per day as a spell-like ability. Lawful or evil targets take a -1 penalty on saves against this effect, while lawful evil targets take a -2 penalty on saves.</p>
<p><strong>Greater:</strong> Elysium's blessing bolsters your bravery and sense of self. Whenever you are under the effects of an ongoing fear effect, a possession effect, or an effect that grants mental control over you (such as <Link to="/spell/dominate_person">dominate person</Link>), at the beginning of each of your turns, you can attempt a new saving throw against that effect as though you were initially exposed to it. On a success, the effect immediately ends. You can attempt a number of additional saves this way each day equal to 3 + your Charisma modifier (minimum 4/day).</p>
<h4 id="feat-planar_infusion-ethereal-plane" data-hash-target>Ethereal Plane</h4>
<p><strong>Basic:</strong> Your senses are sharp and attuned to the Ghost World. You gain a +3 bonus on Perception checks on the <Link to="/rule/ethereal_plane">Ethereal Plane</Link>, against creatures native to the Ethereal Plane, or against creatures on the Material Plane that are ethereal. When on the Ethereal Plane, you can see twice as far (clearly to 600 feet, and indistinctly to 1,800 feet).</p>
<p><strong>Improved:</strong> Your sense of sight on the Ethereal Plane improves greatly, and you can see clearly in the Ghost World. You can gain nourishment and water from ectoplasm as if it were a tasteless food, and once per day you can use <Link to="/spell/ectoplasmic_snare">ectoplasmic snare</Link> as a spell-like ability.</p>
<p><strong>Greater:</strong> You can step from reality into the In-Between to travel and explore. Once per day you can use <Link to="/spell/ethereal_jaunt">ethereal jaunt</Link> as a spell-like ability.</p>
<h4 id="feat-planar_infusion-first-world" data-hash-target>First World</h4>
<p><strong>Basic:</strong> Traveling in the constantly changing <Link to="/rule/the_first_world">First World</Link> has taught you to be ever ready for situations to shift in unpredictable ways. You gain a +2 bonus on Perception checks, initiative checks, and Charisma checks to shape <Link to="/rule/the_first_world">the First World</Link>.</p>
<p><strong>Improved:</strong> Once per day, you can summon a fey creature from the First World to serve you, as if using <Link to="/spell/summon_natures_ally_iv">summon nature's ally IV</Link> as a spell-like ability. When you use this ability, you can choose to summon 1 <Link to="/monster/boggart">boggart</Link>, 1 <Link to="/monster/calpina">calpina</Link>, 1 <Link to="/monster/huldra">huldra</Link> (a summoned huldra's manipulate luck ability's duration lasts only as long as the summoned huldra persists), 1 <Link to="/monster/satyr">satyr</Link>, 1d3 <Link to="/monster/liminal_sprite">liminal sprites</Link>, 1d3 <Link to="/monster/pooka">pookas</Link>, 1d4+1 <Link to="/monster/atomie">atomies</Link>, 1d4+1 <Link to="/monster/brownie">brownies</Link>, 1d4+1 <Link to="/monster/faun">fauns</Link>, 1d4+1 <Link to="/monster/grig">grigs</Link>, or 1d4+1 <Link to="/monster/mockingfey">mockingfeys</Link>.</p>
<p><strong>Greater:</strong> You can use <Link to="/spell/fey_form_iii">fey form III</Link> as a spell-like ability once per day.</p>
<h4 id="feat-planar_infusion-hao-jin-tapestry" data-hash-target>Hao Jin Tapestry</h4>
<p><strong>Basic:</strong> An infusion of the <Link to="/rule/hao_jin_tapestry">Hao Jin Tapestry</Link> makes you become sensitive to the reality-warping presence of extradimensional spaces and magical portals. You can use Perception or Knowledge (planes) in place of Spellcraft to identify magic items, spells, and magical effects associated with such effects as if using <Link to="/spell/detect_magic">detect magic</Link>.</p>
<p><strong>Improved:</strong> You can use <Link to="/spell/dimension_door">dimension door</Link> once per day as a spell-like ability.</p>
<p><strong>Greater:</strong> You can use <Link to="/spell/mages_magnificent_mansion">mage's magnificent mansion</Link> once per day as a spell-like ability.</p>
<h4 id="feat-planar_infusion-harrowed-realm" data-hash-target>Harrowed Realm</h4>
<p><strong>Basic:</strong> Living in the <Link to="/rule/harrowed_realm">Harrowed Realm</Link> has given you some insight into fate. Once per day, you can draw a card from a <Link to="/eq-misc/harrow_deck">Harrow deck</Link> to randomly choose one of the six ability scores. (Players who don't have an actual Harrow deck can instead roll 1d6 to randomly determine an ability score.) At any point during the next 24 hours, you can gain a +2 bonus on a single d20 roll modified by that ability score. You can add this bonus after the die is rolled, but must do so before you learn the outcome of the roll.</p>
<p><strong>Improved:</strong> The bonus granted by your basic infusion is now +4, and you can apply the bonus on two different d20 rolls during the day.</p>
<p><strong>Greater:</strong> The bonus granted by your basic infusion is now +6, and you can apply the bonus on three different d20 rolls during the day. Alternatively, you can expend all three uses for the day to apply the bonus on a d20 roll after you've learned the outcome of the roll.</p>
<h4 id="feat-planar_infusion-heaven" data-hash-target>Heaven</h4>
<p><strong>Basic:</strong> Your acceptance of <Link to="/rule/heaven">Heaven</Link> has fortified your physical endurance and bolsters your presence. You gain a +1 bonus on Fortitude saves, a +2 bonus on Diplomacy checks against good creatures, and a +2 bonus on Intimidate checks against evil creatures.</p>
<p><strong>Improved:</strong> You can call down Heaven's divine fury as a standard action, channeling it through your own body and expelling it all around you. Once per day, you can release this divine energy in a 30-foot-radius <Link to="/misc/burst">burst</Link> centered on you. Each evil creature within the area takes 1d8 points of damage per character level you have (maximum 10d8) and is <Link to="/misc/blinded">blinded</Link> for a number of rounds equal to your Charisma modifier (minimum 1 round). On a successful Will save, an affected creature takes only half damage and negates the blindness.</p>
<p><strong>Greater:</strong> You can keep Heaven's champions from being called home before their work is complete. Twice per day, you can use <Link to="/spell/breath_of_life">breath of life</Link> as a spell-like ability. If the target is lawful good, you can use this ability as a move action. If the target is evil, it becomes <Link to="/misc/staggered">staggered</Link> for 10 minutes unless it vows to repent for its evil ways.</p>
<h4 id="feat-planar_infusion-hell" data-hash-target>Hell</h4>
<p><strong>Basic:</strong> <Link to="/rule/hell">Hell's</Link> influence grants you a silvered tongue and bolsters your arrogance. You gain a +1 bonus on Will saves, a +2 bonus on Bluff checks to lie to or fool someone, and a +2 bonus on Diplomacy checks to adjust a creature's attitude.</p>
<p><strong>Improved:</strong> Whenever you deal fire damage, you can instead deal hellfire damage (hellfire damage is half fire damage and half damage from unholy energy; evil-aligned creatures and creatures with the evil subtype take no damage from the unholy energy, but good-aligned beings and those with the good subtype take double the normal damage from it. Creatures under the effects of spells such as <Link to="/spell/protection_from_evil">protection from evil</Link> are unaffected by this unholy energy, though they are still subject to the fire damage.). Secondary fires lit by your initial fire attack deal normal fire damage (including burn damage, if such damage occurs).</p>
<p><strong>Greater:</strong> You can inflict the agonizing pain of eternal damnation on the masses for a brief instant. You can use <Link to="/spell/mass_inflict_pain">mass inflict pain</Link> once per day as a spell-like ability.</p>
<h4 id="feat-planar_infusion-jandelay" data-hash-target>Jandelay</h4>
<p><strong>Basic:</strong> The power of Jandelay infuses your being, granting you resistance against entropy. You gain a +4 bonus on saving throws against effects that reduce your body to dust (such as <Link to="/spell/destruction">destruction</Link> or <Link to="/spell/disintegrate">disintegrate</Link>) and on saving throws against confusion effects and spells with the chaos descriptor.</p>
<p><strong>Improved:</strong> You can use <Link to="/spell/orders_wrath">order's wrath</Link> once per day as a spell-like ability.</p>
<p><strong>Greater:</strong> You can use <Link to="/spell/dictum">dictum</Link> once per day as a spell-like ability.</p>
<h4 id="feat-planar_infusion-leng" data-hash-target>Leng</h4>
<p><strong>Basic:</strong> You can infuse the menace of Leng into everything you do. You gain a +2 bonus on Intimidate checks to demoralize foes, and you increase the save DC of supernatural fear effects you create by 1.</p>
<p><strong>Improved:</strong> You can use <Link to="/spell/confusion">confusion</Link> once per day as a spell-like ability.</p>
<p><strong>Greater:</strong> You can use <Link to="/spell/contact_entity_iv">contact entity IV</Link> once per day as a spell-like ability but must still supply the required material component.</p>
<h4 id="feat-planar_infusion-maelstrom" data-hash-target>Maelstrom</h4>
<p><strong>Basic:</strong> <Link to="/rule/maelstrom">The Maelstrom</Link> grants you the ability to react to unpredictable situations, while also helping you to be more unpredictable. You gain a +1 bonus on initiative checks, a +1 bonus on Reflex saves, and a +2 bonus on Bluff checks to <Link to="/rule/feint">feint</Link> in combat.</p>
<p><strong>Improved:</strong> The whimsical entropy of the Maelstrom runs through your veins. Once per day, you can use <em>confusion</em> as a spell-like ability.</p>
<p><strong>Greater:</strong> You can invoke the pure chaos of the Maelstrom with a word. Once per day, you can use <Link to="/spell/word_of_chaos">word of chaos</Link> as a spell-like ability.</p>
<h4 id="feat-planar_infusion-material-plane" data-hash-target>Material Plane</h4>
<p><strong>Basic:</strong> none</p>
<p><strong>Improved:</strong> none</p>
<p><strong>Greater:</strong> none</p>
<h4 id="feat-planar_infusion-negative-energy-plane" data-hash-target>Negative Energy Plane</h4>
<p><strong>Basic:</strong> You have been infused with unlife and are affected by positive and <Link to="/rule/negative_energy_plane">negative energy</Link> as if you were undead. Undead creatures who gain this ability instead gain a +2 bonus to their <Link to="/umr/channel_resistance">channel resistance</Link>.</p>
<p><strong>Improved:</strong> You can use <Link to="/spell/enervation">enervation</Link> once per day as a spell-like ability.</p>
<p><strong>Greater:</strong> Negative energy suffuses your being and can be unleashed in a devastating burst once per day as an immediate action when are reduced to 0 or fewer hit points. This creates an explosion of negative energy in a 20-foot burst, centered on you, that deals 1d6 points of negative energy damage per Hit Die you have (maximum 20d6) to all creatures in the area of effect. Each affected creature can attempt a Reflex save (DC = 10 + half your Hit Dice + your Charisma modifier) to take half damage. This negative energy damage does not heal undead. When this effect is triggered, you regain a number of hit points equal to your total Hit Dice; this healing applies immediately, and if it brings your hit point total above a negative number equal to your Constitution (or above 0 if you are undead), then the healing prevents your death.</p>
<h4 id="feat-planar_infusion-nirvana" data-hash-target>Nirvana</h4>
<p><strong>Basic:</strong> <Link to="/rule/nirvana">Nirvana's</Link> influence has enlightened your mind. You gain a +1 bonus on Will saves, a +1 bonus on Perception checks, and a +2 bonus on Sense Motive checks to avoid being bluffed.</p>
<p><strong>Improved:</strong> You can focus on Nirvana's serenity, allowing you to restore a creature's sense of self with a touch. This functions as <Link to="/spell/restoration">restoration</Link>, but it cannot cure ability damage or drain to Strength, Dexterity, or Constitution, nor can it eliminate <Link to="/misc/fatigue">fatigue</Link> or <Link to="/misc/exhaustion">exhaustion</Link>. You can use this ability once per day. As a spell-like ability, it does not require a diamond dust component unless the target is nongood, in which case you must supply the 100 gp or 1,000 gp of diamond dust as if you had cast the spell normally.</p>
<p><strong>Greater:</strong> You gain <em>truespeech</em> and can speak with any creature that has a language, as though you were using the <Link to="/spell/tongues">tongues</Link> spell. You gain a +4 bonus on all saving throws against language-dependent effects, and any language-dependent effect you create that allows a saving throw has its save DC increased by 1.</p>
<h4 id="feat-planar_infusion-plane-of-air" data-hash-target>Plane of Air</h4>
<p><strong>Basic:</strong> You gain a +2 bonus on Fly checks and a +2 bonus on saving throws against air or electricity effects, thanks to your connection with the <Link to="/rule/plane_of_air">Plane of Air</Link>.</p>
<p><strong>Improved:</strong> You can use <Link to="/spell/air_walk">air walk</Link> once per day as a spell-like ability.</p>
<p><strong>Greater:</strong> You can use <Link to="/spell/wind_walk">wind walk</Link> once per day as a spell-like ability.</p>
<h4 id="feat-planar_infusion-plane-of-earth" data-hash-target>Plane of Earth</h4>
<p><strong>Basic:</strong> You gain a +2 bonus on Climb checks and a +2 bonus on saving throws against earth and acid effects, thanks to your connection with the <Link to="/rule/plane_of_earth">Plane of Earth</Link>.</p>
<p><strong>Improved:</strong> You can use <Link to="/spell/acid_pit">acid pit</Link> once per day as a spell-like ability.</p>
<p><strong>Greater:</strong> You can use <Link to="/spell/statue">statue</Link> once per day as a spell-like ability.</p>
<h4 id="feat-planar_infusion-plane-of-fire" data-hash-target>Plane of Fire</h4>
<p><strong>Basic:</strong> You gain a +2 bonus on Acrobatics checks and a +2 bonus on saving throws against fire effects, thanks to your connection with the <Link to="/rule/plane_of_fire">Plane of Fire</Link>.</p>
<p><strong>Improved:</strong> You can use <Link to="/spell/wall_of_fire">wall of fire</Link> once per day as a spell-like ability.</p>
<p><strong>Greater:</strong> You can use <Link to="/spell/delayed_blast_fireball">delayed blast fireball</Link> once per day as a spell-like ability.</p>
<h4 id="feat-planar_infusion-plane-of-water" data-hash-target>Plane of Water</h4>
<p><strong>Basic:</strong> You gain a +2 bonus on Swim checks and a +2 bonus on saving throws against water and cold effects, thanks to your connection with the <Link to="/rule/plane_of_water">Plane of Water</Link>.</p>
<p><strong>Improved:</strong> You can use <Link to="/spell/control_water">control water</Link> once per day as a spell-like ability.</p>
<p><strong>Greater:</strong> You can use <Link to="/spell/vortex">vortex</Link> once per day as a spell-like ability.</p>
<h4 id="feat-planar_infusion-positive-energy-plane" data-hash-target>Positive Energy Plane</h4>
<p><strong>Basic:</strong> You've been infused with raw life force, and whenever you're healed by a positive energy effect (including all <Link to="/main/cure_spells">cure spells</Link>), you regain an additional number of hit points equal to your total Hit Dice. You gain a +4 bonus on Constitution checks to stabilize while dying.</p>
<p><strong>Improved:</strong> Thanks to your deeper understanding of <Link to="/rule/positive_energy_plane">positive energy</Link>, you can call upon it to restore yourself or others. Once per day you can touch a creature to create one of the following effects as a spell-like ability: <Link to="/spell/cure_serious_wounds">cure serious wounds</Link>, <Link to="/spell/lesser_restoration">lesser restoration</Link>, <Link to="/spell/remove_blindness_deafness">remove blindness/deafness</Link>, <Link to="/spell/remove_disease">remove disease</Link>, or <Link to="/spell/remove_paralysis">remove paralysis</Link>. If you use the ability on yourself, this ability requires only a move action to activate.</p>
<p><strong>Greater:</strong> Once per day, you can use <Link to="/spell/raise_dead">raise dead</Link> as a spell-like ability. If you use this ability on a creature that has been dead no longer than 1 minute per Hit Die you have, the creature restored to life does not incur any negative levels and does not lose its prepared spells or spell slots, nor does this ability require an expensive material component. If you use this ability on a creature that has been dead longer than 1 minute per Hit Die you have, you must supply the material component as usual, and the target is subject to the normal side effects for raise dead.</p>
<h4 id="feat-planar_infusion-shadow-plane" data-hash-target>Shadow Plane</h4>
<p><strong>Basic:</strong> You can see clearly in shadowy conditions to a short range. In every square in your space, and in all squares adjacent to your space, you treat conditions of <Link to="/rule/dim_light">dim light</Link> as normal light.</p>
<p><strong>Improved:</strong> You have the ability to use <Link to="/spell/shadow_conjuration">shadow conjuration</Link> once per day as a spell-like ability.</p>
<p><strong>Greater:</strong> The essence of <Link to="/rule/shadow_plane">shadow</Link> so infuses your being that you sometimes exist only partially when subjected to damage. As an immediate action when you would take damage from an attack, spell, or other effect, you can reflexively dissolve the portion of your body that would be injured into quasi-real shadowstuff to gain a 50% chance to ignore all the damage from the effect. You can successfully ignore damage in this way up to three times per day - if you activate this ability and it fails to prevent damage, it does not count against your limited daily uses of the ability.</p>
<h4 id="feat-planar_infusion-xibalba" data-hash-target>Xibalba</h4>
<p><strong>Basic:</strong> The dread horrors of Xibalba infuse your being, and there is little that can further unnerve you. Increase the save DC of fear effects you create by 1, and you gain a +2 bonus on all saving throws against fear effects.</p>
<p><strong>Improved:</strong> You can use <Link to="/spell/phantasmal_killer">phantasmal killer</Link> as a spell-like ability once per day.</p>
<p><strong>Greater:</strong> You can use <Link to="/spell/insanity">insanity</Link> as a spell-like ability once per day.</p>
</>};
const _planar_mentor = {title: "Planar Mentor", jsx: <><h2 id="feat-planar_mentor-planar-mentor">Planar Mentor</h2>
<p><strong>Sources</strong> <Link to="/source/plane_hoppers_handbook">Plane-Hopper's Handbook pg. 26</Link></p>
<p>Whether you sought it out, caught its attention, or inherited its service, an outsider is watching over you. The more you impress it, the more it shares its power and knowledge.<br/><strong>Benefit:</strong> When you take this feat, choose one non-unique outsider with 18 Hit Dice or fewer and whose alignment is within one step of your own along either the law/chaos axis or the good/evil axis. Twice per day (three times per day for an outsider with only neutral alignment components) when you fulfill the condition associated with either component of your mentor's alignment, you can gain your mentor's boon for that alignment as an immediate action. This grants you resistance equal to your level to a particular energy type as well as a special benefit associated with that alignment. These benefits last for a number of rounds equal to your Charisma modifier + 1 (minimum 1).</p>
<blockquote>
<p><strong className="hl">Chaotic:</strong> To earn chaotic approval, you must provoke an attack of opportunity from a creature whose CR is at least half your level. You gain acid resistance as well as a 10% miss chance due to <Link to="/rule/concealment">concealment</Link>.</p>
<p><strong className="hl">Evil:</strong> To earn evil approval, you must damage a <Link to="/rule/flat_footed">flat-footed</Link> foe, hit a foe you're <Link to="/rule/flanking">flanking</Link>, or confirm a critical hit. You gain fire resistance, and your attacks deal an amount of bleed damage equal to half your level.</p>
<p><strong className="hl">Good:</strong> To earn good approval, you must heal another creature or deal nonlethal damage to a foe using an ability that has no additional effects beyond nonlethal damage. You gain electricity resistance and a +2 bonus on your saving throws.</p>
<p><strong className="hl">Lawful:</strong> To earn lawful approval, you must perform the <Link to="/rule/aid_another">aid another</Link> action for an ally whose level is equal to or greater than your own, or you must benefit from the aid another action from such an ally. You gain cold resistance and the benefits of the light fortification armor special ability.</p>
<p><strong className="hl">Neutral:</strong> To earn neutral approval, you must succeed at a saving throw prompted by a source with a CR of at least half your level. You gain resistance to any one energy type (your choice) and a +2 bonus on skill checks.</p>
</blockquote>
<p>If your mentor is killed or imprisoned, you lose the benefits of this feat and any feats for which it is a prerequisite. When you gain a level, you can secure a new mentor by performing a ritual that takes 8 hours and expends components worth 200 gp &times; the new mentor's Hit Dice.</p>
<p><strong>Special:</strong> At the GM's discretion, a PC can select an outsider of any alignment. This represents a relationship in which the outsider is attempting to corrupt, redeem, or otherwise influence the PC.</p>
</>};
const _planar_preservationist = {title: "Planar Preservationist", jsx: <><h2 id="feat-planar_preservationist-planar-preservationist">Planar Preservationist</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 154</Link></p>
<p>You know how to preserve and reconstitute extraplanar monsters as well as normal animals.<br/><strong>Prerequisites:</strong> <Link to="/arc-alchemist/preservationist">Preservationist</Link> alchemist archetype.<br/><strong>Benefit:</strong> For every <Link to="/spell/summon_natures_ally">summon nature's ally</Link> extract you know, you learn the equivalent <Link to="/spell/summon_monster">summon monster</Link> spell as an extract. If you later learn other <em>summon nature's ally</em> extracts, you automatically learn the equivalent <em>summon monster</em> spell as an extract.</p>
</>};
const _planar_sensitivity = {title: "Planar Sensitivity", jsx: <><h2 id="feat-planar_sensitivity-planar-sensitivity">Planar Sensitivity</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_105_the_inferno_gate">Pathfinder #105: The Inferno Gate pg. 64</Link></p>
<p>You can sense and manipulate connections between the planes.<br/><strong>Prerequisites:</strong> Knowledge (planes) 3 ranks.<br/><strong>Benefit:</strong> You gain access to the gatefinder and gatekeeper skill unlocks (see below).<br/><strong>Special:</strong> Sentient outsiders who have one or more ranks in Knowledge (planes) and who lack the native subtype are treated as having this feat.</p>
<h3 id="feat-planar_sensitivity-gatefinder-perception">Gatefinder (Perception)</h3>
<p>You can notice <Link to="/rule/planar_travel">soulgates</Link> compatible with your alignment.</p>
<p><strong>Check:</strong> You are familiar with soulgates and might notice those with an alignment matching your own. To notice a soulgate that you're not already familiar with, you must succeed at a DC 20 <Link to="/skill/perception">Perception</Link> check - this DC could be higher if the portal is obscured or damaged, or at the GM's discretion. If the soulgate shares your exact alignment, you gain a +5 bonus on your check to notice the portal, feeling an instinctual draw toward it. If your alignment and the portal's share none of the same components, you take a -5 penalty on your check to notice the portal. If your alignment is neutral with no other alignment components, you take no penalties on checks to find soulgates.</p>
<p>For example, a lawful good character would gain a +5 bonus on her Perception checks to find lawful good soulgates, but would take a -5 penalty on checks to find chaotic evil, chaotic neutral, and neutral evil soulgates, as she has no chaotic, neutral, or evil components to her alignment. A neutral character, however, gains a +5 bonus on checks to find neutral gates, but gains no bonus on checks to find chaotic neutral, lawful neutral, neutral good, and neutral evil soulgates. Additionally, she takes no penalty on checks to notice chaotic good, chaotic evil, lawful good, or lawful evil soulgates.</p>
<p>Once you are aware of a soulgate, you never need to succeed at a Perception check to find that particular gate again, as long as some remarkable event doesn't change its appearance or location.</p>
<h3 id="feat-planar_sensitivity-gatekeeper-knowledge-planes">Gatekeeper (Knowledge [Planes])</h3>
<p>You can attempt to open soulgates compatible with your alignment.</p>
<p><strong>Check:</strong> Once you are aware of a soulgate, you can use your knowledge of the planes and your place as a child of the multiverse to attempt to open the portal. This attempt takes 1 minute to perform. The DC of the <Link to="/skill/knowledge_planes">Knowledge (planes)</Link> check to open a soulgate is 30. If your alignment perfectly matches that of the soulgate, you gain a +5 bonus on this check. You can also attempt to open a soulgate with an alignment that is within one step of your own. However, unless you are neutral, you cannot open a soulgate with an alignment two or more steps away from your own.</p>
<p>For example, a lawful evil character would gain a +5 bonus on her attempt to open a soulgate connecting the Material Plane to <Link to="/rule/hell">Hell</Link> (lawful evil) or other planes of lawful evil alignment. She can also attempt to open soulgates to <Link to="/rule/abaddon">Abaddon</Link> (neutral evil), <Link to="/rule/axis">Axis</Link> (lawful neutral), and other planes that share those planes' alignments, because their alignments are one step away from lawful evil. She can never open a soulgate to <Link to="/rule/the_abyss">the Abyss</Link> (chaotic evil), <Link to="/rule/the_boneyard">the Boneyard</Link> (neutral), <Link to="/rule/elysium">Elysium</Link> (chaotic good), <Link to="/rule/heaven">Heaven</Link> (lawful good), the <Link to="/rule/maelstrom">Maelstrom</Link> (chaotic neutral), <Link to="/rule/nirvana">Nirvana</Link> (neutral good), or any other plane with those alignments.</p>
<p>If your alignment is neutral with no other alignment components, you can open soulgates with an alignment two steps away from your own, but you take a -10 penalty on attempts to do so.</p>
<p>Once opened, you can keep a soulgate open for a number of rounds equal to your Charisma modifier. An open soulgate closes at the end of that time, or you can close it earlier as a standard action.</p>
</>};
const _planar_survivor = {title: "Planar Survivor", jsx: <><h2 id="feat-planar_survivor-planar-survivor">Planar Survivor</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 31</Link></p>
<p>Your study of the nature and hazards of a diverse array of planes has prepared you for their dangers.<br/><strong>Prerequisites:</strong> Knowledge (planes) 3 ranks, Survival 3 ranks.<br/><strong>Benefit:</strong> You gain a +2 bonus on Survival checks on planes other than the Material Plane and a +2 bonus on saving throws against hazards encountered in such environments. If you have 10 or more ranks in Survival, the bonus on Survival checks increases to +4. This bonus does not stack with the bonus granted by the <Link to="/feat/self_sufficient">Self-Sufficient</Link> feat.</p>
</>};
const _planar_traveler = {title: "Planar Traveler", jsx: <><h2 id="feat-planar_traveler-planar-traveler-story">Planar Traveler (Story)</h2>
<p><strong>Sources</strong> <Link to="/source/quests_and_campaigns">Quests and Campaigns pg. 12</Link></p>
<p>The confines of the Material Plane cannot sate your wanderlust, and you walk between alternate spheres of reality unhindered.<br/><strong>Prerequisites:</strong> You must be related to an outsider or have been born on a plane other than the Material Plane.<br/><strong>Benefit:</strong> You gain a +2 bonus on Survival checks when outside your home plane. You can identify <Link to="/rule/planar_travel">portals and other planar connections</Link> as well as where they lead by sight or touch with a successful DC 20 Perception check.<br/><strong>Goal:</strong> Spend at least 24 consecutive hours on three different planes of existence other than your home plane or more than a month on a single plane other than your home plane. Demiplanes do not count for the purposes of fulfilling this goal.<br/><strong>Completion Benefit:</strong> Whenever you cast a spell or use a magic item to travel to another plane, you always arrive exactly where you had intended. In addition, when identifying portals with the first benefit of this feat, you gain a glimpse of what you would see, hear, and smell upon arriving on the other end of the portal.</p>
<p><em>Suggested Traits:</em> <Link to="/trait/fey_protection">Fey Protection</Link>, <Link to="/trait/scholar_of_the_great_beyond">Scholar of the Great Beyond</Link>, <Link to="/trait/wanderlust">Wanderlust</Link>.</p>
<h3 id="feat-planar_traveler-possible-planar-traveler-quests">Possible Planar Traveler Quests</h3>
<ScrollContainer id="feat-planar_traveler--table-0"><table>
<thead>
<tr>
<th>d8</th>
<th>Quest</th>
</tr>
</thead>
<tbody><tr>
<td>1</td>
<td>Your morbid curiosity urges you to journey through the Worldwound, either to contact or combat what impossible fiendish entities no doubt lurk beyond.</td>
</tr>
<tr>
<td>2</td>
<td>Several weak points exist between the forested realms of the River Kingdoms and the plane known as <Link to="/rule/the_first_world">the First World</Link>. You seek to learn the mysteries of that realm's strange fey inhabitants.</td>
</tr>
<tr>
<td>3</td>
<td>Ancient relics imply connections between the fallen Empire of Thassilon and the nightmare realm of <Link to="/rule/leng">Leng</Link>.</td>
</tr>
<tr>
<td>4</td>
<td>The wealth of mortal cities pales in comparison to that of the fabled City of Brass on the <Link to="/rule/plane_of_fire">Plane of Fire</Link>. You intend to seize at least a part of the metropolis's incredible wealth for yourself.</td>
</tr>
<tr>
<td>5</td>
<td>You have always been fascinated by death. Now, you wish to travel to its kingdom, <Link to="/rule/the_boneyard">the Boneyard</Link>, in life, either to rescue another soul from an uncertain fate or to learn of your own destiny.</td>
</tr>
<tr>
<td>6</td>
<td>You have resolved to reach <Link to="/rule/hell">Hell's</Link> vast fortress-capital Dis, where the magical treasures of Hell are available for a price.</td>
</tr>
<tr>
<td>7</td>
<td>In <Link to="/rule/axis">Axis</Link>, the city of perfect order, you hope to scale the crystal spires where the laws of reality are carved so that you might understand or, perhaps, change them.</td>
</tr>
<tr>
<td>8</td>
<td>The <Link to="/rule/eleven_minor_demiplanes">Immortal Ambulatory</Link> drifts among countless planes, allowing those who can reach the demiplane to visit many other realities. Perhaps by going there you can resolve long-unanswered questions regarding dragons and the nature of the multiverse.</td>
</tr>
</tbody></table></ScrollContainer>
</>};
const _planar_wanderer = {title: "Planar Wanderer", jsx: <><h2 id="feat-planar_wanderer-planar-wanderer">Planar Wanderer</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 88</Link></p>
<p>Your knowledge of the planes and teleportation allows you to travel with more precision.<br/><strong>Prerequisites:</strong> <Link to="/feat/cartogramancer">Cartogramancer</Link>, Knowledge (geography) 10 ranks, Knowledge (planes) 10 ranks, ability to cast <Link to="/spell/greater_teleport">greater teleport</Link> and <Link to="/spell/plane_shift">plane shift</Link>.<br/><strong>Benefit:</strong> When researching a plane to which you intend to <em>plane shift,</em> you can attempt a DC 25 Knowledge (planes) check as you cast the spell. If you succeed at the check, you're able to more precisely target your planar transport, allowing you to arrive 5d20 miles away from your intended destination instead of 5d% miles away. If you exceed the DC by 10 or more, you arrive 5d10 miles away instead, and if you exceed the DC by 20 or more, you arrive 5d6 miles away.</p>
</>};
const _planar_wild_shape = {title: "Planar Wild Shape", jsx: <><h2 id="feat-planar_wild_shape-planar-wild-shape">Planar Wild Shape</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 113</Link></p>
<p>You can infuse your wild shape with planar strength.<br/><strong>Prerequisites:</strong> Wild shape class feature, Knowledge (planes) 5 ranks.<br/><strong>Benefit:</strong> When you use wild shape to take the form of an animal, you can expend an additional daily use of your wild shape class feature to add the <Link to="/template/celestial">celestial</Link> template or <Link to="/template/fiendish">fiendish</Link> template to your animal form. (Good druids must use the celestial template, while evil druids must use the fiendish template.) If your form has the celestial template and you score a critical threat against an evil creature while using your form's natural weapons, you gain a +2 bonus on the attack roll to confirm the critical hit. The same bonus applies if your form has the fiendish template and you score a critical threat against a good creature.</p>
</>};
const _planewalkers_insight = {title: "Planewalker's Insight", jsx: <><h2 id="feat-planewalkers_insight-planewalkers-insight">Planewalker's Insight</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 31</Link></p>
<p>You are well versed in the lore of the planes and the psychology of their natives.<br/><strong>Benefit:</strong> You gain a +2 bonus on Knowledge (planes) checks and on Sense Motive checks against outsiders, and Knowledge (planes) is a class skill for you. If you have 10 or more ranks in either of these skills, the bonus for that skill increases to +4. These bonuses do not stack with those granted by the <Link to="/feat/alertness">Alertness</Link> or <Link to="/feat/scholar">Scholar</Link> feats.</p>
</>};
const _planned_spontaneity = {title: "Planned Spontaneity", jsx: <><h2 id="feat-planned_spontaneity-planned-spontaneity">Planned Spontaneity</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_society_primer">Pathfinder Society Primer pg. 13</Link></p>
<p>You have a measure of flexibility when preparing spells.<br/><strong>Prerequisites:</strong> Knowledge (arcana) 9 ranks, ability to prepare and cast 4th-level spells.<br/><strong>Benefit:</strong> Once per day when you prepare spells, you can designate one spell slot from each of up to three different spell levels that are lower than the highest-level spell that you can cast. In each designated slot you can memorize two different spells of the respective level. You can cast either spell as normal, but when you do, the spell consumes both of the spells prepared in that spell slot.<br/><strong>Special:</strong> A wizard can select this feat as one of his bonus feats.</p>
</>};
const _play_to_the_crowd = {title: "Play to the Crowd", jsx: <><h2 id="feat-play_to_the_crowd-play-to-the-crowd">Play to the Crowd</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 88</Link></p>
<p>You can glean the interests of others and use that information to strengthen your rhetoric.<br/><strong>Prerequisites:</strong> Int 19, <Link to="/feat/ironclad_logic">Ironclad Logic</Link>, Diplomacy 5 ranks, Sense Motive 5 ranks.<br/><strong>Benefit:</strong> When you use Diplomacy to change the attitude of a character, you can first attempt a Sense Motive check against that NPC to get a hunch to determine whether the character is under the influence of an enchantment, to use <Link to="/feat/sense_assumptions">Sense Assumptions</Link>, or to determine biases for a <Link to="/rule/verbal_duels">verbal duel</Link>. If you succeed at the Sense Motive check, you gain a +2 bonus on the Diplomacy check, and if you learned any biases for a verbal duel, you learn one additional bias of your choice. You do not worsen an NPC's attitude if you fail a Diplomacy check by 5 or more.</p>
</>};
const _point_blank_master = {title: "Point-Blank Master", jsx: <><h2 id="feat-point_blank_master-point-blank-master-combat">Point-Blank Master (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 167</Link></p>
<p>You are adept at firing ranged weapons in close quarters.<br/><strong>Prerequisites:</strong> <Link to="/feat/weapon_specialization">Weapon Specialization</Link> with selected ranged weapon.<br/><strong>Benefit:</strong> Choose one type of ranged weapon. You do not provoke attacks of opportunity when firing the selected weapon while threatened.<br/><strong>Normal:</strong> Using a ranged weapon while you are threatened provokes attacks of opportunity.<br/><strong>Special:</strong> Starting at 6th level, a ranger with the archery <Link to="/ability/combat_styles">combat style</Link> may select Point Blank Master as a combat style feat, but he must have <Link to="/feat/weapon_focus">Weapon Focus</Link> instead of Weapon Specialization in the selected weapon.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-point_blank_master--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-point_blank_master-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 129</Link><br/>When firing any type of ranged weapon, throwing a weapon, or making a ranged touch attack, you can spend 2 stamina points to avoid provoking an attack of opportunity.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional elephant"><ScrollContainer id="feat-point_blank_master--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/the_elephant_in_the_room"><IonIcon aria-label="The Elephant in the Room" icon="/icons/elephant.svg" /></ThLink><td><p><strong>Sources</strong> <Link to="/source/the_elephant_in_the_room_feat_taxes_in_pathfinder">The Elephant in the Room: Feat Taxes in Pathfinder</Link><br/>You are adept at firing ranged weapons in close quarters.<br/><strong>Prerequisites:</strong> <Link to="/feat/weapon_specialization">Weapon Specialization</Link> with selected weapon group.<br/><strong>Benefit:</strong> Choose the bows, crossbows, or thrown <Link to="/ability/weapon_groups">group</Link> listed under the fighter's Weapon Training class feature. You do not provoke attacks of opportunity when firing the selected weapon while threatened.<br/><strong>Normal:</strong> Using a ranged weapon while you are threatened provokes attacks of opportunity.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _point_blank_shot = {title: "Point-Blank Shot", jsx: <><h2 id="feat-point_blank_shot-point-blank-shot-combat">Point-Blank Shot (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 131</Link></p>
<p>You are especially accurate when making ranged attacks against close targets.<br/><strong>Benefit:</strong> You get a +1 bonus on attack and damage rolls with ranged weapons at ranges of up to 30 feet.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-point_blank_shot--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-point_blank_shot-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 129</Link><br/>You can spend up to 6 stamina points to increase this feat's range by 5 feet for each stamina point you spent.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional mythic"><ScrollContainer id="feat-point_blank_shot--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Point-Blank Shot</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 71</Link><br/>Your accuracy with ranged attacks is unmatched at pointblank range.<br/><strong>Prerequisites:</strong> Point-Blank Shot.<br/><strong>Benefit:</strong> The bonus on attack and damage rolls granted by Point-Blank Shot increases to +2. As a swift action, you can expend one use of mythic power to gain an additional bonus on these rolls equal to half your tier.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional elephant"><ScrollContainer id="feat-point_blank_shot--table-2"><table><tbody><tr><ThLink scope="row" to="/rule/the_elephant_in_the_room"><IonIcon aria-label="The Elephant in the Room" icon="/icons/elephant.svg" /></ThLink><td><p><strong>Sources</strong> <Link to="/source/the_elephant_in_the_room_feat_taxes_in_pathfinder">The Elephant in the Room: Feat Taxes in Pathfinder</Link><br/>You are especially accurate when making ranged attacks against close targets.<br/><strong>Prerequisites:</strong> <Link to="/feat/precise_shot">Precise Shot</Link>.<br/><strong>Benefit:</strong> You get a +1 bonus on attack and damage rolls with ranged weapons at ranges of up to 30 feet.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _poised_bearing = {title: "Poised Bearing", jsx: <><h2 id="feat-poised_bearing-poised-bearing-armor-mastery-combat">Poised Bearing (Armor Mastery, Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 17</Link></p>
<p>Your armor's weight gives you stable footing.<br/><strong>Prerequisites:</strong> Base attack bonus +6 or fighter level 4th, armor training class feature, proficiency with medium or heavy armor.<br/><strong>Benefit:</strong> You treat your size as one category larger for the purposes of determining the size of creatures against which you can attempt <Link to="/rule/bull_rush">bull rush</Link>, <Link to="/rule/drag">drag</Link>, <Link to="/rule/overrun">overrun</Link>, and <Link to="/rule/trip">trip</Link> combat maneuvers.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-poised_bearing--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-poised_bearing-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 21</Link><br/>You can spend 3 stamina points as a swift action to have this feat's effect on your size for the purposes of specific combat maneuvers also determine what size a creature must be to perform the combat maneuvers against you.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _poison_focus = {title: "Poison Focus", jsx: <><h2 id="feat-poison_focus-poison-focus">Poison Focus</h2>
<p><strong>Sources</strong> <Link to="/source/alchemy_manual">Alchemy Manual pg. 8</Link></p>
<p>You know the secrets of creating especially vicious poisons.<br/><strong>Prerequisites:</strong> Craft (alchemy) 1 rank.<br/><strong>Benefit:</strong> The save DC of any poison you craft with Craft (alchemy) and any spells you cast with the poison descriptor increases by 1. This bonus doesn't stack with the bonus granted by <Link to="/feat/spell_focus">Spell Focus</Link>.</p>
</>};
const _poison_resin = {title: "Poison Resin", jsx: <><h2 id="feat-poison_resin-poison-resin">Poison Resin</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 4</Link></p>
<p>The toxic slime from your skin hardens into a thick, venomous resin that you can craft into various shapes.<br/><strong>Prerequisites:</strong> <Link to="/race/grippli">Grippli</Link>, toxic skin alternate racial trait.<br/><strong>Benefit:</strong> As a standard action, you can spend a use of your toxic skin alternate racial trait to create any simple light weapon out of your hardened secretions. This weapon remains intact and usable for 1 hour. Once per minute when making an attack, you can treat this weapon as if you had applied your grippli racial poison to it. You can use this envenoming function a number of times per day equal to your Constitution modifier for any individual weapon created. Anyone other than you who attempts to wield the weapon is exposed to your poison.</p>
</>};
const _poison_shot_deed = {title: "Poison Shot Deed", jsx: <><h2 id="feat-poison_shot_deed-poison-shot-deed-grit">Poison Shot Deed (Grit)</h2>
<p><strong>Sources</strong> <Link to="/source/dirty_tactics_toolbox">Dirty Tactics Toolbox pg. 9</Link></p>
<p>You can specially prepare bullets to deliver poisons that are normally used more subtly.<br/><strong>Prerequisites:</strong> <Link to="/feat/amateur_gunslinger">Amateur Gunslinger</Link> or grit class feature.<br/><strong>Benefit:</strong> You can spend 1 grit point to load your firearm with 1 dose of inhaled or ingested poison as a move action. This action has no chance of exposing you to the poison (as if you had the <Link to="/ability/poison_use">poison use</Link> class feature). Shooting a firearm loaded with a poison in this manner is a standard action that provokes attacks of opportunity and sprays out the poison in a 15-foot cone. Any creatures caught in the blast take no damage but are exposed to this poison and must each immediately attempt a save against the poison as though the onset time had elapsed.</p>
</>};
const _poisoners_channel = {title: "Poisoner's Channel", jsx: <><h2 id="feat-poisoners_channel-poisoners-channel">Poisoner's Channel</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 215</Link></p>
<p>You cause anyone damaged by your negative energy to become susceptible to poison.<br/><strong>Prerequisites:</strong> <Link to="/ability/channel_energy">Channel energy</Link> 3d6, worshiper of <Link to="/faith/norgorber">Norgorber</Link>.<br/><strong>Benefit:</strong> Once per day when you channel negative energy to damage living creatures, you can cause any creatures that failed their save against your channel to take a -4 penalty on saving throws against poison effects. This penalty lasts for 1 minute.</p>
</>};
const _polyglot_familiar = {title: "Polyglot Familiar", jsx: <><h2 id="feat-polyglot_familiar-polyglot-familiar-familiar">Polyglot Familiar (Familiar)</h2>
<p><strong>Sources</strong> <Link to="/source/familiar_folio">Familiar Folio pg. 19</Link></p>
<p>Your familiar can speak with animals other than those of its own kind.<br/><strong>Prerequisites:</strong> Must have a familiar.<br/><strong>Benefit:</strong> Choose a category of creature: amphibians, birds, felines, invertebrates, reptiles, rodents, simians, or vermin. Your <Link to="/ability/familiar">familiar</Link> can speak with creatures of that kind.<br/><strong>Special:</strong> This feat can be taken multiple times, choosing a different category of creature each time. The first time you take this feat, if your familiar can't already speak with creatures of its kind, you must choose that category of creature. If your familiar later gains the ability to speak with creatures of its kind, you can choose to apply this feat's benefits to a different category of creature instead.</p>
</>};
const _polytheistic_blessing = {title: "Polytheistic Blessing", jsx: <><h2 id="feat-polytheistic_blessing-polytheistic-blessing">Polytheistic Blessing</h2>
<p><strong>Sources</strong> <Link to="/source/tombs_of_golarion">Tombs of Golarion pg. 63</Link>, <Link to="/source/faiths_and_philosophies">Faiths and Philosophies pg. 21</Link></p>
<p>You are granted a small bit of divine power as a result of your veneration of a pantheon of deities.<br/><strong>Prerequisites:</strong> Wis 13, must worship a pantheon.<br/><strong>Benefit:</strong> When you take this feat, select a pantheon from the list below. You gain the listed spell-like ability for your selected pantheon, usable once per day. If the granted spell allows a saving throw, the DC is equal to 10 + 1/2 your character level + your Charisma modifier.<br/><strong>Special:</strong> If you act out of line with the tenets of your pantheon's beliefs, you lose the ability to cast the granted spell-like ability until you have received an <Link to="/spell/atonement">atonement</Link> for your transgression (as a <Link to="/class/cleric">cleric</Link> attempting to regain lost class abilities).</p>
<h3 id="feat-polytheistic_blessing-juju-pantheon-cultural">Juju Pantheon (Cultural)</h3>
<p><strong>Deities</strong> wendo (supernatural entities of the spirit world)</p>
<p><strong>Common Believers</strong> juju practitioners, wendifa</p>
<p><strong>Granted Spell-like Ability</strong> <Link to="/spell/speak_with_animals">speak with animals</Link></p>
<h3 id="feat-polytheistic_blessing-sar-gorog-pantheon-aligned-and-cultural">Sar-Gorog Pantheon (Aligned and Cultural)</h3>
<p><strong>Deities</strong> <Link to="/faith/urgathoa">Urgathoa</Link> (NE), <Link to="/faith/rovagug">Rovagug</Link> (CE), and <Link to="/faith/zura">Zura</Link> (CE)</p>
<p><strong>Common Believers</strong> Koboto cannibal tribes of the Sodden Lands</p>
<p><strong>Granted Spell-like Ability</strong> <Link to="/spell/decompose_corpse">decompose corpse</Link>; if you use this ability on a corpse rather than on a corporeal undead, you receive nourishment as though you had eaten a normal meal for a Medium creature.</p>
<p><strong>Note:</strong> This feat was originally titled <em>Pantheistic Blessing.</em></p>
</>};
const _pommel_strike_deed = {title: "Pommel Strike Deed", jsx: <><h2 id="feat-pommel_strike_deed-pommel-strike-deed-panache">Pommel Strike Deed (Panache)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 153</Link></p>
<p>With a surprise swipe with your pommel, you can topple a foe.<br/><strong>Prerequisites:</strong> <Link to="/feat/amateur_swashbuckler">Amateur Swashbuckler</Link> or panache class feature; base attack bonus +3.<br/><strong>Benefit:</strong> You can spend 1 panache point to make a melee attack with the pommel of a light or one-handed piercing melee weapon as a standard action. You make this attack as if you were using the weapon normally (including any bonuses gained from the <em>swashbuckler finesse</em> class feature, <Link to="/feat/weapon_finesse">Weapon Finesse</Link>, or other similar feats and effects), but you deal 1d6 bludgeoning damage (or 1d4 if you are Small) instead of the weapon's normal damage. Regardless of your size, the critical threat range and critical multiplier of this attack are 20/&times;2, and they are not affected by <Link to="/feat/improved_critical">Improved Critical</Link>, the <Link to="/magic-enh/keen">keen</Link> weapon special ability, or similar effects. If the attack hits, you can attempt a combat maneuver check to knock the target <Link to="/rule/prone">prone</Link> as a free action.</p>
</>};
const _poppet_familiar = {title: "Poppet Familiar", jsx: <><h2 id="feat-poppet_familiar-poppet-familiar">Poppet Familiar</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 31</Link></p>
<p>You may select a poppet as your familiar.<br/><strong>Prerequisites:</strong> Ability to acquire a new familiar, caster level 3rd.<br/><strong>Benefit:</strong> You can choose a standard <Link to="/monster/tiny_poppet">Tiny poppet</Link> that you control as your <Link to="/ability/familiar">familiar</Link>. This poppet cannot have any existing augmentations. You absorb the poppet's token harmlessly into your body, making it impossible for you to transfer control of the poppet thereafter. A poppet familiar uses the rules for regular <Link to="/sidekick/familiar">familiars</Link>, with the following exceptions: its type does not change, and it does not gain the ability to speak with others of its kind. The poppet's Wisdom score increases to match its Intelligence score and it can speak and understand one language chosen by you at the time you select the poppet as your familiar. A poppet familiar has Craft, Perception, Profession, and Stealth as class skills. A poppet familiar cannot receive augmentations from crafting, but its connection to you allows it to spontaneously generate augmentations of your choice as you increase in level.</p>
<p>If your caster level is 5th or higher, your poppet familiar either becomes Small in size or gains two augmentations of your choice. You do not need to meet the requirements (or pay the construction cost) to craft these augmentations. At caster level 7th, and every 2 caster levels thereafter, your poppet familiar gains an additional augmentation of your choice.</p>
<p>If your caster level is 7th or higher, your poppet familiar gains the ability to generate spray of splinters as a breath weapon that deals 1d6 points of piercing damage in a 15-foot cone. At caster level 9th and every 2 caster levels thereafter, the damage increases by 1d6 (to a maximum of 7d6 at 19th level). A poppet can use this breath weapon three times per day.</p>
<p>If your poppet familiar is lost or destroyed, you can replace it with another standard Tiny poppet that you control by undertaking a ritual that takes 8 hours to complete. If your previous poppet familiar was Small or had gained augmentations, you can choose different augmentations for your new poppet familiar.</p>
</>};
const _porcupine_defense = {title: "Porcupine Defense", jsx: <><h2 id="feat-porcupine_defense-porcupine-defense-combat">Porcupine Defense (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/dragonslayers_handbook">Dragonslayer's Handbook pg. 25</Link></p>
<p>You are a threat to opponents that try to overwhelm you.<br/><strong>Prerequisites:</strong> <Link to="/feat/combat_expertise">Combat Expertise</Link>, <Link to="/feat/combat_reflexes">Combat Reflexes</Link>, base attack bonus +6.<br/><strong>Benefit:</strong> Whenever an opponent of at least one size category larger than yourself attempts a combat maneuver attack against you, you gain a +2 bonus on any allowed attacks of opportunity. If your opponent may make such attacks without provoking attacks of opportunity, you instead gain a +2 bonus to CMD against such maneuvers.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-porcupine_defense--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-porcupine_defense-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 21</Link><br/>You can spend 5 stamina points to make an attack of opportunity against an opponent at least one size category larger than you if that opponent attempts a combat maneuver check against you. You can perform this attack of opportunity even if your opponent can attempt such combat maneuvers without normally provoking attacks of opportunity.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _position_of_strength = {title: "Position of Strength", jsx: <><h2 id="feat-position_of_strength-position-of-strength-combat">Position of Strength (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 188</Link></p>
<p>You know how to press your advantage when negotiating with noncombatants.<br/><strong>Prerequisites:</strong> Intimidate 5 ranks.<br/><strong>Benefit:</strong> As long as you are wielding one or more weapons with which you are proficient, you gain a +4 bonus on Intimidate checks against unarmed creatures, which doesn't stack with <Link to="/feat/intimidating_prowess">Intimidating Prowess</Link>. Additionally, if you successfully use Intimidate to demoralize an unarmed creature, that creature becomes <Link to="/misc/shaken">shaken</Link> for as long as you continue to be armed and they continue not to be, to a maximum of 1 minute. Creatures with natural attacks, or whose unarmed strikes deal lethal damage, are considered to be armed for the purposes of this feat.</p>
</>};
const _possess_creature = {title: "Possess Creature", jsx: <><h2 id="feat-possess_creature-possess-creature-monster">Possess Creature (Monster)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_28_the_infernal_syndrome">Pathfinder #28: The Infernal Syndrome pg. 57</Link></p>
<p>A fiend gains the ability to merge its physical form with another creature's body, spreading its foul influence from within a living vessel.<br/><strong>Prerequisites:</strong> Cha 20, any evil outsider with 10 or more Hit Dice.<br/><strong>Benefit:</strong> Once per day, as a full-round action, a fiend can discorporate into a malign presence and target a creature within 15 feet. The creature targeted must succeed at a Will save equal to 10 + half the fiend's Hit Dice + the fiend's Charisma modifier or be possessed (see below). Targets under the effects of <Link to="/spell/protection_from_evil">protection from evil</Link>, or related spells, gain a bonus to this save. Should a target succeed at its Will save, the fiend is forced back into its natural form and is stunned for 1 round.</p>
<p>A fiend that successfully possesses a target enters its space and merges with it. While possessing a creature or object, a fiend's body and abilities are unavailable. Once a fiend merges with its target it cannot be harmed until it leaves or is forcibly removed. While possessing a target, a fiend shares the senses of its host and can communicate with it telepathically. A fiend also gains a number of possession points per day equal to its total Hit Dice. These points can be spent to utilize special bodily <Link to="/rule/possession_actions">possession actions</Link>. A fiend may expend these points as it pleases, with each possession action taking a full-round action.</p>
<p>Each day, the victim of a possession is allowed a new Will save at the original DC to force the possessing fiend to leave its body - objects and areas do not receive daily saves. Should a victim make this save or be killed, the fiend is ejected, retakes its original form in an adjacent space, and is <Link to="/misc/stunned">stunned</Link> for 1 round. A fiend may not possess a new target for 24 hours after being ejected from a victim. <Link to="/spell/dispel_evil">Dispel evil</Link> (or <Link to="/spell/dispel_chaos">dispel chaos</Link> or <Link to="/spell/dispel_law">dispel law</Link>, depending on the fiend) can eject a fiend, but the caster must succeed at a caster level check with a DC equal to 10 + the HD of the possessing fiend + the fiend's Cha modifier. <Link to="/spell/banishment">Banishment</Link> and <Link to="/spell/dismissal">dismissal</Link> immediately eject a fiend from a target if it fails to save against the spell.</p>
</>};
const _possess_location = {title: "Possess Location", jsx: <><h2 id="feat-possess_location-possess-location-monster">Possess Location (Monster)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_28_the_infernal_syndrome">Pathfinder #28: The Infernal Syndrome pg. 57</Link></p>
<p>A fiend learns to disperse its essence over an area, gaining mastery over features and structures there and tainting the place with its wickedness.<br/><strong>Prerequisites:</strong> Cha 16, any evil outsider with 8 or more Hit Dice.</p>
<p>Once per day, as a full-round action, a fiend may attempt to possess a structure or small area (like a pool, grove, or ruin) of a diameter equal to 10 feet per Hit Die. This area is spherical, so a fiend possessing a particularly large structure might only have power over a certain number of rooms. An area receives no save against fiendish possession unless creatures or magical items occupy the space, in which case the area makes a Will save equal to 10 + half the fiend's Hit Dice + the fiend's Charisma modifier using the stats of the occupant with the highest Will save. An area within the effects of a <Link to="/spell/hallow">hallow</Link> spell cannot be possessed. A fiend possessing an area operates similarly to one using the <Link to="/feat/possess_creature">Possess Creature</Link> feat, but can only be spent on location <Link to="/rule/possession_actions">possession actions</Link>.</p>
<p>Should a possessed location be destroyed, the fiend is ejected, retakes its original form in a space adjacent to the area it previously possessed, and is <Link to="/misc/stunned">stunned</Link> for 1 round. <Link to="/spell/dispel_evil">Dispel evil</Link> (or <Link to="/spell/dispel_chaos">dispel chaos</Link> or <Link to="/spell/dispel_law">dispel law</Link>, depending on the fiend) can eject a fiend, but the caster must succeed at a caster level check with a DC equal to 10 + the HD of the possessing fiend + the fiend's Cha modifier. <Link to="/spell/banishment">Banishment</Link> and <Link to="/spell/dismissal">dismissal</Link> immediately eject a fiend from an object if it fails to make its saving throw against the spell's effects.</p>
</>};
const _possess_object = {title: "Possess Object", jsx: <><h2 id="feat-possess_object-possess-object-monster">Possess Object (Monster)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_28_the_infernal_syndrome">Pathfinder #28: The Infernal Syndrome pg. 58</Link></p>
<p>A fiend gains the power to bind its malign essence to a single object, corrupting it into a relic of undeniable evil.<br/><strong>Prerequisites:</strong> Cha 18, any evil outsider with 9 or more Hit Dice.</p>
<p>Once per day, as a full-round action, a fiend can possess a Large or smaller object. Unattended, a mundane object receives no saving throw against possession, while an attended object uses its owner's saving throw to make a Will save equal to 10 + half the fiend's Hit Dice + the fiend's Charisma modifier. Magic items save as if they were subject to a spell. Items within the area of effect of a <Link to="/spell/hallow">hallow</Link> spell cannot be possessed. This effect is similar to that detailed in the <Link to="/feat/possess_creature">Possess Creature</Link> feat, but can only be spent on object <Link to="/rule/possession_actions">possession actions</Link>.</p>
<p>Should a possessed object be destroyed, the fiend is ejected, retakes its original form in an adjacent space, and is stunned for 1 round. <Link to="/spell/dispel_evil">Dispel evil</Link> (or <Link to="/spell/dispel_chaos">dispel chaos</Link> or <Link to="/spell/dispel_law">dispel law</Link>, depending on the fiend) can eject a fiend, but the caster must succeed at a caster level check with a DC equal to 10 + the HD of the possessing fiend + the fiend's Cha modifier. <Link to="/spell/banishment">Banishment</Link> and <Link to="/spell/dismissal">dismissal</Link> immediately eject a fiend from an object if it fails to make its saving throw against the spell's effects.</p>
</>};
const _possessed_hand = {title: "Possessed Hand", jsx: <><h2 id="feat-possessed_hand-possessed-hand">Possessed Hand</h2>
<p><strong>Sources</strong> <Link to="/source/haunted_heroes_handbook">Haunted Heroes Handbook pg. 25</Link></p>
<p>You've made a peaceful and permanent bargain with a ghost, spirit, or outsider. It possesses your hand, guiding and aiding you in exchange for help in return.<br/><strong>Benefit:</strong> You attract a ghost, spirit, or outsider with personal motivations to possess your hand. This usually involves some sort of mutually beneficial pact or agreement. Your possessed hand helps you in numerous ways, but its periodic, uncontrolled antics are distracting; you take a permanent -2 penalty on <Link to="/rule/concentration">concentration</Link> checks once you gain this feat.</p>
<p>Any attack you make with a one-handed weapon, light weapon, unarmed strike, or natural attack with your possessed hand gains a +1 insight bonus on the attack roll and damage roll. You also gain a +1 insight bonus on Disable Device and Sleight of Hand checks. Once per day as a swift action, you can retrieve any stowed object you carry on your person, provided the object weighs no more than 5 pounds.</p>
</>};
const _potent_holy_symbol = {title: "Potent Holy Symbol", jsx: <><h2 id="feat-potent_holy_symbol-potent-holy-symbol">Potent Holy Symbol</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_night">Blood of the Night pg. 28</Link></p>
<p>In your pious hands, your holy symbol is a shining light of faith.<br/><strong>Prerequisites:</strong> Good alignment, worshiper of a good deity.<br/><strong>Benefit:</strong> Any round in which you use your holy symbol as a divine focus for the casting of a spell or to <Link to="/ability/channel_positive_energy">channel positive energy</Link>, you count as presenting a holy symbol, chanting prayers, or ringing a hand bell for the purpose of keeping <Link to="/template/vampire">vampires</Link> at bay.</p>
</>};
const _potent_surge = {title: "Potent Surge", jsx: <><h2 id="feat-potent_surge-potent-surge-mythic">Potent Surge (Mythic)</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 71</Link></p>
<p>Your surge is more potent.<br/><strong>Benefit:</strong> Whenever you use your surge ability, add 1 to your surge result.</p>
</>};
const _potion_glutton = {title: "Potion Glutton", jsx: <><h2 id="feat-potion_glutton-potion-glutton">Potion Glutton</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 215</Link></p>
<p>You gulp down potions with unsettling speed.<br/><strong>Prerequisites:</strong> Worshiper of <Link to="/faith/urgathoa">Urgathoa</Link>.<br/><strong>Benefit:</strong> You can drink potions, elixirs, or other potables (but not extracts) as a move action without provoking an attack of opportunity.<br/><strong>Normal:</strong> Drinking potions is a standard action that provokes an attack of opportunity.</p>
</>};
const _power_attack = {title: "Power Attack", jsx: <><h2 id="feat-power_attack-power-attack-combat">Power Attack (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 131</Link></p>
<p>You can make exceptionally deadly melee attacks by sacrificing accuracy for strength.<br/><strong>Prerequisites:</strong> Str 13, base attack bonus +1.<br/><strong>Benefit:</strong> You can choose to take a -1 penalty on all melee attack rolls and combat maneuver checks to gain a +2 bonus on all melee damage rolls. This bonus to damage is increased by half (+50%) if you are making an attack with a two-handed weapon, a one handed weapon using two hands, or a primary natural weapon that adds 1-1/2 times your Strength modifier on damage rolls. This bonus to damage is halved (-50%) if you are making an attack with an off-hand weapon or secondary natural weapon. When your base attack bonus reaches +4, and every 4 points thereafter, the penalty increases by -1 and the bonus to damage increases by +2. You must choose to use this feat before making an attack roll, and its effects last until your next turn. The bonus damage does not apply to touch attacks or effects that do not deal hit point damage.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-power_attack--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-power_attack-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 129</Link><br/>When using this feat, you can spend 2 stamina points to gain the benefits and the hindrances of that feat until the end of your turn, instead of until your next turn.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional mythic"><ScrollContainer id="feat-power_attack--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Power Attack</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 71</Link><br/>Your attacks are truly devastating.<br/><strong>Prerequisites:</strong> Power Attack.<br/><strong>Benefit:</strong> When you use Power Attack, you gain a +3 bonus on melee damage rolls instead of +2. When your base attack bonus reaches +4 and every 4 points thereafter, the amount of bonus damage increases by +3 instead of +2. In addition, the bonus damage from this feat is doubled on a critical hit, before it's multiplied by the weapon's critical multiplier.</p>
<p>You can expend one use of mythic power when you activate Power Attack to ignore the penalties on melee attack rolls and combat maneuver checks for 1 minute.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional elephant"><ScrollContainer id="feat-power_attack--table-2"><table><tbody><tr><ThLink scope="row" to="/rule/the_elephant_in_the_room"><IonIcon aria-label="The Elephant in the Room" icon="/icons/elephant.svg" /></ThLink><td><p><strong>Sources</strong> <Link to="/source/the_elephant_in_the_room_feat_taxes_in_pathfinder">The Elephant in the Room: Feat Taxes in Pathfinder</Link><br/>This feat has been removed, replaced with the <Link to="/rule/combat_errata">Risky Strike</Link> action.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _powerful_poisoning = {title: "Powerful Poisoning", jsx: <><h2 id="feat-powerful_poisoning-powerful-poisoning">Powerful Poisoning</h2>
<p><strong>Sources</strong> <Link to="/source/dirty_tactics_toolbox">Dirty Tactics Toolbox pg. 6</Link></p>
<p>You can make powerful attacks that place more of your weapon's poison into a target's wounds.<br/><strong>Prerequisites:</strong> <Link to="/feat/power_attack">Power Attack</Link>; Craft (poison) 3 ranks or <Link to="/ability/poison_use">poison use</Link> class feature.<br/><strong>Benefit:</strong> When you damage an opponent with a Power Attack while using a poisoned weapon, you can forgo the bonus damage from Power Attack to increase the save DC of the poison by 1. When your base attack bonus reaches +4, and every +4 thereafter, the bonus to the poison's save DC increases by an additional 1. This can't cause the save DC to exceed 15 + 1/2 your character level.</p>
</>};
const _powerful_shape = {title: "Powerful Shape", jsx: <><h2 id="feat-powerful_shape-powerful-shape">Powerful Shape</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 154</Link></p>
<p>Your wild shapes are mighty and muscular.<br/><strong>Prerequisites:</strong> Wild shape class feature, druid level 8th.<br/><strong>Benefit:</strong> When in wild shape, treat your size as one category larger for the purpose of calculating CMB, CMD, carrying capacity, and any size-based special attacks you use or that are used against you (such as <Link to="/umr/grab">grab</Link>, <Link to="/umr/swallow_whole">swallow whole</Link>, and <Link to="/umr/trample">trample</Link>).</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="feat-powerful_shape--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Powerful Shape</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 71</Link><br/>The forms you take in wild shape tower over their natural counterparts.<br/><strong>Prerequisites:</strong> Powerful Shape.<br/><strong>Benefit:</strong> You can apply the <Link to="/template/giant">giant</Link> simple template (quick rules version) to any form you take with wild shape. This replaces the benefit from Powerful Shape.</p>
<p>As a free action, you can expend one use of mythic power to combine the benefit from this feat with the benefit from non-mythic Powerful Shape for a number of rounds equal to your tier.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _powerful_tongue = {title: "Powerful Tongue", jsx: <><h2 id="feat-powerful_tongue-powerful-tongue">Powerful Tongue</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 8</Link></p>
<p>Unlike others of your kind, you are able to pull your prey toward yourself.<br/><strong>Prerequisites:</strong> Str 17, sticky tongue.<br/><strong>Benefit:</strong> Your tongue attack gains the <Link to="/umr/pull">pull</Link> special ability. At the start of your turn, if your tongue is attached to a target of your size or smaller and you succeed at a combat maneuver check, you can pull the target 5 feet closer to you as free action.</p>
</>};
const _powerful_wings = {title: "Powerful Wings", jsx: <><h2 id="feat-powerful_wings-powerful-wings-combat">Powerful Wings (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_monster_codex">Inner Sea Monster Codex pg. 53</Link></p>
<p>You have a large wingspan for a member of your race, and can use these appendages to batter your foes.<br/><strong>Prerequisites:</strong> Str 13, <Link to="/feat/skill_focus">Skill Focus</Link> (Fly), base attack bonus +8.<br/><strong>Benefit:</strong> You gain two wing attacks. These are secondary natural attacks that each deal damage appropriate to a creature one size category larger than yourself. You are also considered one size category larger for the purposes of any feats or abilities related to your wings, such as the <Link to="/feat/hover">Hover</Link> feat.<br/><strong>Special:</strong> While this feat is primarily taken by <Link to="/race/strix">strix</Link>, other creatures with natural wings can also take it at the GM's discretion.</p>
</>};
const _practical_kata = {title: "Practical Kata", jsx: <><h2 id="feat-practical_kata-practical-kata-combat-combination">Practical Kata (Combat, Combination)</h2>
<p><strong>Sources</strong> <Link to="/source/martial_arts_handbook">Martial Arts Handbook pg. 27</Link></p>
<p>Your martial meditation extends onto the battlefield.<br/><strong>Prerequisites:</strong> <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>, ki pool class feature.<br/><strong>Benefit:</strong> When you hit with a melee attack against an opponent you have already damaged this round, you can forgo dealing damage to instead regain 1 ki point. This feat can restore only 1 ki point every minute, to a maximum per day of 1 point for every 4 class levels you have.</p>
</>};
const _practiced_dreamer = {title: "Practiced Dreamer", jsx: <><h2 id="feat-practiced_dreamer-practiced-dreamer">Practiced Dreamer</h2>
<p><strong>Sources</strong> <Link to="/source/plane_hoppers_handbook">Plane-Hopper's Handbook pg. 30</Link></p>
<p>Your time in the <Link to="/rule/dimension_of_dreams">Dimension of Dreams</Link> has improved your ability to manipulate its landscape.<br/><strong>Prerequisites:</strong> Cha 15, <Link to="/feat/lucid_dreamer">Lucid Dreamer</Link>, Knowledge (planes) 5 ranks.<br/><strong>Benefit:</strong> Once per day, you can reroll a failed attempt to perform an impossible action, such as casting a spell you can't normally cast, gaining an effect of a spell as if it had been cast, or conjuring a magic item. You also gain an additional +2 bonus on Charisma checks to determine your initial condition when entering a dream with your lucid body.</p>
</>};
const _practiced_leadership = {title: "Practiced Leadership", jsx: <><h2 id="feat-practiced_leadership-practiced-leadership">Practiced Leadership</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_balance">Champions of Balance pg. 15</Link></p>
<p>When you and your cohort are both members of the same organization, you needn't shoulder the burden of leadership alone. By relying on the authority of your shared organization as well as your own leadership skills, your cohort demonstrates improved devotion and tactical acumen.<br/><strong>Prerequisites:</strong> <Link to="/feat/leadership">Leadership</Link>, membership in the same organization as your cohort.<br/><strong>Benefit:</strong> As long as you and your cohort maintain membership in good standing within the same organization, your cohort gains a +4 morale bonus on Will saves against enchantment spells and effects. Additionally, your cohort is treated as though she possessed the same <Link to="/main/teamwork_feat">teamwork feats</Link> you do for the purpose of determining whether you receive a bonus from your teamwork feats. Your cohort doesn't receive any bonuses from these feats unless she actually possesses the feats.</p>
<p>If you and your cohort belong to one of the organizations listed below, your cohort gains the practiced leadership benefit associated with your organization. If a benefit grants your cohort access to a spell-like ability, the caster level of the effect is 1st or equal to your cohort's caster level, whichever is higher.</p>
<h3 id="feat-practiced_leadership-free-captains-cn">Free Captains (CN)</h3>
<p>Less a formal organization and more a loose network of affiliations and mutual obligations, the Free Captains are nonetheless the only authority in the Shackles region. The Free Captains jealously guard their freedom to do as they please and take what they want by guile or force, and rarely have room on their agendas for benevolence or malice. Above all else, the Free Captains respect bravado, daring, and the ability to navigate the Shackles' treacherous seas.</p>
<p>Cohorts of the Free Captains are usually fighters or rogues, and often take archetypes such as the <Link to="/arc-rogue/swashbuckler">swashbuckler</Link> or <Link to="/arc-rogue/pirate">pirate</Link>.</p>
<p><strong>Leadership Benefit:</strong> Free Captains do not take a Leadership score penalty for moving around a lot.</p>
<p><strong>Practiced Leadership Benefit:</strong> If you are a Free Captain with the Practiced Leadership feat, your cohort can use water walk or water breathing once per day as a spell-like ability.</p>
<h3 id="feat-practiced_leadership-green-faith-n">Green Faith (N)</h3>
<p>Druids, farmers, and peasants revere the <Link to="/faith/green_faith">Green Faith</Link> so they might connect to the primal power and endless cycles of the natural world. Many followers of the Green Faith preserve balance for its own sake, so that no philosophy reigns over others and despoils the natural order. Adherents to the Green Faith often live far from civilization, but when they do live in settlements, they encourage their communities to work in harmony with the natural order.</p>
<p>Cohorts of the Green Faith are almost always druids and may become <Link to="/pclass/green_faith_acolyte">Green Faith acolytes</Link>.</p>
<p><strong>Leadership Benefit:</strong> Members of the Green Faith do not take a Leadership score penalty for having an animal companion.</p>
<p><strong>Practiced Leadership Benefit:</strong> If you are a Green Faith follower with the Practiced Leadership feat, your cohort can use <Link to="/spell/speak_with_animals">speak with animals</Link> at will as a spell-like ability.</p>
<h3 id="feat-practiced_leadership-hellknights-ln">Hellknights (LN)</h3>
<p>Terrifying heralds of unrelenting order, the black-armored <Link to="/rule/hellknights">Hellknights</Link> perfect their fighting techniques by training with the militant legions of Hell. Although each of the Hellknight orders has its own particular focus, the order as a whole is committed to the rigid enforcement of law for its own sake, independent of morality and deaf to excuses or exceptions. The greatest Hellknights are as committed to mental exercise as they are to physical training, memorizing tomes of law in order to better mete out perfect justice.</p>
<p>Hellknight cohorts are usually fighters with levels in the <Link to="/pclass/hellknight">Hellknight</Link> prestige class, but some are spellcasters with levels in the <Link to="/pclass/hellknight_signifer">Hellknight signifer</Link> prestige class.</p>
<p><strong>Leadership Benefit:</strong> Hellknights do not take a Leadership score penalty for aloofness.</p>
<p><strong>Practiced Leadership Benefit:</strong> If you are a Hellknight with the Practiced Leadership feat, your cohort gains a +2 deflection bonus to AC against attacks from chaotic outsiders.</p>
<h3 id="feat-practiced_leadership-pathfinder-society-n">Pathfinder Society (N)</h3>
<p><Link to="/rule/pathfinders">Pathfinders</Link> are adventurous scholars who explore the most remote and dangerous corners of the world to find lost knowledge and hidden treasure. Most strive to have their exploits showcased in the pages of the Pathfinder Chronicles, where the most daring members find a sense of immortality in the written word. Although individual Pathfinders vary in alignment, the organization as a whole remains unconcerned with legal niceties or ethical constraints when it comes to recovering lost lore and ancient relics. The Society's leaders are likewise varied in their motives and approaches, but the highest-ranking Pathfinders are so resolute in their pursuit of lore and artifacts that they rarely brook any discussions of moral or ethical concerns.</p>
<p>Pathfinder cohorts can be of any class, but many are bards. At higher levels, they might become <Link to="/pclass/pathfinder_field_agent">Pathfinder field agents</Link>.</p>
<p><strong>Leadership Benefit:</strong> Pathfinders do not take a Leadership score penalty for moving around a lot.</p>
<p><strong>Practiced Leadership Benefit:</strong> If you are a Pathfinder with the Practiced Leadership feat, your cohort can use <Link to="/spell/identify">identify</Link> at will as a spell-like ability.</p>
<h3 id="feat-practiced_leadership-prophets-of-kalistrade-ln">Prophets of Kalistrade (LN)</h3>
<p>Followers of the secular <Link to="/rule/prophecies_of_kalistrade">Prophecies of Kalistrade</Link> amass wealth with a religious fervor. Adherents believe that they reap earthly riches by hewing to the byzantine strictures of their philosophy, and increased compliance leads to increased fortune. Moral considerations rarely impact their lives, as they consider the gods to be fallible and those devoted to the gods to be outmoded. As they must maintain rigorous ritual purity, followers of the Prophecies live structured, orderly lives.</p>
<p>A follower of the Prophecies of Kalistrade typically has either a fellow Kalistocrat or a member of Druma's infamous Mercenary League for a cohort. These "Blackjackets" are ruthless fighters and rogues who serve only to protect Druma's mercantile elite, and in return see their own fortunes rapidly swell.</p>
<p><strong>Leadership Benefit:</strong> Followers of the Prophecies of Kalistrade do not take a Leadership score penalty for recruiting a cohort of a different alignment if the cohort is also a follower of the Prophecies or a member of the Mercenary League.</p>
<p><strong>Practiced Leadership Benefit:</strong> If you are a follower of the Prophecies of Kalistrade with the Practiced Leadership feat and your cohort is a fellow Kalistocrat, once per day she can roll either an Appraise or Bluff check twice and take the higher result. If your cohort is instead a member of the Mercenary League, once per day she can roll either an Intimidate check or a Sense Motive check twice and take the higher result. Your cohort must announce the use of this ability before attempting the check.</p>
</>};
const _practiced_ritualist = {title: "Practiced Ritualist", jsx: <><h2 id="feat-practiced_ritualist-practiced-ritualist">Practiced Ritualist</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 5</Link></p>
<p>You are an experienced leader among ritual casters.<br/><strong>Prerequisites:</strong> Knowledge (arcana, history, planes, and religion) 1 rank.<br/><strong>Benefit:</strong> You gain a +2 bonus on skill checks to perform <Link to="/rule/occult_rituals">occult rituals</Link>, and on Intelligence checks to learn the method of casting an occult ritual. If you are a ritual's primary caster, the DC for saving throws against the ritual's effects is 2 higher. If the ritual has a minimum number of required secondary casters, that number is decreased by 1.</p>
</>};
const _practiced_tactician = {title: "Practiced Tactician", jsx: <><h2 id="feat-practiced_tactician-practiced-tactician">Practiced Tactician</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 167</Link></p>
<p>With only a few quick gestures and commands, you can direct others in combat.<br/><strong>Prerequisites:</strong> Tactician class feature.<br/><strong>Benefit:</strong> You can use your tactician ability to grant allies a teamwork feat one additional time per day.<br/><strong>Special:</strong> You can gain Practiced Tactician multiple times. Its effects stack.</p>
</>};
const _precipice_strike = {title: "Precipice Strike", jsx: <><h2 id="feat-precipice_strike-precipice-strike-combat">Precipice Strike (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe pg. 26</Link></p>
<p>Rough mountain roads are as smooth as cobblestone to you. Enemies challenge you in your home territory at their peril.<br/><strong>Prerequisites:</strong> Dex 15, base attack bonus +6, cragkin <Link to="/race/half_orc">half-orc</Link>.<br/><strong>Benefit:</strong> When you and the target of your attack are both in <Link to="/rule/difficult_terrain">difficult terrain</Link>, treat the target as if he were <Link to="/rule/flat_footed">flat-footed</Link>. In addition, if you attack a flat-footed enemy from a higher elevation (including while falling), you gain a +2 circumstance bonus on your attack roll.</p>
</>};
const _precise_shot = {title: "Precise Shot", jsx: <><h2 id="feat-precise_shot-precise-shot-combat">Precise Shot (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 131</Link></p>
<p>You are adept at firing ranged attacks into melee.<br/><strong>Prerequisites:</strong> <Link to="/feat/point_blank_shot">Point-Blank Shot</Link>.<br/><strong>Benefit:</strong> You can shoot or throw ranged weapons at an opponent engaged in melee without taking the standard -4 penalty on your attack roll.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-precise_shot--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-precise_shot-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 129</Link><br/>As a standard action, you can spend 2 stamina points and make a ranged attack against a foe engaged in melee with an ally. If the attack hits, it deals no damage, but your ally gains your choice of either a +2 bonus on her next attack roll against that opponent or a +2 bonus to AC against that opponent's next attack. This bonus lasts until the start of your next turn.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional elephant"><ScrollContainer id="feat-precise_shot--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/the_elephant_in_the_room"><IonIcon aria-label="The Elephant in the Room" icon="/icons/elephant.svg" /></ThLink><td><p><strong>Sources</strong> <Link to="/source/the_elephant_in_the_room_feat_taxes_in_pathfinder">The Elephant in the Room: Feat Taxes in Pathfinder</Link><br/>You are adept at firing ranged attacks into melee.<br/><strong>Benefit:</strong> You can shoot or throw ranged weapons at an opponent engaged in melee without taking the standard -4 penalty on your attack roll.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _precise_strike = {title: "Precise Strike", jsx: <><h2 id="feat-precise_strike-precise-strike-combat-teamwork">Precise Strike (Combat, Teamwork)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 167</Link></p>
<p>You are skilled at striking where it counts, as long as an ally distracts your foe.<br/><strong>Prerequisites:</strong> Dex 13, base attack bonus +1.<br/><strong>Benefit:</strong> Whenever you and an ally who also has this feat are <Link to="/rule/flanking">flanking</Link> the same the creature, you deal an additional 1d6 points of <Link to="/misc/precision_damage">precision damage</Link> with each successful melee attack. This bonus damage stacks with other sources of precision damage, such as <Link to="/ability/sneak_attack">sneak attack</Link>. This bonus damage is not multiplied on a critical hit.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-precise_strike--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-precise_strike-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 129</Link><br/>When dealing precision damage with this feat, you can spend 2 stamina points to increase that precision damage to 2d6.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _precocious_youth = {title: "Precocious Youth", jsx: <><h2 id="feat-precocious_youth-precocious-youth">Precocious Youth</h2>
<p><strong>Sources</strong> <Link to="/source/quests_and_campaigns">Quests and Campaigns pg. 27</Link></p>
<p>Even in youth, you seek to be more adult than your childish peers, a personal trait that will no doubt aid you in future years.<br/><strong>Prerequisites:</strong> Young age category.<br/><strong>Benefit:</strong> You lose one of the penalties associated with the <Link to="/rule/creating_young_characters">young age category</Link>, either -2 Constitution, -2 Strength, or -2 Wisdom. Upon reaching adulthood you may exchange this feat for <Link to="/feat/great_fortitude">Great Fortitude</Link>, <Link to="/feat/iron_will">Iron Will</Link>, or <Link to="/feat/lightning_reflexes">Lightning Reflexes</Link>.<br/><strong>Special:</strong> You may take this feat up to three times. Each time you do, it affects a different penalty and must be exchanged for a different feat upon reaching adulthood.</p>
</>};
const _preferred_spell = {title: "Preferred Spell", jsx: <><h2 id="feat-preferred_spell-preferred-spell">Preferred Spell</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 167</Link></p>
<p>You find it very easy to cast one particular spell.<br/><strong>Prerequisites:</strong> Spellcraft 5 ranks, <Link to="/feat/heighten_spell">Heighten Spell</Link>.<br/><strong>Benefit:</strong> Choose one spell which you have the ability to cast. You can cast that spell spontaneously by sacrificing a prepared spell or spell slot of equal or higher level. You can apply any metamagic feats you possess to this spell when you cast it. This increases the minimum level of the prepared spell or spell slot you must sacrifice in order to cast it but does not affect the casting time.<br/><strong>Special:</strong> You can gain this feat multiple times. Its effects do not stack. Each time you take the feat, it applies to a different spell.</p>
</>};
const _press_to_the_wall = {title: "Press to the Wall", jsx: <><h2 id="feat-press_to_the_wall-press-to-the-wall-combat">Press to the Wall (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 7</Link></p>
<p>You gain an advantage when your opponent can't easily retreat.<br/><strong>Prerequisites:</strong> <Link to="/feat/step_up">Step Up</Link>, base attack bonus +3.<br/><strong>Benefit:</strong> If you are the only character threatening an opponent, you can treat solid, immovable objects that occupy a square (such as columns, tree trunks, and walls) and are adjacent to that opponent as allies threatening the opponent when determining whether you <Link to="/rule/flank">flank</Link> the foe.</p>
</>};
const _pressure_adept = {title: "Pressure Adept", jsx: <><h2 id="feat-pressure_adept-pressure-adept">Pressure Adept</h2>
<p><strong>Sources</strong> <Link to="/source/aquatic_adventures">Aquatic Adventures pg. 58</Link></p>
<p>You've spent so much time at unusual pressures that You've extended your native range beyond the norms of your species.<br/><strong>Prerequisites:</strong> Swim 5 ranks.<br/><strong>Benefit:</strong> Add one <Link to="/rule/oceanic_zones">oceanic zone</Link> to your native range when calculating pressure (meaning that you don't take <Link to="/rule/pressure_damage">pressure damage</Link> in that range unless instantaneously transported up or down, and even then you adapt to the change all at once rather than 100 feet at a time). Surface-dwellers taking this feat must select the sunlight zone, and aquatic creatures can select any zone either directly above or directly below their native range.</p>
</>};
const _prestigious_spellcaster = {title: "Prestigious Spellcaster", jsx: <><h2 id="feat-prestigious_spellcaster-prestigious-spellcaster">Prestigious Spellcaster</h2>
<p><strong>Sources</strong> <Link to="/source/paths_of_the_righteous">Paths of the Righteous pg. 3</Link></p>
<p>The transition into a spellcasting prestige class is less difficult for you, and because of this, you gain 1 additional effective spellcaster level from your prestige class levels.<br/><strong>Prerequisites:</strong> <Link to="/feat/favored_prestige_class">Favored Prestige Class</Link> with selected prestige class.<br/><strong>Benefit:</strong> The first time you gain a level in your favored prestige class and the spells per day class feature does not grant an increase in effective level for the purpose of casting spells, you gain new spells per day as if the prestige class did grant +1 level of spellcasting for that level. This effect is retroactive if you gain this feat at a level beyond the point where your favored prestige class would normally have not advanced your spellcasting.</p>
<p>The Prestigious Spellcaster feat does not have any effect if your favored prestige class does not have the spells per day class feature, or if it does have the spells per day class feature but already grants a level increase for every level of the prestige class (as do the <Link to="/pclass/arcane_trickster">arcane trickster</Link> and <Link to="/pclass/loremaster">loremaster</Link> prestige classes).</p>
<p><strong>Special:</strong> You can select the Prestigious Spellcaster feat multiple times. Each time you select the Prestigious Spellcaster feat, your effective caster level increases by 1. However, regardless of the number of times you choose this feat, the total increase to your effective caster level cannot exceed your actual prestige class level.</p>
<p>This feat also applies to prestige classes that grant extracts per day instead of spells per day.</p>
</>};
const _primal_ancestry = {title: "Primal Ancestry", jsx: <><h2 id="feat-primal_ancestry-primal-ancestry">Primal Ancestry</h2>
<p><strong>Sources</strong> <Link to="/source/andoran_birthplace_of_freedom">Andoran, Birthplace of Freedom pg. 34</Link></p>
<p>You have a deep connection to the primal First World and can channel this link into powerful effects once a day.<br/><strong>Prerequisites:</strong> Wis 13, member of the Primordial Ones<br/><strong>Benefit:</strong> Once per day as a move action, you can tap into the essence of the First World, and gain DR 5/cold iron for 1 minute. If you have 11 or more Hit Dice, this increases to DR 10/cold iron. Additionally, while under this effect, enchantment spells you cast gain a +1 bonus to caster level.</p>
</>};
const _primal_bloom = {title: "Primal Bloom", jsx: <><h2 id="feat-primal_bloom-primal-bloom-conduit">Primal Bloom (Conduit)</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 31</Link></p>
<p>With a ferocious cry, you call to the First World to render magic unpredictable.<br/><strong>Prerequisites:</strong> Knowledge (planes) 10 ranks.<br/><strong>Benefit:</strong> As a standard action, you can create a 50-foot-radius spread of primal fey influence centered on yourself. This area is stationary and lasts for 1 minute. The affected area gains the wild magic <Link to="/rule/planar_traits">planar trait</Link>, except that the DC of the caster level check increases by 5. If the area already has the wild magic planar trait, the DC of the caster level check increases by 10 instead.</p>
<p>You can use this feat once per day, plus an additional time per day once you have 15 ranks in <Link to="/skill/knowledge_planes">Knowledge (planes)</Link> and three times per day once you have 20 ranks in Knowledge (planes).</p>
</>};
const _primal_kineticist = {title: "Primal Kineticist", jsx: <><h2 id="feat-primal_kineticist-primal-kineticist">Primal Kineticist</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_wastes">People of the Wastes pg. 6</Link></p>
<p>When primal magic surrounds you, you can channel it to transform the nature of your kinetic blasts.<br/><strong>Prerequisites:</strong> <Link to="/class/kineticist">Kineticist</Link> level 1st.<br/><strong>Benefit:</strong> When using a simple kinetic blast in an area where <Link to="/rule/primal_magic">primal magic</Link> is either predominant or very common, you can accept 1 point of burn to cause your blast to become one of the following simple blasts instead. Roll 1d10 on the table below to determine the simple blast. You can apply any of your form or substance infusions that are allowed as choices for the random blast, accepting the typical burn cost.</p>
<ScrollContainer id="feat-primal_kineticist--table-0"><table>
<thead>
<tr>
<th>1d10</th>
<th>Simple blast</th>
</tr>
</thead>
<tbody><tr>
<td>1</td>
<td className="ion-activatable"><Link to="/kinetic/air_blast">Air blast<IonRippleEffect /></Link></td>
</tr>
<tr>
<td>2</td>
<td className="ion-activatable"><Link to="/kinetic/cold_blast">Cold blast<IonRippleEffect /></Link></td>
</tr>
<tr>
<td>3</td>
<td className="ion-activatable"><Link to="/kinetic/earth_blast">Earth blast<IonRippleEffect /></Link></td>
</tr>
<tr>
<td>4</td>
<td className="ion-activatable"><Link to="/kinetic/electric_blast">Electric blast<IonRippleEffect /></Link></td>
</tr>
<tr>
<td>5</td>
<td className="ion-activatable"><Link to="/kinetic/fire_blast">Fire blast<IonRippleEffect /></Link></td>
</tr>
<tr>
<td>6</td>
<td className="ion-activatable"><Link to="/kinetic/gravity_blast">Gravity blast<IonRippleEffect /></Link></td>
</tr>
<tr>
<td>7</td>
<td className="ion-activatable"><Link to="/kinetic/negative_blast">Negative blast<IonRippleEffect /></Link></td>
</tr>
<tr>
<td>8</td>
<td className="ion-activatable"><Link to="/kinetic/telekinetic_blast">Telekinetic blast<IonRippleEffect /></Link></td>
</tr>
<tr>
<td>9</td>
<td className="ion-activatable"><Link to="/kinetic/water_blast">Water blast<IonRippleEffect /></Link></td>
</tr>
<tr>
<td>10</td>
<td className="ion-activatable"><Link to="/kinetic/wood_blast">Wood blast<IonRippleEffect /></Link></td>
</tr>
</tbody></table></ScrollContainer>
</>};
const _primal_strike = {title: "Primal Strike", jsx: <><h2 id="feat-primal_strike-primal-strike-combat">Primal Strike (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_wastes">People of the Wastes pg. 7</Link></p>
<p>You have learned to draw primal magic through your body to befuddle your enemies.<br/><strong>Prerequisites:</strong> Wis 17, <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>, base attack bonus +8.<br/><strong>Benefit:</strong> Before making an attack roll, you can declare a primal strike. If you do and the attack hits, it deals damage normally and your target must attempt a Fortitude saving throw (DC = 10 + half your character level + your Wisdom modifier). A target who fails this saving throw is <Link to="/misc/confused">confused</Link> for 1 round. If you are in an area of <Link to="/rule/primal_magic">primal magic</Link>, the confused condition lasts for 1d4 rounds. You can attempt a primal strike attack once per day for every 4 character levels you have (see Special below if you have monk levels), but no more than once per round. A primal strike is a mind-affecting compulsion effect.<br/><strong>Special:</strong> If you have levels in the monk class, you can make a primal attack a number of times per day equal to your monk level, plus one additional time per day for every 4 levels you have in classes other than monk, though still no more than once per round.</p>
</>};
const _prodigy = {title: "Prodigy", jsx: <><h2 id="feat-prodigy-prodigy">Prodigy</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 154</Link></p>
<p>You are naturally skilled at arts, professions, and the acquisition of knowledge.<br/><strong>Benefit:</strong> Choose two Craft, Perform, or Profession skills in any combination (two Craft skills, a Craft skill and a Perform skill, and so on). You receive a +2 bonus on checks with these skills. If you have 10 or more ranks in any one of these skills, the bonus increases to +4 for that skill.<br/><strong>Special:</strong> You can gain this feat multiple times. Its effects do not stack. Each time you take the feat, it applies to two new skills.</p>
</>};
const _profane_studies = {title: "Profane Studies", jsx: <><h2 id="feat-profane_studies-profane-studies">Profane Studies</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 91</Link></p>
<p>Your study of fiends grants you advantages when summoning or fighting them.<br/><strong>Prerequisites:</strong> Int 13, Knowledge (planes) 4 ranks, ability to cast a <Link to="/spell/summon_monster">summon monster</Link> spell.<br/><strong>Benefit:</strong> You gain a +5 bonus on Knowledge (planes) checks involving evil outsiders. Additionally, when you cast a <em>summon monster</em> spell to summon an evil outsider, treat your caster level as 2 levels higher for the purpose of determining the duration.</p>
</>};
const _profits_of_kalistrade = {title: "Profits of Kalistrade", jsx: <><h2 id="feat-profits_of_kalistrade-profits-of-kalistrade">Profits of Kalistrade</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_campaign_setting">Pathfinder Campaign Setting pg. 73</Link></p>
<p>Your careful investments provide you with liquid assets with which you may gain the use of various items on a temporary basis.<br/><strong>Prerequisites:</strong> Diplomacy 1 rank, lives or works in Druma.<br/><strong>Benefit:</strong> By utilizing your mercantile connections, when you gain this feat you acquire a resource pool worth 100 gp. You may add to this resource pool with gold you acquire through adventuring, but once you put it in, it remains a part of your resource pool thereafter. Your resource pool increases by 100 gp at levels 2-5, 500 gp at levels 6-10, 1,000 gp at levels 11-15, and 5,000 gp at levels 16 and up.</p>
<p>You may utilize this resource pool in any community of village size or larger by requesting an item (mundane or magical). If the item you request is worth less than the community's gp limit, you gain it within 1d4 hours. If the item exceeds the community's gp limit but is less than double the limit, you gain the item within 1d4 days. An item more than twice as expensive as a community's gp limit is unavailable. For as long as you have the item in your possession, your resource pool is reduced by the amount of the item's value. If you lose the item or otherwise cannot return it to the resource pool, the pool permanently decreases by the value of the item. A charged item acquired in this way loses a percentage of its value based on the number of charges used, and when returned to the resource pool it reduces the size of the pool an equal amount. Your resource pool is available to you even outside of Druma, but in that case gaining a requested item takes 1 hour longer if below a community's gp limit or 1 day longer if above.</p>
</>};
const _prone_shooter = {title: "Prone Shooter", jsx: <><h2 id="feat-prone_shooter-prone-shooter-combat">Prone Shooter (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 113</Link></p>
<p>Take a reduced penalty to your AC against melee attacks while prone<br/><strong>Prerequisites:</strong> Base attack bonus +1.<br/><strong>Benefit:</strong> If you have been <Link to="/rule/prone">prone</Link> since the end of your last turn, the penalty to your Armor Class against melee attacks made against you is reduced to -2. In addition, the bonus to your Armor Class against ranged attacks made against you is increased to +6.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-prone_shooter--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-prone_shooter-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 129</Link><br/>As long as you have at least 1 stamina point in your stamina pool, you gain the bonuses from this feat even if you haven't been prone since the end of your last turn.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _prone_slinger = {title: "Prone Slinger", jsx: <><h2 id="feat-prone_slinger-prone-slinger-combat">Prone Slinger (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 113</Link></p>
<p>Your sideways sling release allows you to launch bullets and stones even while prone.<br/><strong>Benefit:</strong> While <Link to="/rule/prone">prone</Link>, you can use a sling to make ranged attacks.<br/><strong>Normal:</strong> Crossbows and firearms are the only ranged weapons that can be used while prone.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-prone_slinger--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-prone_slinger-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 129</Link><br/>As long as you have at least 1 stamina point in your stamina pool, you gain a +2 bonus on attack rolls made while prone and using a sling.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _prophet = {title: "Prophet", jsx: <><h2 id="feat-prophet-prophet-story">Prophet (Story)</h2>
<p><strong>Sources</strong> <Link to="/source/quests_and_campaigns">Quests and Campaigns pg. 12</Link>, <Link to="/source/ultimate_campaign">Ultimate Campaign pg. 71</Link></p>
<p>The truth has been revealed, and you have been chosen to deliver it.<br/><strong>Prerequisites:</strong> Ability to cast divine spells, and you must either have received a vision from your god (or another appropriate supernatural entity) or have the <Link to="/rule/birth_circumstances_and_more">Marked by the Gods</Link> circumstance background.<br/><strong>Benefit:</strong> If you are nonevil and worship a nonevil deity, whenever you cast a beneficial spell on an ally you gain a +1 sacred bonus to AC for 1 round per spell level. If you are evil or worship an evil deity, whenever you cast a harmful spell on an enemy you gain a +1 profane bonus to AC for 1 round per spell level. Casting a spell on yourself does not count unless it also affects an ally.<br/><strong>Goal:</strong> Convert an appropriate number of creatures to the worship of your deity.<br/><strong>Completion Benefit:</strong> Your bonus to AC for casting beneficial or harmful spells on allies increases to +2, and the bonus also applies on saving throws for the same duration.</p>
<p><em>Suggested Traits:</em> <Link to="/trait/called">Called</Link>, <Link to="/trait/ease_of_faith">Ease of Faith</Link>, <Link to="/trait/mystery_initiate">Mystery Initiate</Link>.</p>
<h3 id="feat-prophet-possible-prophet-quests">Possible Prophet Quests</h3>
<ScrollContainer id="feat-prophet--table-0"><table>
<thead>
<tr>
<th>d8</th>
<th>Quest</th>
</tr>
</thead>
<tbody><tr>
<td>1</td>
<td>You have been tasked with bringing <Link to="/faith/iomedae">Iomedae's</Link> faith to "uncivilized" backwoods people in a randomly determined nation.</td>
</tr>
<tr>
<td>2</td>
<td>The Umbral Court of Nidal expressly forbids the worship of gods other than <Link to="/faith/zon_kuthon">Zon-Kuthon</Link> within their shadowy nation, but you're set to protect and spread <Link to="/faith/desna">Desna's</Link> ideals to the Nidalese, either at large or in a relatively confined region, such as around the Atteran Ranches.</td>
</tr>
<tr>
<td>3</td>
<td>You seek to aid the little-known breed of horse-headed centaurs in the Exalted Wood in Razmiran and introduce them to your faith.</td>
</tr>
<tr>
<td>4</td>
<td>The Last Temple of Rahadoum offers the potential of many desperate evangelists who might aid you in spreading your god's faith in that domineering nation of atheists.</td>
</tr>
<tr>
<td>5</td>
<td>Inspired by the Hellknights of the Order of the Godclaw, you preach the words of your lawful patron among the rebellious rabble of Cheliax, whom you will turn into models of discipline whether they like it or not.</td>
</tr>
<tr>
<td>6</td>
<td>Disgusted by the disrespect of the Molthuni toward the once-sacred valley called Deadeye's Haunt, you intend to show them the error of their ways with the power of <Link to="/faith/erastil">Erastil</Link>.</td>
</tr>
<tr>
<td>7</td>
<td>You spread the faith of <Link to="/faith/milani">Milani</Link>, the Everbloom, by expelling unjust tyrants and aiding the downtrodden.</td>
</tr>
<tr>
<td>8</td>
<td>Your patron - a demon lord, archdevil, or other generally unwanted influence (determine randomly) - inspires you to disguise your faith and reveal it only slowly to potential converts in order to lure them into the fold.</td>
</tr>
</tbody></table></ScrollContainer>
</>};
const _prophetic_visionary = {title: "Prophetic Visionary", jsx: <><h2 id="feat-prophetic_visionary-prophetic-visionary">Prophetic Visionary</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 154</Link></p>
<p>Your oracular abilities give you a glimpse into the future.<br/><strong>Prerequisites:</strong> Mystery class feature.<br/><strong>Benefit:</strong> Once per day, you can enter a deep trance to receive a vision of the future. The trance lasts for 10 minutes, during which time you can take no other actions. If you are interrupted, you must begin again. When you come out of the trance, you know whether a particular action in the immediate future will bring good or bad results, as an <Link to="/spell/augury">augury</Link> spell with a 70% chance of success.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="feat-prophetic_visionary--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Prophetic Visionary</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 71</Link><br/>Your precognitive powers aid you further.<br/><strong>Prerequisites:</strong> Prophetic Visionary.<br/><strong>Benefit:</strong> You can use Prophetic Visionary's <em>augury</em> ability at will, spending 10 minutes in a deep trance each time. Your chance of a successful <em>augury</em> increases by 1% per tier. A successful <em>augury</em> made by using this feat also grants you the benefits of <Link to="/spell/guidance">guidance</Link>, but the bonus is equal to your tier and is an insight bonus instead of a competence bonus.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _prosperity_and_pride = {title: "Prosperity and Pride", jsx: <><h2 id="feat-prosperity_and_pride-prosperity-and-pride-story">Prosperity and Pride (Story)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_131_the_reapers_right_hand">Pathfinder #131: The Reaper's Right Hand pg. 76</Link></p>
<p>Your family has raised cities and mastered trade, and you seek to do the same.<br/><strong>Prerequisites:</strong> Be a member of House Corcina, or have the Inheritance <Link to="/rule/birth_circumstances_and_more">major childhood event</Link> background, Worldshaker (bard) <Link to="/rule/class_background_tables">class background</Link>, or the Craftsperson or Well-Connected Friend <Link to="/rule/influential_associates_table">background</Link>.<br/><strong>Benefit:</strong> When in a settlement the size of a large city or smaller, you receive a +2 bonus on Appraise checks and Diplomacy checks. If you have 10 or more ranks in one of these skills, the bonus on that skill increases to +4.<br/><strong>Goal:</strong> Your actions must spur a <Link to="/rule/settlements_in_play">settlement</Link> to grow to the next size category; this usually involves decisively defeating a challenging foe or an appropriate number of foes preying upon or impeding the settlement's citizenry.<br/><strong>Completion Benefit:</strong> You teach others how to get the most out of their equipment. Three times per day as a standard action, you can increase the armor bonus provided by a suit of nonmagical armor, the circumstance bonus to a skill provided by a tool or skill kit, or the shield bonus provided by a nonmagical shield by 1. This bonus lasts for 1 hour and doesn't stack with other uses of this ability.</p>
</>};
const _protective_channel = {title: "Protective Channel", jsx: <><h2 id="feat-protective_channel-protective-channel">Protective Channel</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 215</Link></p>
<p>When you channel energy, Iomedae grants protection against dark forces.<br/><strong>Prerequisites:</strong> <Link to="/ability/channel_energy">Channel energy</Link> 7d6, worshiper of <Link to="/faith/iomedae">Iomedae</Link>.<br/><strong>Benefit:</strong> When you channel positive energy to heal living creatures, you can choose to affect healed creatures with a <Link to="/spell/protection_from_evil">protection from evil</Link> spell (caster level equal to your effective cleric level).</p>
</>};
const _protective_line = {title: "Protective Line", jsx: <><h2 id="feat-protective_line-protective-line-combat-teamwork">Protective Line (Combat, Teamwork)</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 56</Link></p>
<p>Your teammates look out for you while you reload.<br/><strong>Prerequisites:</strong> <Link to="/feat/exotic_weapon_proficiency">Exotic Weapon Proficiency</Link> (firearms).<br/><strong>Benefit:</strong> When you are adjacent to an ally who also has this feat, you do not provoke attacks of opportunity while loading a firearm.</p>
</>};
const _protector_of_the_people = {title: "Protector of the People", jsx: <><h2 id="feat-protector_of_the_people-protector-of-the-people-story">Protector of the People (Story)</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 91</Link></p>
<p>You have vowed to construct a defender for your community.<br/><strong>Prerequisites:</strong> Your community has come under persecution and requires considerable defense.<br/><strong>Benefit:</strong> You temporarily gain the <Link to="/feat/craft_construct">Craft Construct</Link> feat for the purposes of building one <Link to="/family/golem">golem</Link> to satisfy the goal of this story feat. You do not need to meet Craft Construct's prerequisites, and it can't be used as a prerequisite for any other crafting endeavor.<br/><strong>Goal:</strong> Craft a golem of CR 5 or greater and donate it to your community for its defense against persecution. You and your allies must fund the construction, not the community. You must be significantly involved in the golem's construction. After completion, this golem cannot be used as a personal adventuring companion; it is the property of the community to which it was dedicated. The donated creature must be a golem and not another type of construct, such as an <Link to="/monster/animated_object">animated object</Link>.<br/><strong>Completion Benefit:</strong> You gain Craft Construct as a bonus feat without meeting its prerequisites and can use it for any purpose. The cost to build any construct that normally costs less than the cost of your donated golem is permanently reduced by 10%; the cost of the base materials is not reduced, however.</p>
</>};
const _protectors_strike = {title: "Protector's Strike", jsx: <><h2 id="feat-protectors_strike-protectors-strike">Protector's Strike</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 215</Link>, <Link to="/source/faiths_of_purity">Faiths of Purity pg. 25</Link></p>
<p>You can use your smiting power to protect an ally from known evil.<br/><strong>Prerequisites:</strong> Base attack bonus +5, smite evil class feature.<br/><strong>Benefit:</strong> When you choose the target of your smite evil ability, you also choose one creature other than you within line of sight. While your smite is in effect, the additional creature you chose gains a deflection bonus to AC equal to your Charisma modifier against attacks made by the target of the smite. This bonus ends when the smite ends. You do not gain the deflection bonus to AC normally granted by smite evil.<br/><strong>Normal:</strong> While smite evil is in effect, the paladin gains a deflection bonus to her AC equal to her Charisma bonus (if any) against attacks made by the target of her smite attack.</p>
</>};
const _proxy_summoning = {title: "Proxy Summoning", jsx: <><h2 id="feat-proxy_summoning-proxy-summoning">Proxy Summoning</h2>
<p><strong>Sources</strong> <Link to="/source/ranged_tactics_toolbox">Ranged Tactics Toolbox pg. 12</Link></p>
<p>Creatures you summon can act as proxies to deliver your spells to foes.<br/><strong>Prerequisites:</strong> Ability to cast conjuration (summoning) spells or a conjuration (summoning) spell-like ability, caster level 5th.<br/><strong>Benefit:</strong> Whenever you cast a touch spell while adjacent to a creature you summoned (including an eidolon), you can have the summoned creature carry the spell's charge. Once the spell is cast, you and any creature you summon gain the share spells ability. This feat doesn't qualify you for feats or other rules options that require you to have an animal companion, familiar, or similar allied creature with the share spells ability.</p>
</>};
const _psychic_adept = {title: "Psychic Adept", jsx: <><h2 id="feat-psychic_adept-psychic-adept">Psychic Adept</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 137</Link></p>
<p>You have honed your mind to harness psychic power.<br/><strong>Prerequisites:</strong> Int 11, <Link to="/feat/psychic_sensitivity">Psychic Sensitivity</Link>.<br/><strong>Benefit:</strong> You gain the ability to cast a 0-level knack from the <Link to="/main/spells_psychic_0_1">psychic class's spell list</Link>. You can cast this spell three times per day as a spell-like ability. The caster level for this ability is equal to your character level, and the save DC is equal to 10 + your Intelligence modifier.<br/><strong>Special:</strong> You can choose this feat multiple times, choosing a different knack each time.</p>
</>};
const _psychic_combatant = {title: "Psychic Combatant", jsx: <><h2 id="feat-psychic_combatant-psychic-combatant-combat">Psychic Combatant (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 137</Link></p>
<p>You are skilled at attacking opponents in psychic duels.<br/><strong>Prerequisites:</strong> Int 13, <Link to="/feat/psychic_sensitivity">Psychic Sensitivity</Link> or the ability to cast psychic spells or use psychic spell-like abilities, character level 3rd.<br/><strong>Benefit:</strong> You gain an extra pool of manifestation points with a number of points equal to 1/2 your character level. You can use these points at any time during a <Link to="/rule/psychic_duels">psychic duel</Link>. When you are not participating in a psychic duel, you can spend 1 of these extra manifestation points as a swift action to gain a +1 bonus on saving throws against psychic spells until the start of your next turn, or 3 points as a swift action to gain a +2 bonus on saving throws against psychic spells until the start of your next turn. This pool refreshes at the start of each day.</p>
</>};
const _psychic_defender = {title: "Psychic Defender", jsx: <><h2 id="feat-psychic_defender-psychic-defender">Psychic Defender</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 138</Link></p>
<p>You are adept at defending yourself during psychic duels.<br/><strong>Prerequisites:</strong> Int 13, <Link to="/feat/psychic_sensitivity">Psychic Sensitivity</Link> or the ability to cast psychic spells or use psychic spell-like abilities, character level 3rd.<br/><strong>Benefit:</strong> Each time you enter a psychic duel, you gain a number of temporary hit points equal to your manifesting level. These temporary hit points last until the end of the psychic duel.</p>
</>};
const _psychic_disciple = {title: "Psychic Disciple", jsx: <><h2 id="feat-psychic_disciple-psychic-disciple">Psychic Disciple</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 138</Link></p>
<p>You have opened your mind to the more advanced disciplines of basic psychic magic.<br/><strong>Prerequisites:</strong> Int 13, <Link to="/feat/psychic_adept">Psychic Adept</Link>, <Link to="/feat/psychic_sensitivity">Psychic Sensitivity</Link>.<br/><strong>Benefit:</strong> You gain the ability to cast a 1st-level psychic spell from the <Link to="/main/spells_psychic_0_1">psychic class's spell list</Link>. You can cast this spell twice per day as a spell-like ability. The caster level for this ability is equal to your character level, and the save DC is equal to 11 + your Intelligence modifier.<br/><strong>Special:</strong> You can take this feat multiple times, choosing a different spell each time.</p>
</>};
const _psychic_healing = {title: "Psychic Healing", jsx: <><h2 id="feat-psychic_healing-psychic-healing">Psychic Healing</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 138</Link></p>
<p>The spirit finds ways to heal the body, guided by your faith.<br/><strong>Prerequisites:</strong> Cha 11, <Link to="/feat/psychic_sensitivity">Psychic Sensitivity</Link> or the ability to cast psychic spells, Heal 3 ranks.<br/><strong>Benefit:</strong> As an additional use of the <Link to="/skill/faith_healing">faith healing</Link> skill unlock, you can attempt to manipulate a creature's psychic form to heal damage to its physical form. This works as the treat deadly wounds use of the <Link to="/skill/heal">Heal</Link> skill, but also grants the creature a number of <Link to="/rule/temporary_hit_points">temporary hit points</Link> equal to the amount of damage healed. These temporary hit points last for 1 hour. Psychic healing doesn't require a <Link to="/eq-misc/healers_kit">healer's kit</Link>. A creature can benefit from psychic healing only once per day, and can't benefit from both this ability and treat deadly wounds in the same day.</p>
</>};
const _psychic_maestro = {title: "Psychic Maestro", jsx: <><h2 id="feat-psychic_maestro-psychic-maestro">Psychic Maestro</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 138</Link></p>
<p>You can use two occult skill unlocks more often.<br/><strong>Prerequisites:</strong> <Link to="/feat/psychic_sensitivity">Psychic Sensitivity</Link> or the ability to cast psychic spells.<br/><strong>Benefit:</strong> Choose two <Link to="/rule/occult_skill_unlocks">occult skill unlocks</Link>. You can use each of those one additional time per day (or per week, in the case of automatic writing). You must have at least 1 rank in the skills associated with the chosen occult skill unlocks.</p>
</>};
const _psychic_sensitivity = {title: "Psychic Sensitivity", jsx: <><h2 id="feat-psychic_sensitivity-psychic-sensitivity">Psychic Sensitivity</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 138</Link></p>
<p>You unlock the secrets of the occult world.<br/><strong>Benefit:</strong> You gain access to <Link to="/rule/occult_skill_unlocks">occult skill unlocks</Link> for any skills in which you have ranks. If you have no ranks in the appropriate skill, you can't use the occult skill unlock, even if that skill can be used untrained.<br/><strong>Normal:</strong> You must have the ability to cast psychic spells in order to use occult skill unlocks.</p>
</>};
const _psychic_virtuoso = {title: "Psychic Virtuoso", jsx: <><h2 id="feat-psychic_virtuoso-psychic-virtuoso">Psychic Virtuoso</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 138</Link></p>
<p>You can use all of your occult skill unlocks more often and you are more talented at using them.<br/><strong>Prerequisites:</strong> <Link to="/feat/psychic_sensitivity">Psychic Sensitivity</Link> or ability to cast psychic spells.<br/><strong>Benefit:</strong> You gain a +2 bonus on checks to use <Link to="/rule/occult_skill_unlocks">occult skill unlocks</Link>. If you have more than 10 ranks in the base skill, this bonus increases to +4. This bonus doesn't apply on other checks using the base skills - only on checks for occult skill unlocks.</p>
</>};
const _psychovore_master = {title: "Psychovore Master", jsx: <><h2 id="feat-psychovore_master-psychovore-master-combat">Psychovore Master (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_spiral_of_bones_3">Pathfinder Spiral of Bones #3 pg. 29</Link></p>
<p>When your unarmed attacks strike true. you also damage your target's mind and gain power from it.<br/><strong>Prerequisites:</strong> <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>, <Link to="/feat/psychovore_strike">Psychovore Strike</Link>, <Link to="/feat/psychovore_style">Psychovore Style</Link>, Sense Motives 15 ranks.<br/><strong>Benefit:</strong> When you score a critical hit against the creature you are gaining a dodge bonus to AC against from Psychovore Style with your unarmed strike, that target also takes 1 point of Intelligence and Wisdom damage and you gain 2d8 <Link to="/rule/temporary_hit_points">temporary hit points</Link>. These temporary hit points last for 1 hour and don't stack with other temporary hit points you might gain with this feat.</p>
</>};
const _psychovore_strike = {title: "Psychovore Strike", jsx: <><h2 id="feat-psychovore_strike-psychovore-strike-combat">Psychovore Strike (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_spiral_of_bones_3">Pathfinder Spiral of Bones #3 pg. 29</Link></p>
<p>You can land blows that confuse your enemies.<br/><strong>Prerequisites:</strong> <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>, <Link to="/feat/psychovore_style">Psychovore Style</Link>, Sense Motive 9 ranks.<br/><strong>Benefit:</strong> When you strike the creature you are gaining a dodge bonus to AC against from Psychovore Style with your unarmed strike, you can force that creature to attempt a Will saving throw (DC = 10 + 1/2 your character level + your Wisdom modifier), in addition to dealing damage normally. A creature who fails its save is <Link to="/misc/confused">confused</Link> for 1d6 rounds. You must declare that you are using this feat before you make your attack roll (thus, a failed attack roll ruins the attempt). You can use this ability a number of times per day equal to 1 + your Wisdom bonus (minimum once per day), and no more than once per round. This is a mind-affecting effect, and a creature confused in this way never attacks you.</p>
</>};
const _psychovore_style = {title: "Psychovore Style", jsx: <><h2 id="feat-psychovore_style-psychovore-style-combat-style">Psychovore Style (Combat, Style)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_spiral_of_bones_3">Pathfinder Spiral of Bones #3 pg. 30</Link></p>
<p>You can sense the thoughts of others, allowing you to predict their movements.<br/><strong>Prerequisites:</strong> <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>, Sense Motive 3 ranks.<br/><strong>Benefit:</strong> When using this style, you can attempt a Sense Motive check (DC = 15 + CR of target) as a move action against a creature with an Intelligence score of 3 or higher. If you succeed, you gain a +1 dodge bonus to your AC against attacks from the target creature until you are no longer using this style. You can have this bonus against only one creature at a time: if you succeed at this Sense Motive check against another creature, you lose the bonus against the first creature. This bonus increases to +2 when you have 8 ranks in Sense Motive, and to +3 when you have 13 ranks in Sense Motive.</p>
</>};
const _pummeling_bully = {title: "Pummeling Bully", jsx: <><h2 id="feat-pummeling_bully-pummeling-bully-combat">Pummeling Bully (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 153</Link></p>
<p>Your punch has the chance to trip or move your target.<br/><strong>Prerequisites:</strong> <Link to="/feat/improved_reposition">Improved Reposition</Link>, <Link to="/feat/improved_trip">Improved Trip</Link>, <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>, <Link to="/feat/pummeling_style">Pummeling Style</Link>; base attack bonus +9, brawler level 5th, or monk level 5th.<br/><strong>Benefit:</strong> When you use Pummeling Style to make an entire full attack or flurry of blows against a single target, if you hit with any of your attacks, you can attempt a <Link to="/rule/reposition">reposition</Link> or <Link to="/rule/trip">trip</Link> combat maneuver check as a free action.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-pummeling_bully--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-pummeling_bully-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 129</Link><br/>When you hit with a Pummeling Style attack, you can spend 2 stamina points to make a bull rush attempt as a free action instead of a reposition attempt.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _pummeling_charge = {title: "Pummeling Charge", jsx: <><h2 id="feat-pummeling_charge-pummeling-charge-combat">Pummeling Charge (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 154</Link></p>
<p>Your charge ends with a mighty haymaker.<br/><strong>Prerequisites:</strong> <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>, <Link to="/feat/pummeling_style">Pummeling Style</Link>; base attack bonus +12, brawler level 8th, or monk level 8th.<br/><strong>Benefit:</strong> You can charge and make a full attack or flurry of blows at the end of your charge as part of the charge action. You can use Pummeling Charge in this way only if all of your attacks qualify for using Pummeling Style against a single target.<br/><strong>Normal:</strong> You cannot make a full attack on a charge.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-pummeling_charge--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-pummeling_charge-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 129</Link><br/>When you make a Pummeling Charge attack, you can spend 5 stamina points to make a single extra attack at your highest bonus.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _pummeling_style = {title: "Pummeling Style", jsx: <><h2 id="feat-pummeling_style-pummeling-style-combat-style">Pummeling Style (Combat, Style)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 154</Link></p>
<p>Your unarmed strikes weave together in an effortless combo, focusing on the spots you've weakened with the last hit.<br/><strong>Prerequisites:</strong> <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>; base attack bonus +6, brawler's flurry class feature, or flurry of blows class feature.<br/><strong>Benefit:</strong> Whenever you use a full-attack action or flurry of blows to make multiple attacks against a single opponent with unarmed strikes, total the damage from all hits before applying damage reduction. This ability works only with unarmed strikes, no matter what other abilities you might possess.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-pummeling_style--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-pummeling_style-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 129</Link><br/>While using this style, you can spend 5 stamina points to pool all of your attacks as a standard action, instead of a full-round action.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _punch_through = {title: "Punch Through", jsx: <><h2 id="feat-punch_through-punch-through-combat-teamwork">Punch Through (Combat, Teamwork)</h2>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook pg. 21</Link></p>
<p>You and your allies are adept at bypassing enemy defenses.<br/><strong>Prerequisites:</strong> Base attack bonus +6.<br/><strong>Benefit:</strong> As a full-round action, you may make a single attack against a target. If the attack hits and deals damage to the target, all of your allies with this feat ignore up to 5 points of damage reduction against the same target for 1 round. This feat does not apply to damage reduction without a type (such as DR 10/-).</p>
</>};
const _pungent_stench = {title: "Pungent Stench", jsx: <><h2 id="feat-pungent_stench-pungent-stench">Pungent Stench</h2>
<p><strong>Sources</strong> <Link to="/source/demons_revisited">Demons Revisited pg. 26</Link></p>
<p>Your stench is overwhelmingly nauseating.<br/><strong>Prerequisites:</strong> <Link to="/umr/stench">Stench</Link> universal monster ability, <Link to="/feat/improved_stench">Improved Stench</Link>, <Link to="/feat/great_fortitude">Great Fortitude</Link><br/><strong>Benefit:</strong> The first round a creature is affected by your stench, it is <Link to="/misc/nauseated">nauseated</Link> in addition to being <Link to="/misc/sickened">sickened</Link>. At the end of an affected creature's turn after the first round, it can make a new save against the stench's DC to remove the nauseated condition, but the sickened condition lasts as long as normal.</p>
</>};
const _punishing_kick = {title: "Punishing Kick", jsx: <><h2 id="feat-punishing_kick-punishing-kick-combat">Punishing Kick (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 167</Link></p>
<p>Your kicks are so powerful you use them to push or knock back your foes.<br/><strong>Prerequisites:</strong> Con 13, Wis 13, <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>, base attack bonus +8.<br/><strong>Benefit:</strong> You must declare that you are using this feat before you make your attack roll (thus a failed attack roll ruins the attempt). On a successful hit, the attack deals damage normally and you can choose to push your target 5 feet or attempt to knock them <Link to="/rule/prone">prone</Link>. If you decide to push the target, it is moved 5 feet directly away from you. This movement does not provoke attacks of opportunity, and the target must end this move in a safe space it can stand in. If you decide to attempt to knock the target prone, the target receives a Fortitude saving throw with a DC of 10 + 1/2 your character level + your Wisdom modifier to avoid the effect. You may attempt a punishing kick attack once per day for every four levels you have attained (but see Special), and no more than once per round.<br/><strong>Special:</strong> A <Link to="/arc-monk/hungry_ghost_monk">hungry ghost monk</Link> receives Punishing Kick as a bonus feat at 1st level, even if he does not meet the prerequisites. A monk may attempt a punishing kick attack a number of times per day equal to his monk level, plus one more time per day for every four levels he has in classes other than monk.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-punishing_kick--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-punishing_kick-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 129</Link><br/>You can spend 5 stamina points to declare you are using this feat after you make a successful unarmed strike attack.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _punishing_step = {title: "Punishing Step", jsx: <><h2 id="feat-punishing_step-punishing-step-combat">Punishing Step (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/monster_hunters_handbook">Monster Hunter's Handbook pg. 15</Link></p>
<p>You can hurt a foe that uses a combat maneuver against you.<br/><strong>Prerequisites:</strong> Dex 13, <Link to="/feat/dodge">Dodge</Link>.<br/><strong>Benefit:</strong> Your bonus to AC from the Dodge feat increases to +2 when calculating your CMD. When a creature attempts a combat maneuver against you and fails, you gain a +2 circumstance bonus on attack rolls against that creature until the end of your next turn.</p>
</>};
const _puppet_master = {title: "Puppet Master", jsx: <><h2 id="feat-puppet_master-puppet-master-story">Puppet Master (Story)</h2>
<p><strong>Sources</strong> <Link to="/source/spymasters_handbook">Spymaster's Handbook pg. 16</Link></p>
<p>You crave power you can wield without drawing attention to yourself.<br/><strong>Prerequisites:</strong> You must have survived an encounter with a challenging foe without suffering significant harm by striking a deal (regardless of whether the deal was with the challenging foe or not), or have the Boss, the Liege Lord, or the Well-Connected Friend <Link to="/rule/influential_associates_table">background</Link>.<br/><strong>Benefit:</strong> If you succeed at a Diplomacy check to make a request of a creature by 5 or more, the DCs of additional requests you attempt increase by 1 per request, rather than 5.<br/><strong>Goal:</strong> Either thwart or decisively defeat an appropriate number of challenging foes as a direct result of bargains you have struck or control at least three leaders of settlements of at least 2,000 residents or similarly influential administrators for at least 6 months without being publicly exposed.<br/><strong>Completion Benefit:</strong> If you succeed at a Diplomacy check to make a request of a creature, the DCs of additional requests you attempt increase by 1 per request, rather than 5.</p>
</>};
const _pure_faith = {title: "Pure Faith", jsx: <><h2 id="feat-pure_faith-pure-faith">Pure Faith</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 154</Link></p>
<p>Not only are you immune to disease, like most paladins, but you also are highly resilient to poisons.<br/><strong>Prerequisites:</strong> Divine health class feature.<br/><strong>Benefit:</strong> You gain a +4 sacred bonus to saving throws against poison.</p>
</>};
const _pure_legion_assault = {title: "Pure Legion Assault", jsx: <><h2 id="feat-pure_legion_assault-pure-legion-assault-combat">Pure Legion Assault (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/spymasters_handbook">Spymaster's Handbook pg. 23</Link></p>
<p>The Pure Legion trained you to apply your knowledge of religions to predicting and defeating divine servitors.<br/><strong>Prerequisites:</strong> Bluff 1 rank, Knowledge (religion) 1 rank, <Link to="/trait/pure_legion_recruit">Pure Legion Recruit</Link> trait.<br/><strong>Benefit:</strong> You gain a +2 bonus on saving throws against divine spells and effects and abilities from outsiders. If you must attempt a saving throw against a divine spell, you gain a +1 bonus on attack rolls against the creature that cast the spell</p>
</>};
const _purging_emesis = {title: "Purging Emesis", jsx: <><h2 id="feat-purging_emesis-purging-emesis">Purging Emesis</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 91</Link></p>
<p>You learn to purge toxins by vomiting.<br/><strong>Prerequisites:</strong> <Link to="/feat/great_fortitude">Great Fortitude</Link>.<br/><strong>Benefit:</strong> As a full-round action that provokes attacks of opportunity, you can attempt to end an ingested poison effect by making yourself vomit. If you succeed at a new saving throw against the initial effect, you gain the <Link to="/misc/nauseated">nauseated</Link> condition for 1 round but end the poison effect as if you had succeeded at the requisite saving throws. Your vomiting causes one adjacent square to become slippery until your vomit is cleaned (usually taking 1 full round) or dries up (usually 1 hour). Once you use this feat, you must wait at least 1 hour and consume food or drink before you can use it again.</p>
</>};
const _purifying_channel = {title: "Purifying Channel", jsx: <><h2 id="feat-purifying_channel-purifying-channel">Purifying Channel</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 15</Link></p>
<p>Your healing energy also damages your enemies.<br/><strong>Prerequisites:</strong> Cha 15, <Link to="/feat/selective_channeling">Selective Channeling</Link>, <Link to="/ability/channel_energy">channel energy</Link> class feature.<br/><strong>Benefit:</strong> When you channel positive energy to heal, one creature that you exclude from your channeling takes an amount of fire damage equal to the die result you roll for healing, and is <Link to="/misc/dazzled">dazzled</Link> for 1 round by the light of these flames. A successful saving throw against your channel energy halves the fire damage and negates the dazzled effect.</p>
</>};
const _pursuit_of_glory = {title: "Pursuit of Glory", jsx: <><h2 id="feat-pursuit_of_glory-pursuit-of-glory-combat-teamwork">Pursuit of Glory (Combat, Teamwork)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 208</Link></p>
<p>You know that daring deeds and heroics live forever in song, and sagas will carry your deeds into immortality.<br/><strong>Prerequisites:</strong> <Link to="/race/human">Human</Link> (Ulfen).<br/><strong>Benefit:</strong> Whenever you start or end a charge attack in a space adjacent to an ally who also has this feat, you gain a +2 morale bonus on one attack roll you make as part of the charge. Furthermore, you can charge through a space containing an ally who also has this feat.</p>
</>};
const _push_the_limits = {title: "Push the Limits", jsx: <><h2 id="feat-push_the_limits-push-the-limits-combat">Push the Limits (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 113</Link></p>
<p>Even when suffering from fatigue, you can fight through and overcome incredible opposition.<br/><strong>Prerequisites:</strong> Con 13, <Link to="/feat/combat_stamina">Combat Stamina</Link>, base attack bonus +1.<br/><strong>Benefit:</strong> You gain a secondary stamina pool with a number of stamina points equal to your Constitution modifier. You can spend these secondary stamina points only when you have 0 stamina points in your primary stamina pool or when you are <Link to="/misc/fatigued">fatigued</Link>, even though you normally can't spend stamina points while fatigued. You can spend these secondary stamina points as normal, but if the secondary pool drops to 0 points, you become <Link to="/misc/exhausted">exhausted</Link> until you have at least 1 stamina point in your primary pool. Even if you have points in your secondary pool, you are still fatigued as long as you have 0 points in your primary pool. Your secondary pool refreshes only after a full night's rest.</p>
</>};
const _pushing_assault = {title: "Pushing Assault", jsx: <><h2 id="feat-pushing_assault-pushing-assault-combat">Pushing Assault (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 167</Link></p>
<p>A strike made with a two-handed weapon can push a similar sized opponent backward.<br/><strong>Prerequisites:</strong> Str 15, <Link to="/feat/power_attack">Power Attack</Link>, base attack bonus +1.<br/><strong>Benefit:</strong> When you hit a creature your size or smaller with a two-handed weapon attack modified by the Power Attack feat, you can choose to push the target 5 feet directly away from you instead of dealing the extra damage from Power Attack. If you score a critical hit, you can instead push the target 10 feet directly away from you. This movement does not provoke attacks of opportunities, and the target must end this move in a safe space it can stand in. You choose which effect to apply after the attack roll has been made, but before the damage is rolled.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-pushing_assault--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-pushing_assault-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 129</Link><br/>You can spend 5 stamina points to gain the effects of this feat and still deal the extra damage from Power Attack.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _putrid_summons = {title: "Putrid Summons", jsx: <><h2 id="feat-putrid_summons-putrid-summons">Putrid Summons</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 91</Link></p>
<p>You summon creatures whose very presence turns the stomach of your foes.<br/><strong>Prerequisites:</strong> <Link to="/feat/spell_focus">Spell Focus</Link> (conjuration); ability to cast <Link to="/spell/summon_monster">summon monster</Link> or <Link to="/spell/summon_natures_ally">summon nature's ally</Link>.<br/><strong>Benefit:</strong> When you cast a <em>summon monster</em> or <em>summon nature's ally</em> spell, you can choose to summon a single creature that exudes a putrid odor or befouls the water surrounding it, granting it the <Link to="/umr/stench">stench</Link> universal monster ability. The duration of the <Link to="/misc/sickened">sickened</Link> condition created by this stench is a number of rounds equal to the spell's level. When performing a putrid summon, you summon a creature from the next lower list than the spell you are casting. For instance, if you cast <Link to="/spell/summon_monster_iv">summon monster IV</Link>, you summon a creature from the <Link to="/spell/summon_monster_iii">summon monster III</Link> list.</p>
</>};
const _quah_bond = {title: "Quah Bond", jsx: <><h2 id="feat-quah_bond-quah-bond-teamwork">Quah Bond (Teamwork)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 208</Link></p>
<p>Your bond with your totem spirit increases around others of the same quah.<br/><strong>Prerequisites:</strong> <Link to="/feat/totem_spirit">Totem Spirit</Link>, <Link to="/race/human">human</Link> (Shoanti).<br/><strong>Benefit:</strong> If at least one Shoanti ally from the same quah who also has this feat is within 30 feet, double your benefits from the Totem Spirit feat.</p>
</>};
const _quarterstaff_master = {title: "Quarterstaff Master", jsx: <><h2 id="feat-quarterstaff_master-quarterstaff-master-combat">Quarterstaff Master (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 154</Link></p>
<p>You can wield a quarterstaff as either a two-handed or one-handed weapon.<br/><strong>Prerequisites:</strong> <Link to="/feat/weapon_focus">Weapon Focus</Link> (quarterstaff), base attack bonus +5.<br/><strong>Benefit:</strong> By employing a number of different stances and techniques, you can wield a <Link to="/eq-weapon/quarterstaff">quarterstaff</Link> as a one-handed weapon. At the start of your turn, you decide whether or not you are going to wield the quarterstaff as a one-handed or two-handed weapon. When you wield it as a one-handed weapon, your other hand is free, and you cannot use the staff as a double weapon. You can take the feat <Link to="/feat/weapon_specialization">Weapon Specialization</Link> in the quarterstaff even if you have no levels in fighter.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-quarterstaff_master--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-quarterstaff_master-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 129</Link><br/>When you use this feat to wield a quarterstaff as a one-handed weapon, you can spend 5 stamina points to retain the ability to use it as a double weapon and still keep a hand free. This effect lasts until the beginning of your next turn.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _quick_bull_rush = {title: "Quick Bull Rush", jsx: <><h2 id="feat-quick_bull_rush-quick-bull-rush-combat">Quick Bull Rush (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 113</Link></p>
<p>You can barrel into your opponent and follow this with an attack.<br/><strong>Prerequisites:</strong> Str 13, <Link to="/feat/improved_bull_rush">Improved Bull Rush</Link>, <Link to="/feat/power_attack">Power Attack</Link>, base attack bonus +6.<br/><strong>Benefit:</strong> On your turn, you can perform a single <Link to="/rule/bull_rush">bull rush</Link> combat maneuver in place of one of your melee attacks. You must choose the melee attack with the highest base attack bonus to make the bull rush.<br/><strong>Normal:</strong> A bull rush combat maneuver is a standard action.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-quick_bull_rush--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-quick_bull_rush-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 129</Link><br/>You can spend 2 stamina points to change an attack that does not have your highest base attack bonus into a bull rush combat maneuver. You can use this combat trick only once per round, but you can use it even if you already used your attack at the highest base attack bonus to bull rush.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _quick_channel = {title: "Quick Channel", jsx: <><h2 id="feat-quick_channel-quick-channel">Quick Channel</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 154</Link></p>
<p>Your divine energies flash with dazzling speed.<br/><strong>Prerequisites:</strong> Knowledge (religion) 5 ranks, <Link to="/ability/channel_energy">channel energy</Link> class feature.<br/><strong>Benefit:</strong> You may channel energy as a move action by spending 2 daily uses of that ability.</p>
</>};
const _quick_dirty_trick = {title: "Quick Dirty Trick", jsx: <><h2 id="feat-quick_dirty_trick-quick-dirty-trick-combat">Quick Dirty Trick (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 114</Link></p>
<p>You can perpetrate a dirty trick and deliver an attack before your opponent is the wiser.<br/><strong>Prerequisites:</strong> Int 13, <Link to="/feat/combat_expertise">Combat Expertise</Link>, <Link to="/feat/improved_dirty_trick">Improved Dirty Trick</Link>, base attack bonus +6.<br/><strong>Benefit:</strong> On your turn, you can perform a single <Link to="/rule/dirty_trick">dirty trick</Link> combat maneuver in place of one of your melee attacks. You must choose the melee attack with the highest base attack bonus to make the dirty trick combat maneuver.<br/><strong>Normal:</strong> A dirty trick combat maneuver is a standard action.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-quick_dirty_trick--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-quick_dirty_trick-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 129</Link><br/>You can select this feat even if you don't meet the ability score prerequisite (Intelligence 13). You gain the benefits of this feat only as long as you have at least 1 stamina point in your stamina pool. You can spend 2 stamina points to change an attack that does not have your highest base attack bonus into a dirty trick combat maneuver. You can use this combat trick only once per round, but you can use it even if you already used your attack at the highest base attack bonus for a dirty trick.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _quick_drag = {title: "Quick Drag", jsx: <><h2 id="feat-quick_drag-quick-drag-combat">Quick Drag (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 114</Link></p>
<p>You drag your enemy and deliver a punishing blow.<br/><strong>Prerequisites:</strong> Str 13, <Link to="/feat/improved_drag">Improved Drag</Link>, <Link to="/feat/power_attack">Power Attack</Link>, base attack bonus +6.<br/><strong>Benefit:</strong> On your turn, you can perform a single <Link to="/rule/drag">drag</Link> combat maneuver in place of one of your melee attacks. You must choose the melee attack with the highest base attack bonus to make the drag.<br/><strong>Normal:</strong> A drag combat maneuver is a standard action.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-quick_drag--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-quick_drag-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 129</Link><br/>You can spend 2 stamina points to change an attack that does not have your highest base attack bonus into a drag combat maneuver. You can use this combat trick only once per round, but you can use it even if you already used your attack at the highest base attack bonus to drag.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _quick_draw = {title: "Quick Draw", jsx: <><h2 id="feat-quick_draw-quick-draw-combat">Quick Draw (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 131</Link></p>
<p>You can draw weapons faster than most.<br/><strong>Prerequisites:</strong> Base attack bonus +1.<br/><strong>Benefit:</strong> You can draw a weapon as a free action instead of as a move action. You can draw a hidden weapon (see the <Link to="/skill/sleight_of_hand">Sleight of Hand</Link> skill) as a move action. A character who has selected this feat may throw weapons at his full normal rate of attacks (much like a character with a bow). Alchemical items, potions, scrolls, and wands cannot be drawn quickly using this feat.<br/><strong>Normal:</strong> Without this feat, you may draw a weapon as a move action, or (if your base attack bonus is +1 or higher) as a free action as part of movement. Without this feat, you can draw a hidden weapon as a standard action.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-quick_draw--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-quick_draw-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 129</Link><br/>As long as you have at least 1 stamina point in your stamina pool, you can sheathe a weapon as a swift action.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional mythic"><ScrollContainer id="feat-quick_draw--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Quick Draw</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 71</Link><br/>You can retrieve any item quickly, not just weapons.<br/><strong>Prerequisites:</strong> Quick Draw.<br/><strong>Benefit:</strong> You can use Quick Draw to draw items of any kind, not just weapons, provided they are stored or concealed on your person. As a move action, you can expend one use of mythic power to retrieve up to two hidden items. You must have two hands free to do so.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _quick_favor = {title: "Quick Favor", jsx: <><h2 id="feat-quick_favor-quick-favor">Quick Favor</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 89</Link></p>
<p>You can quickly take advantage of your charm.<br/><strong>Prerequisites:</strong> <Link to="/feat/persuasive">Persuasive</Link>.<br/><strong>Benefit:</strong> Once per day, you can decrease the time required for a Diplomacy check to gather information to 4d10 minutes when you use Diplomacy to gather information again just after you previously gathered information there (whether or not the previous attempt was successful).<br/><strong>Normal:</strong> You must spend 1d4 hours to gather information using Diplomacy.</p>
</>};
const _quick_preparation = {title: "Quick Preparation", jsx: <><h2 id="feat-quick_preparation-quick-preparation">Quick Preparation</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_society_primer">Pathfinder Society Primer pg. 9</Link></p>
<p>Early on in your adventuring career, you learned (perhaps the hard way) how to prepare your spells even when put under extreme time constraints.<br/><strong>Prerequisites:</strong> Ability to prepare spells.<br/><strong>Benefit:</strong> When preparing spells, you halve the time necessary to do so.<br/><strong>Normal:</strong> Preparing all of your spells takes 1 hour.</p>
</>};
const _quick_reposition = {title: "Quick Reposition", jsx: <><h2 id="feat-quick_reposition-quick-reposition-combat">Quick Reposition (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 114</Link></p>
<p>Your opponent becomes an unwitting dance partner, following your lead while you fight.<br/><strong>Prerequisites:</strong> Int 13, <Link to="/feat/combat_expertise">Combat Expertise</Link>, <Link to="/feat/improved_reposition">Improved Reposition</Link>, base attack bonus +6.<br/><strong>Benefit:</strong> On your turn, you can perform a single <Link to="/rule/reposition">reposition</Link> combat maneuver in place of one of your melee attacks. You must choose the melee attack with the highest base attack bonus to make the reposition.<br/><strong>Normal:</strong> A reposition combat maneuver is a standard action.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-quick_reposition--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-quick_reposition-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 129</Link><br/>You can select this feat even if you don't meet the ability score prerequisite (Intelligence 13). You gain the benefits of this feat only as long as you have at least 1 stamina point in your stamina pool. You can spend 2 stamina points to change an attack that does not have your highest base attack bonus into a reposition combat maneuver. You can use this combat trick only once per round, but you can use it even if you already used your attack at the highest base attack bonus to reposition.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _quick_steal = {title: "Quick Steal", jsx: <><h2 id="feat-quick_steal-quick-steal-combat">Quick Steal (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 114</Link></p>
<p>You are adept at relieving foes of their belongings even while you strike.<br/><strong>Prerequisites:</strong> Int 13, <Link to="/feat/combat_expertise">Combat Expertise</Link>, <Link to="/feat/improved_steal">Improved Steal</Link>, base attack bonus +6.<br/><strong>Benefit:</strong> On your turn, you can perform a single <Link to="/rule/steal">steal</Link> combat maneuver in place of one of your melee attacks. You must choose the melee attack with the highest base attack bonus to make the steal.<br/><strong>Normal:</strong> A steal combat maneuver is a standard action.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-quick_steal--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-quick_steal-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 130</Link><br/>You can select this feat even if you don't meet the ability score prerequisite (Intelligence 13). You gain the benefit of this feat only as long as you have at least 1 stamina point in your stamina pool. You can spend 2 stamina points to change an attack that does not have your highest base attack bonus into a steal combat maneuver. You can use this combat trick only once per round, but you can use it even if you already used your attack at the highest base attack bonus to steal.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _quick_stow = {title: "Quick Stow", jsx: <><h2 id="feat-quick_stow-quick-stow-combat">Quick Stow (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 128</Link></p>
<p>You effortlessly stow items and sheathe weapons.<br/><strong>Prerequisites:</strong> <Link to="/feat/quick_draw">Quick Draw</Link>, base attack bonus +1.<br/><strong>Benefit:</strong> You do not provoke an attack of opportunity when sheathing a weapon, and you can combine a move action to sheathe a weapon with a regular move action. (You can both stow and draw a weapon as part of the same move action in this way.) If you have the <Link to="/feat/two_weapon_fighting">Two-Weapon Fighting</Link> feat, you can sheathe two light or one-handed weapons in the time it would normally take to sheathe one.</p>
<p>You can also quickly stow items in a backpack or other container that you are wearing or carrying. When you successfully use an action to pick up an item (including when you steal an item with a successful Sleight of Hand check or <Link to="/rule/steal">steal</Link> combat maneuver check), you can stow the item as part of the same action used to acquire it. You can try to hide this object by attempting a Sleight of Hand check with a -20 penalty, opposed by the Perception check results of all opponents.</p>
</>};
const _quick_study = {title: "Quick Study", jsx: <><h2 id="feat-quick_study-quick-study-combat">Quick Study (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 89</Link></p>
<p>You can learn quickly, although you do not always retain what you learn long.<br/><strong>Prerequisites:</strong> Int 13, bravery +3 class feature, fighter level 10th.<br/><strong>Benefit:</strong> Once per day, you can train with someone who has a combat feat you do not possess to gain that feat. You must train with that person for 8 hours and must meet the feat's prerequisites to gain it this way. You gain this feat until you learn another one using this feat.</p>
</>};
const _quick_trapper = {title: "Quick Trapper", jsx: <><h2 id="feat-quick_trapper-quick-trapper">Quick Trapper</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_116_fangs_of_war">Pathfinder #116: Fangs of War pg. 67</Link></p>
<p>Your trap-making proficiency improves greatly.<br/><strong>Prerequisites:</strong> <Link to="/feat/learn_ranger_trap">Learn Ranger Trap</Link> or trap class feature, Survival 5 ranks.<br/><strong>Benefit:</strong> When setting a <Link to="/ability/ranger_traps">ranger trap</Link>, you can do so as a standard action rather than a full-round action. If you do so, the trap DC is reduced by 5.</p>
</>};
const _quick_wild_shape = {title: "Quick Wild Shape", jsx: <><h2 id="feat-quick_wild_shape-quick-wild-shape">Quick Wild Shape</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 154</Link></p>
<p>You sacrifice power for speed in changing form.<br/><strong>Prerequisites:</strong> Wild shape class feature, caster level 8th.<br/><strong>Benefit:</strong> You can wild shape as a move action or a swift action. However, you are limited to forms available to a druid two levels lower when changing form as a move action, or four levels lower as a swift action.</p>
</>};
const _quicken_blessing = {title: "Quicken Blessing", jsx: <><h2 id="feat-quicken_blessing-quicken-blessing">Quicken Blessing</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 154</Link></p>
<p>You can deliver one of your blessings with greater speed.<br/><strong>Prerequisites:</strong> Access to a blessing's major power, blessings class feature.<br/><strong>Benefit:</strong> Choose one of your <Link to="/ability/blessings">blessings</Link> that normally requires a standard action to use. You can expend two of your daily uses of blessings to deliver that blessing (regardless of whether it's a minor or major effect) as a swift action instead.<br/><strong>Special:</strong> You can take this feat multiple times. Each time you do, you choose a different blessing.</p>
</>};
const _quicken_spell = {title: "Quicken Spell", jsx: <><h2 id="feat-quicken_spell-quicken-spell-metamagic">Quicken Spell (Metamagic)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 132</Link></p>
<p>You can cast spells in a fraction of the normal time.<br/><strong>Benefit:</strong> Casting a quickened spell is a swift action. You can perform another action, even casting another spell, in the same round as you cast a quickened spell. A spell whose casting time is more than 1 round or 1 full-round action cannot be quickened.</p>
<p>A quickened spell uses up a spell slot four levels higher than the spell's actual level. Casting a quickened spell doesn't provoke an attack of opportunity.</p>
<p><strong>Special:</strong> You can apply the effects of this feat to a spell cast spontaneously, so long as it has a casting time that is not more than 1 full-round action, without increasing the spell's casting time.</p>
</>};
const _quicken_spell_like_ability = {title: "Quicken Spell-Like Ability", jsx: <><h2 id="feat-quicken_spell_like_ability-quicken-spell-like-ability-monster">Quicken Spell-Like Ability (Monster)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_rpg_bestiary">Pathfinder RPG Bestiary pg. 315</Link></p>
<p>This creature can use one of its spell-like abilities with next to no effort.<br/><strong>Prerequisites:</strong> Spell-like ability at CL 10th or higher.<br/><strong>Benefit:</strong> Choose one of the creature's spell-like abilities, subject to the restrictions described in this feat. The creature can use the chosen spell-like ability as a quickened spell-like ability three times per day (or less, if the ability is normally usable only once or twice per day).</p>
<p>Using a quickened spell-like ability is a swift action that does not provoke an attack of opportunity. The creature can perform another action - including the use of another spell-like ability (but not another swift action) - in the same round that it uses a quickened spell-like ability. The creature may use only one quickened spell-like ability per round.</p>
<p>The creature can only select a spell-like ability duplicating a spell with a level less than or equal to 1/2 its caster level (round down) - 4. For a summary, see the table below.</p>
<p>A spell-like ability that duplicates a spell with a casting time greater than 1 full round cannot be quickened.</p>
<ScrollContainer id="feat-quicken_spell_like_ability--table-0"><table>
<thead>
<tr>
<th>Spell Level</th>
<th>Caster Level to Quicken</th>
</tr>
</thead>
<tbody><tr>
<td>0</td>
<td>8th</td>
</tr>
<tr>
<td>1st</td>
<td>10th</td>
</tr>
<tr>
<td>2nd</td>
<td>12th</td>
</tr>
<tr>
<td>3rd</td>
<td>14th</td>
</tr>
<tr>
<td>4th</td>
<td>16th</td>
</tr>
<tr>
<td>5th</td>
<td>18th</td>
</tr>
<tr>
<td>6th</td>
<td>20th</td>
</tr>
<tr>
<td>7th</td>
<td>-</td>
</tr>
<tr>
<td>8th</td>
<td>-</td>
</tr>
<tr>
<td>9th</td>
<td>-</td>
</tr>
</tbody></table></ScrollContainer>
<p><strong>Normal:</strong> The use of a spell-like ability normally requires a standard action (at the very least) and provokes an attack of opportunity.<br/><strong>Special:</strong> This feat can be taken multiple times. Each time it is taken, the creature can apply it to a different one of its spell-like abilities.</p>
</>};
const _quiet_death = {title: "Quiet Death", jsx: <><h2 id="feat-quiet_death-quiet-death-combat">Quiet Death (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 89</Link></p>
<p>You have learned to dispatch your enemies with the silence and grace of an accomplished assassin.<br/><strong>Prerequisites:</strong> Dex 19, Stealth 10 ranks, rogue level 10th.<br/><strong>Benefit:</strong> When you ambush an enemy or enemies that are unaware of your presence, you can roll a Stealth check with a -5 penalty. The result indicates the Perception DC to hear your attacks (rather than the normal DC of -10 to hear pitched combat) until an opponent's first action, when the DC returns to -10. Other enemies present can still see the attack; Quiet Death only prevents the sounds of battle from alerting further enemies.</p>
</>};
const _quillbreaker_defense = {title: "Quillbreaker Defense", jsx: <><h2 id="feat-quillbreaker_defense-quillbreaker-defense-combat">Quillbreaker Defense (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/magical_marketplace">Magical Marketplace pg. 6</Link></p>
<p>You know how to put armor spikes to defensive use by thrusting them into the path of an oncoming attack just in time.<br/><strong>Prerequisites:</strong> Proficiency with <Link to="/eq-armorenh/armor_spikes">armor spikes</Link>.<br/><strong>Benefit:</strong> If you are wearing armor spikes, as an immediate action when you take damage from a nonmagical attack, you can give your armor spikes the <Link to="/misc/broken">broken</Link> condition to reduce the amount of damage you take by 5. If your armor spikes are already broken, they are destroyed when you take the damage. If you are wearing masterwork armor spikes, you instead reduce the damage taken by 10.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-quillbreaker_defense--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-quillbreaker_defense-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 21</Link><br/>If you choose to spend 5 stamina points when using this feat, there is a 50% chance that your armor spikes do not gain the broken condition. This combat trick has no effect if your armor spikes already have the broken condition.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _quivering_palm_adept = {title: "Quivering Palm Adept", jsx: <><h2 id="feat-quivering_palm_adept-quivering-palm-adept-combat">Quivering Palm Adept (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer pg. 25</Link></p>
<p>Your quivering palm strikes are more potent than most.<br/><strong>Prerequisites:</strong> Quivering palm class feature.<br/><strong>Benefit:</strong> Add +2 to the saving throw DC against your quivering palm attacks.</p>
</>};
const _quivering_palm_versatility = {title: "Quivering Palm Versatility", jsx: <><h2 id="feat-quivering_palm_versatility-quivering-palm-versatility-combat">Quivering Palm Versatility (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer pg. 25</Link></p>
<p>You can alter the way you apply a quivering palm's vibrations to an opponent's body to cause extreme pain, put it in a coma, or destroy its memories.<br/><strong>Prerequisites:</strong> Quivering palm class feature, base attack bonus +13.<br/><strong>Benefit:</strong> After successfully using your quivering palm attack on a creature, you can produce one of the following effects instead of killing the creature, as long as you do so within a number of days equal to your monk level.</p>
<blockquote>
<p><strong className="hl">Coma:</strong> The subject falls <Link to="/misc/unconscious">unconscious</Link> and is <Link to="/misc/helpless">helpless</Link> for a number of days equal to your monk level.</p>
<p><strong className="hl">Memory Loss:</strong> The subject falls unconscious for 24 hours and awakens with huge gaps in its memory. The target's memories of the recent past (a number of consecutive days equal to your monk level) are completely obliterated, and can only be restored by a <Link to="/spell/wish">wish</Link> or <Link to="/spell/miracle">miracle</Link> spell.</p>
<p><strong className="hl">Pain:</strong> The subject takes 1d6 points of nonlethal damage per monk level you possess.</p>
</blockquote>
<p>You must choose the desired effect before the quivering palm's attack roll is made. Unless the target succeeds at its Fortitude save against your quivering palm attack, it succumbs to the desired effect when you will it (a free action). This feat is otherwise subject to all of the limits and conditions of quivering palm.</p>
</>};
const _racial_heritage = {title: "Racial Heritage", jsx: <><h2 id="feat-racial_heritage-racial-heritage">Racial Heritage</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 168</Link></p>
<p>The blood of a non-human ancestor flows in your veins.<br/><strong>Prerequisites:</strong> <Link to="/race/human">Human</Link>.<br/><strong>Benefit:</strong> Choose another humanoid race. You count as both human and that race for any effects related to race. For example, if you choose dwarf, you are considered both a human and a dwarf for the purpose of taking traits, feats, how spells and magic items affect you, and so on.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="feat-racial_heritage--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Racial Heritage</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 71</Link><br/>Your racial heritage mingles with your mythic power to become more pronounced.<br/><strong>Prerequisites:</strong> Racial Heritage.<br/><strong>Benefit:</strong> You gain a single racial trait of your choice from the race you picked when you took non-mythic Racial Heritage. That racial trait can't modify your size or ability scores. You also gain the racial language of the race (if any) if you don't already know it. For races with multiple racial languages, you gain all of them.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _racial_item_mastery = {title: "Racial Item Mastery", jsx: <><h2 id="feat-racial_item_mastery-racial-item-mastery-item-mastery">Racial Item Mastery (Item Mastery)</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 30</Link></p>
<p>You can use certain magic items to fuel your innate powers.<br/><strong>Prerequisites:</strong> Use Magic Device 6 ranks, base Fortitude saving throw bonus +3.<br/><strong>Benefit:</strong> You can focus on an item associated with your race to use a racial spell-like ability that you have without expending any uses per day from that spell-like ability. A racial spell-like ability is any spell-like ability that you have gained from a racial trait, from a feat or trait that lists your race as a prerequisite, or from a class option or archetype that is available only to members of your race. You must use an item with a spell in its construction requirement that belongs to the same school and is at least of the same level as the spell-like ability that you wish to use. You can use this feat once per day, plus an additional time per day when your base Fortitude save bonus reaches +9 and +12.</p>
</>};
const _radiant_charge = {title: "Radiant Charge", jsx: <><h2 id="feat-radiant_charge-radiant-charge">Radiant Charge</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 154</Link></p>
<p>When you charge, you do so with the power of faith.<br/><strong>Prerequisites:</strong> <Link to="/ability/lay_on_hands">Lay on hands</Link> class feature.<br/><strong>Benefit:</strong> When you hit with a <Link to="/rule/charge">charge</Link> attack, you can expend all of your remaining uses of lay on hands to deal extra damage equal to 1d6 per use of lay on hands expended + your Charisma bonus. This damage comes from holy power and is not subject to damage reduction, energy immunities, or energy resistances.</p>
</>};
const _rage_casting = {title: "Rage Casting", jsx: <><h2 id="feat-rage_casting-rage-casting">Rage Casting</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 154</Link></p>
<p>Your blood is raw and potent power, and you can burn it to empower your spells.<br/><strong>Prerequisites:</strong> Blood casting class feature.<br/><strong>Benefit:</strong> When you cast a bloodrager spell, as a swift action you can sacrifice some of your life force to augment the spell's potency. You can opt to take up to 1d6 points of damage per spell level of the spell you are casting, choosing the amount of dice before rolling. You cannot overcome this damage in any way, and it cannot be taken from temporary hit points. For each of these damage dice you roll, the DC of the spell you are casting increases by 1.</p>
</>};
const _raging_absorption = {title: "Raging Absorption", jsx: <><h2 id="feat-raging_absorption-raging-absorption">Raging Absorption</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 154</Link></p>
<p>You can absorb hostile spell energy to refuel your continued bloodrage.<br/><strong>Prerequisites:</strong> Ability to cast 2nd-level bloodrager spells, bloodrage class feature.<br/><strong>Benefit:</strong> While you are bloodraging, if you successfully save against a damaging arcane spell that either targets you or includes you in its area, and you take no damage from that spell, you can absorb a portion of its arcane energy to replenish your bloodrage. You regain 1 round of bloodrage for every 2 levels of the spell you successfully saved against. You cannot use this feat to regain more rounds of bloodrage each day than your daily maximum number of rounds, nor can you ever exceed your maximum number of rounds.</p>
</>};
const _raging_blood = {title: "Raging Blood", jsx: <><h2 id="feat-raging_blood-raging-blood">Raging Blood</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 155</Link></p>
<p>Your blood boils with latent energy, filling you with an intense fury.<br/><strong>Prerequisites:</strong> <Link to="/feat/eldritch_heritage">Eldritch Heritage</Link> or sorcerer bloodline class feature.<br/><strong>Benefit:</strong> You gain the 1st-level <Link to="/ability/bloodrager_bloodlines">bloodrager bloodline</Link> power for your bloodline. In addition, you gain the ability to enter a state similar to (but less powerful than) a <Link to="/class/bloodrager">bloodrager's</Link> bloodrage. You can enter this lesser bloodrage twice per day, for up to 4 rounds. During this lesser bloodrage, you gain a +2 morale bonus to Strength and Constitution, and no morale bonus on Will saving throws. Otherwise, this benefit is the same as the bloodrage class feature.</p>
<p>If you have more than one bloodline, you choose the bloodline this applies to upon taking the feat.</p>
</>};
const _raging_brutality = {title: "Raging Brutality", jsx: <><h2 id="feat-raging_brutality-raging-brutality">Raging Brutality</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 114</Link></p>
<p>You expend some of your rage to strike your opponents with a more powerful weapon blow.<br/><strong>Prerequisites:</strong> Str 13, rage class feature, <Link to="/feat/power_attack">Power Attack</Link>, base attack bonus +12.<br/><strong>Benefit:</strong> While raging and using Power Attack, you can spend 3 additional rounds of your rage as a swift action to add your Constitution bonus on damage rolls for melee attacks or thrown weapon attacks you make on your turn. If you are using the weapon two-handed, instead add 1-1/2 times your Constitution bonus. This bonus damage is not multiplied on a critical hit.</p>
</>};
const _raging_brute = {title: "Raging Brute", jsx: <><h2 id="feat-raging_brute-raging-brute">Raging Brute</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 153</Link></p>
<p>You are able to harness the rage that burns inside you and fuels your might.<br/><strong>Prerequisites:</strong> Str 21, <Link to="/monster/ogre">ogre</Link>.<br/><strong>Benefit:</strong> Select one <Link to="/ability/rage_powers">rage power</Link>. Once per day as a free action, you can enter a state of fury and gain the effects of this rage power for 1 minute. If the rage power normally ends a barbarian rage when used, the ability ends after it's used and you immediately become <Link to="/misc/fatigued">fatigued</Link>. You don't otherwise become fatigued at the end of this ability's duration.</p>
<p>Your effective barbarian level for the purpose of qualifying for and using rage powers is equal to your total Hit Dice - 3. This feat doesn't grant any of the normal benefits or penalties of a barbarian's rage.</p>
<p><strong>Special:</strong> You can take this feat multiple times. Each time you do, choose another rage power and gain one additional use per day of this feat. Each time you activate this feat, you can use any or all of your rage powers gained from this feat.</p>
</>};
const _raging_concentration = {title: "Raging Concentration", jsx: <><h2 id="feat-raging_concentration-raging-concentration">Raging Concentration</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 155</Link></p>
<p>When you are in the heat of rage, not even pain can break your concentration.<br/><strong>Prerequisites:</strong> Blood casting class feature.<br/><strong>Benefit:</strong> While in a bloodrage, you gain a bonus on <Link to="/rule/concentration">concentration</Link> checks equal to the morale bonus granted to your Constitution by the bloodrage.</p>
</>};
const _raging_deathblow = {title: "Raging Deathblow", jsx: <><h2 id="feat-raging_deathblow-raging-deathblow">Raging Deathblow</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 114</Link></p>
<p>Every killing blow gives you a surge of vitality, further fueling your rage.<br/><strong>Prerequisites:</strong> Greater rage class feature.<br/><strong>Benefit:</strong> While raging, whenever your attack reduces an opponent of a CR greater than or equal to your character level to -1 or fewer hit points, you gain 1 extra round of rage for that day. If that attack was a critical hit, you gain 1 additional extra round of rage for that day. Whenever you rest to renew your total number of rounds of rage per day, any extra rounds you still have from this feat are lost.</p>
</>};
const _raging_hurler = {title: "Raging Hurler", jsx: <><h2 id="feat-raging_hurler-raging-hurler">Raging Hurler</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 114</Link></p>
<p>An opponent can do little to evade your wrathful pitching of weapons and objects.<br/><strong>Prerequisites:</strong> Rage class feature, <Link to="/feat/throw_anything">Throw Anything</Link>.<br/><strong>Benefit:</strong> While raging, you can throw a two-handed weapon as a standard action, and you double the range increment for weapons you throw. If you also have the <Link to="/feat/quick_draw">Quick Draw</Link> feat, you can throw two-handed weapons at your full normal rate of attacks. Further, you can pick up an unattended object that you can use as an <Link to="/misc/improvised_weapon">improvised weapon</Link> within your reach as part of the attack action to throw that item.</p>
</>};
const _raging_regeneration = {title: "Raging Regeneration", jsx: <><h2 id="feat-raging_regeneration-raging-regeneration-combat">Raging Regeneration (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 224</Link></p>
<p>Your rage pushes your ability to regenerate beyond its normal limits.<br/><strong>Prerequisites:</strong> Rage class ability, <Link to="/umr/regeneration">regeneration</Link>, <Link to="/monster/troll">troll</Link>.<br/><strong>Benefit:</strong> While you are raging, fire and acid damage don't make your regeneration stop functioning on the round following the attack, and instead reduce the number of hit points regained by regeneration each round by 2 until the end of your next turn.<br/><strong>Normal:</strong> Acid and fire damage cause your regeneration to stop functioning on the round following the attack.</p>
</>};
